-- Poems batch 216
INSERT OR IGNORE INTO poems (id,title,author,dynasty,collection,collection_id,rhythmic,tags,excerpt,length,source_path,paragraphs) VALUES
('5e95c2a4-d9b8-4a5c-85a5-a87ad0b591c9','蒙仲書監通守溫陵以戴尚書肖望李內翰元善嘗歷是官即西偏作室匾以西清風月賓主唱和甚盛次韵二首  其一','劉克莊','宋','宋诗','song-poetry','','[]','懶即蓬萊訪具茨，平分不費一錢貲。',64,'全唐诗/poet.song.200000.json','["懶即蓬萊訪具茨，平分不費一錢貲。", "子綦隠几而聞者，太白停盃以問之。", "螃蠏螯肥毋與事，琵琶調下莫題詩。", "是知二老回頭笑，不料清源有此奇。"]'),
('240dd3b9-86c2-4605-8320-b903eaa7e920','蒙仲書監通守溫陵以戴尚書肖望李內翰元善嘗歷是官即西偏作室匾以西清風月賓主唱和甚盛次韵二首  其二','劉克莊','宋','宋诗','song-poetry','','[]','自北及南捷徑行，冰廳消得此嘉名。',64,'全唐诗/poet.song.200000.json','["自北及南捷徑行，冰廳消得此嘉名。", "且參光霽儒家景，誰管歌呼吏舍聲。", "碎安道琴時好淡，種文正竹話偏清。", "每聞酬倡皆皮陸，耄矣無因共膾鯨。"]'),
('00781199-89b7-48ae-833f-56ff2299a3ac','送陳郎玉汝之官二首  其一','劉克莊','宋','宋诗','song-poetry','','[]','昔一平津閣，今隨孟博車。',48,'全唐诗/poet.song.200000.json','["昔一平津閣，今隨孟博車。", "徑趨烏幕遠，漸向鯉廷疎。", "分袂三年別，平安兩字書。", "何時迎晝繡，携酒煮溪魚。"]'),
('138e7d7b-3324-40fc-8958-6a4636b74936','送陳郎玉汝之官二首  其二','劉克莊','宋','宋诗','song-poetry','','[]','管鮑交三世，朱陳共一村。',48,'全唐诗/poet.song.200000.json','["管鮑交三世，朱陳共一村。", "居慙阿承女，獲事太丘孫。", "惜別吾鍾愛，相賓右格言。", "應憐垂白叟，計日望迴轅。"]'),
('d60f4732-2cae-4dfa-a35f-262fdcd04134','警齋侍郎和放翁與茶山五言寄余次韵一首','劉克莊','宋','宋诗','song-poetry','','[]','髫齔參諸老，辱置書冊前。',168,'全唐诗/poet.song.200000.json','["髫齔參諸老，辱置書冊前。", "上起馬本紀，下迄李續編。", "積勤迫榆景，扶病登木天。", "貌醜况古粧，臂短非善緣。", "時人訕晚謬，弟子嘲晝眠。", "墮甑懶迴顧，棄扇羞乞憐。", "衆皆驚曲徑，余惟泥方穿。", "平生憂世病，華佗不能痊。", "仰即丹鳳鶱，俯視磨蟻旋。", "居常哂觸蠻，安肯分濟川。", "舐鼎堪骨蛻，載質從心悁。", "何當坐一月，大勝讀十年。", "惜哉已耄及，晨鏡雪滿顛。", "僊家能返童，肘後儻能傳。"]'),
('4de703c7-2933-49cf-b5f3-eea314e7cc32','答尤溪趙廣文','劉克莊','宋','宋诗','song-poetry','','[]','怪來喜事上雙眉，袖有恬軒老子詩。',64,'全唐诗/poet.song.200000.json','["怪來喜事上雙眉，袖有恬軒老子詩。", "幾箇□□□□斷，十年長敢比肩隨。", "古耆舊傳猶堪續，今少微星更是誰。", "笑殺太清劉管轄，此冠不挂待何時。"]'),
('6ded61dc-5bfb-49ed-ab2e-fa3cf34ca4bc','題尤溪趙氏連桂堂','劉克莊','宋','宋诗','song-poetry','','[]','一從五竇聯芳後，直至君家四桂堂。',64,'全唐诗/poet.song.200000.json','["一從五竇聯芳後，直至君家四桂堂。", "莫是燕山傳下本，又疑蟾窟摘來香。", "即今錄續題千佛，伊昔栽培記十郎。", "却笑郄生太矜露，一枝未足詫名場。"]'),
('4cca0e82-bf77-46cd-a3b2-e6adde287d49','戊午上巳謁何恭人墳三絕  其一','劉克莊','宋','宋诗','song-poetry','','[]','織素塵機長寂寞，燎黄錦誥謾榮華。',32,'全唐诗/poet.song.200000.json','["織素塵機長寂寞，燎黄錦誥謾榮華。", "堪同絡秀書前史，誰爲王符訪外家。"]'),
('5dd8cdf6-5549-464a-8101-efdfb6a9dcb9','戊午上巳謁何恭人墳三絕  其二','劉克莊','宋','宋诗','song-poetry','','[]','華堂不洎千鍾養，荒壠空遺四尺封。',32,'全唐诗/poet.song.200000.json','["華堂不洎千鍾養，荒壠空遺四尺封。", "愁絕狐狸潭畔路，不知更掃幾番松。"]'),
('db0b62fc-36d8-42ad-897c-1c33aad33e82','戊午上巳謁何恭人墳三絕  其三','劉克莊','宋','宋诗','song-poetry','','[]','當日封崇殊草創，末年付授絕悲哀。',32,'全唐诗/poet.song.200000.json','["當日封崇殊草創，末年付授絕悲哀。", "子孫記取吾翁語，斗酒單鷄歲歲來。"]'),
('ef0e05b1-3adb-4fba-b2d6-eb598afcb9b8','夏旱五首  其一','劉克莊','宋','宋诗','song-poetry','','[]','南蕩淺堪戽，北溝乾可田。',24,'全唐诗/poet.song.200000.json','["南蕩淺堪戽，北溝乾可田。", "龍船無頓處，欲起待明年。"]'),
('11a18342-cf7c-4815-afa7-be77eadcf696','夏旱五首  其二','劉克莊','宋','宋诗','song-poetry','','[]','井以瓶罌竭，溪堪揭厲行。',24,'全唐诗/poet.song.200000.json','["井以瓶罌竭，溪堪揭厲行。", "蟹泉一摘子，辛苦上山迎。"]'),
('c0f05ca0-247f-4602-9078-419a0533e417','夏旱五首  其三','劉克莊','宋','宋诗','song-poetry','','[]','尚食停珍膳，清齋禱竹宮。',24,'全唐诗/poet.song.200000.json','["尚食停珍膳，清齋禱竹宮。", "方當歌雲漢，未可和薰風。"]'),
('cd8a8263-5230-4e1c-b2d6-3bf39e2a2385','夏旱五首  其四','劉克莊','宋','宋诗','song-poetry','','[]','奴挈軍持去，丁寧費耳提。',24,'全唐诗/poet.song.200000.json','["奴挈軍持去，丁寧費耳提。", "汝寧緩花塢，吾欲救蔬畦。"]'),
('c5b6a093-195d-4a92-ba6d-1fb01d99da8a','夏旱五首  其五','劉克莊','宋','宋诗','song-poetry','','[]','士窮猶可忍，拾穗亦可歌。',24,'全唐诗/poet.song.200000.json','["士窮猶可忍，拾穗亦可歌。", "歲事還如此，畦間有穗麽。"]'),
('68a7a158-9104-4b11-90cf-93f7abf252ff','喜雨五首  其一','劉克莊','宋','宋诗','song-poetry','','[]','簫鼓修雩祭，風雷起古湫。',24,'全唐诗/poet.song.200000.json','["簫鼓修雩祭，風雷起古湫。", "雖無豢龍氏，尚有斬蛟侯。"]'),
('41a6303f-6ede-4af2-913d-106a2afbddf5','喜雨五首  其二','劉克莊','宋','宋诗','song-poetry','','[]','點點沃枯焦，聲聲伴寂寥。',24,'全唐诗/poet.song.200000.json','["點點沃枯焦，聲聲伴寂寥。", "五更初聽雨，千載後聞韶。"]'),
('b02484b6-680f-4558-9305-68101b5d96d2','喜雨五首  其三','劉克莊','宋','宋诗','song-poetry','','[]','巫祝呼神去，緇黄送水還。',24,'全唐诗/poet.song.200000.json','["巫祝呼神去，緇黄送水還。", "若非宿來雨，仙聖亦慙顔。"]'),
('81da8028-8ad2-4027-a6a3-9656e16c2096','喜雨五首  其四','劉克莊','宋','宋诗','song-poetry','','[]','昕朝避黄屋，露禱動蒼穹。',24,'全唐诗/poet.song.200000.json','["昕朝避黄屋，露禱動蒼穹。", "野老安知帝，豚蹄賽社公。"]'),
('b9531302-baca-4c48-8f75-6792b0a19922','喜雨五首  其五','劉克莊','宋','宋诗','song-poetry','','[]','在處陂池白，寧愁汲路遥。',24,'全唐诗/poet.song.200000.json','["在處陂池白，寧愁汲路遥。", "老猶堪抱甕，窮未至操瓢。"]'),
('bc4a429b-5c1c-4008-854e-bfb7e8df3683','寄題心泉','劉克莊','宋','宋诗','song-poetry','','[]','之子幽棲恨未深，飛泉來處有亭臨。',64,'全唐诗/poet.song.200000.json','["之子幽棲恨未深，飛泉來處有亭臨。", "觚懸木杪猶煩耳，易在床頭且洗心。", "夸士十漿須五饋，癡人一帚享千金。", "箕山潁水應如故，太息巢由不可尋。"]'),
('c1027306-5dfa-4305-ab04-fe7c5eee93d4','久雨五首  其一','劉克莊','宋','宋诗','song-poetry','','[]','復置漢平準，稍修隋義倉。',24,'全唐诗/poet.song.200000.json','["復置漢平準，稍修隋義倉。", "羣公猶禹稷，陛下况堯湯。"]'),
('1805230c-7843-439f-88d8-356f82ae487b','久雨五首  其二','劉克莊','宋','宋诗','song-poetry','','[]','昔憂腹不穀，今恐耳生禾。',24,'全唐诗/poet.song.200000.json','["昔憂腹不穀，今恐耳生禾。", "誰向衛公說，翻瓢莫太多。"]'),
('b7d8c5a9-e95d-4a8f-affb-eb07ad06f6ed','久雨五首  其三','劉克莊','宋','宋诗','song-poetry','','[]','試倚高樓望，桑田化渺彌。',24,'全唐诗/poet.song.200000.json','["試倚高樓望，桑田化渺彌。", "安知爲野老，農事上雙眉。"]'),
('48d5213c-a96b-4fad-a0bf-c62dd5c0b277','久雨五首  其四','劉克莊','宋','宋诗','song-poetry','','[]','噫聲初發竅，巨浸倏漫空。',24,'全唐诗/poet.song.200000.json','["噫聲初發竅，巨浸倏漫空。", "我欲鎸箕畢，爲天節雨風。"]'),
('db7cf9f8-7727-4b32-9ca7-a0963260fab2','久雨五首  其五','劉克莊','宋','宋诗','song-poetry','','[]','久斷過從客，尤妨刈穫夫。',24,'全唐诗/poet.song.200000.json','["久斷過從客，尤妨刈穫夫。", "羲和應爛醉，晨起失金烏。"]'),
('2d274058-31ce-4c01-8f06-2963399ade02','挽朱吏部子明二首  其一','劉克莊','宋','宋诗','song-poetry','','[]','渡江太史後，當世大儒門。',48,'全唐诗/poet.song.200000.json','["渡江太史後，當世大儒門。", "諸老賢宗子，文公愛嫡孫。", "不來陪講席，却去護留屯。", "寂寞馮唐老，無人爲上言。"]'),
('c6e2f2bf-ea89-44d3-93e5-a70d5ac59d13','挽朱吏部子明二首  其二','劉克莊','宋','宋诗','song-poetry','','[]','忝居言偃室，偶在鄭公鄉。',48,'全唐诗/poet.song.200000.json','["忝居言偃室，偶在鄭公鄉。", "盡識階庭秀，多窺屋壁藏。", "數行杜陵淚，一瓣孔林香。", "吾老無行役，何由瀝奠觴。"]'),
('5eb1cc1f-c155-4188-89aa-09bda0e0c8db','喜晴一首','劉克莊','宋','宋诗','song-poetry','','[]','□□尚紛擾，燭龍深伏藏。',24,'全唐诗/poet.song.200000.json','["□□尚紛擾，燭龍深伏藏。", "金鷄不能忍，騰出照扶桑。"]'),
('88facf0b-fd2c-419f-a6dc-e6b4bb4fcaa4','警齋侍郎舟和放翁五言過奬衰朽且示雄文二編次韵一首','劉克莊','宋','宋诗','song-poetry','','[]','熟讀公詩文，高出騷選前。',168,'全唐诗/poet.song.200000.json','["熟讀公詩文，高出騷選前。", "蹇余相追逐，嚴句入杜編。", "里鼓聞咸池，山歌混葛天。", "刀圭靳付授，分寸難扳緣。", "偶逢浮丘伯，月下吹簫眠。", "鳳咮不可和，蚓竅殊自憐。", "披我雲錦裳，易去短褐穿。", "啖我玉井藕，洒然渴肺痊。", "迴瀾使東之，斡天令左旋。", "斯文恃砥柱，諸老隨遊川。", "交遊愧忝竊，薰摘勞結悁。", "當論先後覺，寧較大小年。", "已得渥漥駿，共登崑崙顛。", "指點歸宿處，目覽非耳傳。"]'),
('19fc4690-9a4a-464f-807f-a805844e7f17','倉部弟生日五絕  其一','劉克莊','宋','宋诗','song-poetry','','[]','郎宿臨初度，村翁喜欲顛。',24,'全唐诗/poet.song.200000.json','["郎宿臨初度，村翁喜欲顛。", "要知儂甲子，老弟已稀年。"]'),
('0e752a74-fd64-461b-9f68-96d93948d4a5','倉部弟生日五絕  其二','劉克莊','宋','宋诗','song-poetry','','[]','爵並開鄉邑，官皆視大蓬。',24,'全唐诗/poet.song.200000.json','["爵並開鄉邑，官皆視大蓬。", "年齡高畧似，鬚髮黑難同。"]'),
('12d96310-7d42-4055-8a5b-eb37bb146680','倉部弟生日五絕  其三','劉克莊','宋','宋诗','song-poetry','','[]','我昔單棲久，君今半被空。',24,'全唐诗/poet.song.200000.json','["我昔單棲久，君今半被空。", "天公將老壽，裨補兩鰥翁。"]'),
('66ca8184-db6b-4a7e-8b61-e84541e4edb6','倉部弟生日五絕  其四','劉克莊','宋','宋诗','song-poetry','','[]','菰甘因輟送，荔熟亦均分。',24,'全唐诗/poet.song.200000.json','["菰甘因輟送，荔熟亦均分。", "食指真欺我，脾神不似君。"]'),
('9ba6a825-383c-424c-ada0-32b6aad021be','倉部弟生日五絕  其五','劉克莊','宋','宋诗','song-poetry','','[]','平生老兄弟，歲晚共婆娑。',24,'全唐诗/poet.song.200000.json','["平生老兄弟，歲晚共婆娑。", "蘇氏推同叔，程家說二哥。"]'),
('4d3feb34-2a4d-4f5e-815b-af3531d47fdd','倉部弟和前韵再得五首  其一','劉克莊','宋','宋诗','song-poetry','','[]','節腹羞浮食，徐行畏疾顛。',24,'全唐诗/poet.song.200000.json','["節腹羞浮食，徐行畏疾顛。", "仙須有癯相，貴亦出長年。"]'),
('fc71e74a-ab24-4801-81d1-b6395f9e8083','倉部弟和前韵再得五首  其二','劉克莊','宋','宋诗','song-poetry','','[]','莫放雙眉皺，休嗟兩鬢蓬。',24,'全唐诗/poet.song.200000.json','["莫放雙眉皺，休嗟兩鬢蓬。", "耆英圖裏看，若箇弟兄同。"]'),
('c8dc9330-f2ed-439e-838a-9bded133f429','倉部弟和前韵再得五首  其三','劉克莊','宋','宋诗','song-poetry','','[]','荆花開漸少，瓜蔓摘幾空。',24,'全唐诗/poet.song.200000.json','["荆花開漸少，瓜蔓摘幾空。", "頼有長頭子，相從禿鬢翁。"]'),
('4e11d2df-816b-4448-abba-6986fd8c59e1','倉部弟和前韵再得五首  其四','劉克莊','宋','宋诗','song-poetry','','[]','秧馬催予出，銅魚羨子分。',24,'全唐诗/poet.song.200000.json','["秧馬催予出，銅魚羨子分。", "無蓮照學士，有竹比封君。"]'),
('004dce9e-4054-41a2-8794-633560a88e2b','倉部弟和前韵再得五首  其五','劉克莊','宋','宋诗','song-poetry','','[]','甫昔排閶闔，雄曾賦馺娑。',24,'全唐诗/poet.song.200000.json','["甫昔排閶闔，雄曾賦馺娑。", "而今行不得，切莫喚哥哥。"]'),
('6c3f9670-aec8-4b55-8df9-777c2cdf1bc5','精衛銜石填海','劉克莊','宋','宋诗','song-poetry','','[]','精衛銜寃切，輕生志可憐。',72,'全唐诗/poet.song.200000.json','["精衛銜寃切，輕生志可憐。", "只愁石易盡，不道海難填。", "幻化存遺魄，飛鳴累一拳。", "終朝納芥子，何日變桑田。", "鵑怨啼成血，鴟沉怒拍天。", "君看嘗膽者，終有沼吳年。"]'),
('8436861a-edc9-4201-8980-5ece47c86405','六言五首贈李相士景春  其一','劉克莊','宋','宋诗','song-poetry','','[]','謗東家丘如狗，譽太史儋猶龍。',28,'全唐诗/poet.song.200000.json','["謗東家丘如狗，譽太史儋猶龍。", "卿可自用卿法，吾未始出吾宗。"]'),
('a57e19f6-9879-4575-a034-3201fb1d445e','六言五首贈李相士景春  其二','劉克莊','宋','宋诗','song-poetry','','[]','少年勿議宿士，阿瞞自是相師。',28,'全唐诗/poet.song.200000.json','["少年勿議宿士，阿瞞自是相師。", "蒙叟馘黄項槁，桓郎眼小聲雌。"]'),
('9fe823f8-90e1-4f0f-a2e3-23615d38a45e','六言五首贈李相士景春  其三','劉克莊','宋','宋诗','song-poetry','','[]','馬公带些火色，孟生不合山肩。',28,'全唐诗/poet.song.200000.json','["馬公带些火色，孟生不合山肩。", "爭問唐舉相法，誰贈君平卦錢。"]'),
('845086f2-fc62-46bc-a4c3-1a87e2cfc880','六言五首贈李相士景春  其四','劉克莊','宋','宋诗','song-poetry','','[]','被人看殺叔寶，無地逃生伯喈。',28,'全唐诗/poet.song.200000.json','["被人看殺叔寶，無地逃生伯喈。", "試問天人眉宇，何如土木形骸。"]'),
('87fefd7f-b6c3-4ab9-99dd-fad611fb0e75','六言五首贈李相士景春  其五','劉克莊','宋','宋诗','song-poetry','','[]','眼有紫稜安用，眉無黄色何妨。',28,'全唐诗/poet.song.200000.json','["眼有紫稜安用，眉無黄色何妨。", "自斷非封侯相，尚堪作牧牛郎。"]'),
('54acf409-81a7-45fb-8870-5caaf4885983','再和仲晦監簿','劉克莊','宋','宋诗','song-poetry','','[]','少狂藴奇志，探索刪畫前。',168,'全唐诗/poet.song.200000.json','["少狂藴奇志，探索刪畫前。", "安能一措辭，何止三絕編。", "俚音和薰風，短夢游鈞天。", "竟無魚水分，姑了螢雪緣。", "北扉失脚墮，南窗抱膝眠。", "寧爲英雄笑，不受兒女憐。", "徐侯金閨彥，歲晚鐵硯穿。", "掊擊羣疑亡，發藥沉疴痊。", "鯨浪怒噴薄，蟻封妙回旋。", "精博昔騎省，奇逸今師川。", "望古多慷慨，感時嘗憂悁。", "肯羨蕭芥榮，甘保樗櫟年。", "君有論絕交，吾無書辨顛。", "倡和誑饑腹，聊與好事傳。"]'),
('223280cc-c92f-4d46-885b-5cedad77c45c','兌女余最小孫也慧而夭悼以六言二首  其一','劉克莊','宋','宋诗','song-poetry','','[]','性慧於靈照女，年小似善財童。',28,'全唐诗/poet.song.200000.json','["性慧於靈照女，年小似善財童。", "急急之符奪汝，琅琅之音惱翁。"]'),
('2f6adc15-0d34-4d9f-b0cf-f4c6a19409de','兌女余最小孫也慧而夭悼以六言二首  其二','劉克莊','宋','宋诗','song-poetry','','[]','不合小時了了，可堪長夜茫茫。',28,'全唐诗/poet.song.200000.json','["不合小時了了，可堪長夜茫茫。", "暮年欠汝淚債，已乾更滴數行。"]'),
('d43053dd-a1f6-4314-8eae-89352b0392af','借韵跋林肅翁省題詩','劉克莊','宋','宋诗','song-poetry','','[]','昔冠南宮淡墨書，當年萬卷各名糊。',64,'全唐诗/poet.song.200000.json','["昔冠南宮淡墨書，當年萬卷各名糊。", "至今處子尚綽約，應笑老婆曾抹塗。", "詠慶雲圖如著色，和薰風句肯從諛。", "行三十里余方悟，敢與楊脩較智愚。"]'),
('7c2d4b07-5ae1-41a9-ac9a-d4c60553189a','溫陵諸賢接刊拙稿竹溪直院有詩助譟戲和一首','劉克莊','宋','宋诗','song-poetry','','[]','行世安能保不刊，自憐敝帚笑傍觀。',64,'全唐诗/poet.song.200000.json','["行世安能保不刊，自憐敝帚笑傍觀。", "熏香未可疎班馬，抓癢無過看杜韓。", "雷挾六丁來取易，天教兩鳥不鳴難。", "吾聞海上鯨堪膾，休把鸞刀切蟻肝。"]'),
('b8cf8b5c-b824-4637-863a-c272476f33ee','挽陳梧州二首  其一','劉克莊','宋','宋诗','song-poetry','','[]','谷目多名士，西軒與石門。',48,'全唐诗/poet.song.200000.json','["谷目多名士，西軒與石門。", "族皆通一譜，君獨秀諸孫。", "叔季斯人少，耆英幾箇存。", "可憐同社叟，反袂賦招魂。"]'),
('49c03e6b-238e-4b14-a8ea-32134e35af4d','挽陳梧州二首  其二','劉克莊','宋','宋诗','song-poetry','','[]','小室夷之築，荒州舜所藏。',48,'全唐诗/poet.song.200000.json','["小室夷之築，荒州舜所藏。", "身過冰蘗苦，面带瘴茅黄。", "察使臨陽子，遺民笑化光。", "定知廉吏傳，他日一名香。"]'),
('cc2564eb-efa9-4985-8a2e-b76ac89dbc96','竹溪直院盛稱起予草堂詩之善暇日覽之多有可恨者因效顰作十首亦前人廣騷反騷之意內二十九首用舊題惟歲寒知松柏被褐懷珠玉三首效山谷餘十八首別命題或追錄少作並存于卷以訓童蒙之意 駐蹕山','劉克莊','宋','宋诗','song-poetry','','[]','險絕朝鮮國，微茫海四環。',72,'全唐诗/poet.song.200000.json','["險絕朝鮮國，微茫海四環。", "帝於焉駐蹕，人以此名山。", "虜讋天威近，師行雪浪間。", "車旂臨鳥道，草木識龍顔。", "露布虬鬚喜，鐃歌鴨綠還。", "可憐房與魏，扈從不隨班。"]'),
('9d7462c1-bc75-4c48-9bad-bb7e3a4eb5ee','竹溪直院盛稱起予草堂詩之善暇日覽之多有可恨者因效顰作十首亦前人廣騷反騷之意內二十九首用舊題惟歲寒知松柏被褐懷珠玉三首效山谷餘十八首別命題或追錄少作並存于卷以訓童蒙之意 腐草化爲螢','劉克莊','宋','宋诗','song-poetry','','[]','造化於微物，生生品彙茲。',72,'全唐诗/poet.song.200000.json','["造化於微物，生生品彙茲。", "流螢倏然集，腐草化而爲。", "雨逕陳荄積，寒塘碧色衰。", "與星鬭光彩，助月吐神奇。", "明滅形無定，枯榮理孰推。", "莫矜太陽近，會有肅霜時。"]'),
('809558eb-dfc4-455f-b3d8-03837bf8be98','竹溪直院盛稱起予草堂詩之善暇日覽之多有可恨者因效顰作十首亦前人廣騷反騷之意內二十九首用舊題惟歲寒知松柏被褐懷珠玉三首效山谷餘十八首別命題或追錄少作並存于卷以訓童蒙之意 乘月登樓','劉克莊','宋','宋诗','song-poetry','','[]','越石通身膽，英英管樂儔。',72,'全唐诗/poet.song.200000.json','["越石通身膽，英英管樂儔。", "防秋戍孤壘，乘月上高樓。", "粉堞齊雲逈，冰輪出海浮。", "目中無虜騎，笑裏有邊籌。", "梟羯言猶壯，聞雞志未酬。", "素娥知往事，猶照麗譙頭。"]'),
('1c84c556-94a0-454c-b8ea-d6aa2ede1d35','竹溪直院盛稱起予草堂詩之善暇日覽之多有可恨者因效顰作十首亦前人廣騷反騷之意內二十九首用舊題惟歲寒知松柏被褐懷珠玉三首效山谷餘十八首別命題或追錄少作並存于卷以訓童蒙之意 望祀蓬萊','劉克莊','宋','宋诗','song-poetry','','[]','齊魯多方士，荒唐競自媒。',72,'全唐诗/poet.song.200000.json','["齊魯多方士，荒唐競自媒。", "微茫隔煙霧，向望祀蓬萊。", "甲帳雲旂下，離宮月戶開。", "海難架橋渡，風易引船回。", "求藥童安在，乘槎使不來。", "空令仁聖悔，世豈有仙哉。"]'),
('efa70f4b-2be0-434e-a021-ce40c662af5f','竹溪直院盛稱起予草堂詩之善暇日覽之多有可恨者因效顰作十首亦前人廣騷反騷之意內二十九首用舊題惟歲寒知松柏被褐懷珠玉三首效山谷餘十八首別命題或追錄少作並存于卷以訓童蒙之意 登封泰山','劉克莊','宋','宋诗','song-poetry','','["\u6cf0\u5c71"]','天下名山衆，巖巖獨岱崇。',72,'全唐诗/poet.song.200000.json','["天下名山衆，巖巖獨岱崇。", "聖朝久熙洽，天子乃登封。", "清蹕臨危頂，鉤陳備祲容。", "下觀紅日出，中起白雲濃。", "太史陪祀見，燕公載筆從。", "安知千載後，樵者斧壇松。"]'),
('b5aa63e1-7110-482b-86ac-a7425328a493','竹溪直院盛稱起予草堂詩之善暇日覽之多有可恨者因效顰作十首亦前人廣騷反騷之意內二十九首用舊題惟歲寒知松柏被褐懷珠玉三首效山谷餘十八首別命題或追錄少作並存于卷以訓童蒙之意 爲郎牧羊','劉克莊','宋','宋诗','song-poetry','','[]','式也堪其選，非貲所可爲。',72,'全唐诗/poet.song.200000.json','["式也堪其選，非貲所可爲。", "誰知省郎者，自處牧羊兒。", "夜襆青綾被，晨趨白玉墀。", "都忘列宿貴，甘慕乘田卑。", "衣布猶平日，烹桑聳一時。", "迴頭憐犬子，空獻上林辭。"]'),
('1948b4ab-e609-4fe9-8c03-316e95c028cd','竹溪直院盛稱起予草堂詩之善暇日覽之多有可恨者因效顰作十首亦前人廣騷反騷之意內二十九首用舊題惟歲寒知松柏被褐懷珠玉三首效山谷餘十八首別命題或追錄少作並存于卷以訓童蒙之意 道不拾遺','劉克莊','宋','宋诗','song-poetry','','[]','通國興仁遜，渾然太古時。',72,'全唐诗/poet.song.200000.json','["通國興仁遜，渾然太古時。", "不營分表事，肯拾道傍遺。", "山步多樵笛，郊行足酒旗。", "馬應無失塞，羊豈有亡歧。", "墜李羞三咽，堆金畏四知。", "如何仙聖境，著得竊桃兒。"]'),
('14d8ea71-5196-4c93-a2b9-2cc1c07d4181','竹溪直院盛稱起予草堂詩之善暇日覽之多有可恨者因效顰作十首亦前人廣騷反騷之意內二十九首用舊題惟歲寒知松柏被褐懷珠玉三首效山谷餘十八首別命題或追錄少作並存于卷以訓童蒙之意 登單于臺','劉克莊','宋','宋诗','song-poetry','','[]','五葉英雄主，長驅等拉摧。',72,'全唐诗/poet.song.200000.json','["五葉英雄主，長驅等拉摧。", "單于先退舍，天子自登臺。", "鳴鏑經營遠，乘輿警蹕來。", "穹廬空漠遁，黄屋半天開。", "鴈塞三更月，龍廷一炬灰。", "公卿爭上壽，扈從翠華迴。"]'),
('1d3fac25-421e-4ba3-93a3-0d85abc1831a','竹溪直院盛稱起予草堂詩之善暇日覽之多有可恨者因效顰作十首亦前人廣騷反騷之意內二十九首用舊題惟歲寒知松柏被褐懷珠玉三首效山谷餘十八首別命題或追錄少作並存于卷以訓童蒙之意 公主嫁單于','劉克莊','宋','宋诗','song-poetry','','[]','莫愛於公主，情鍾掌上珠。',72,'全唐诗/poet.song.200000.json','["莫愛於公主，情鍾掌上珠。", "是誰誤天子，遣嫁與單于。", "帝女生而貴，王姬禮亦殊。", "竟令乘鳳侶，遠適牧羊奴。", "不信和戎者，真能保塞無。", "如何丈人行，金絮奉胡雛。"]'),
('f7fd7342-14e4-44e1-9bc1-4b088983b9fd','竹溪直院盛稱起予草堂詩之善暇日覽之多有可恨者因效顰作十首亦前人廣騷反騷之意內二十九首用舊題惟歲寒知松柏被褐懷珠玉三首效山谷餘十八首別命題或追錄少作並存于卷以訓童蒙之意 聞鷄起舞','劉克莊','宋','宋诗','song-poetry','','[]','百動俱休息，遥聞野外鷄。',72,'全唐诗/poet.song.200000.json','["百動俱休息，遥聞野外鷄。", "起提孤劍舞，肯戀一枝棲。", "乍枕琱戈寢，俄驚絳幘啼。", "自嗟褐寬博，不覺褎昂低。", "茅店寒聲絕，函關曉色迷。", "細腰方按曲，風雨漫凄凄。"]'),
('5bbd2f83-cf09-4db1-9f6f-8cfdb75f4a8c','竹溪直院盛稱起予草堂詩之善暇日覽之多有可恨者因效顰作十首亦前人廣騷反騷之意內二十九首用舊題惟歲寒知松柏被褐懷珠玉三首效山谷餘十八首別命題或追錄少作並存于卷以訓童蒙之意 寒機曉猶織','劉克莊','宋','宋诗','song-poetry','','[]','婉彼小家女，終年樂事稀。',72,'全唐诗/poet.song.200000.json','["婉彼小家女，終年樂事稀。", "忍寒惟業織，曉至尚聞機。", "漏聽銅壺滴，梭隨玉腕揮。", "只愁老姑促，忘送素娥歸。", "甚矣獻裘切，傷哉恤緯微。", "盈庭皆賜帛，何以補宵衣。"]'),
('b7409178-d831-4802-b076-0cc1c5705a11','竹溪直院盛稱起予草堂詩之善暇日覽之多有可恨者因效顰作十首亦前人廣騷反騷之意內二十九首用舊題惟歲寒知松柏被褐懷珠玉三首效山谷餘十八首別命題或追錄少作並存于卷以訓童蒙之意 太平無象二首 其一','劉克莊','宋','宋诗','song-poetry','','[]','試聽輿人誦，如何是太平。',72,'全唐诗/poet.song.200000.json','["試聽輿人誦，如何是太平。", "有生遂其性，無象得而名。", "刁斗三邊靜，鋤耰萬里耕。", "毋庸奏奎聚，不必誦河清。", "堯豈容知識，文非以色聲。", "樵歌殊質俚，未足贊休明。"]'),
('988d011d-98ad-4db6-81f0-b4b51f228007','竹溪直院盛稱起予草堂詩之善暇日覽之多有可恨者因效顰作十首亦前人廣騷反騷之意內二十九首用舊題惟歲寒知松柏被褐懷珠玉三首效山谷餘十八首別命題或追錄少作並存于卷以訓童蒙之意 太平無象二首 其二','劉克莊','宋','宋诗','song-poetry','','[]','治象難言說，風謠採道塗。',72,'全唐诗/poet.song.200000.json','["治象難言說，風謠採道塗。", "太平於此盛，曠古以來無。", "腰笛童鞭犢，烹葵婦饁夫。", "文如未見者，堯豈可名乎。", "禮樂河汾策，衣冠洛社圖。", "□□工黼黻，筆力若爲摹。"]'),
('88cba3dd-af53-4ba4-b244-b421b1a7e4a8','竹溪直院盛稱起予草堂詩之善暇日覽之多有可恨者因效顰作十首亦前人廣騷反騷之意內二十九首用舊題惟歲寒知松柏被褐懷珠玉三首效山谷餘十八首別命題或追錄少作並存于卷以訓童蒙之意 祖餞二疎','劉克莊','宋','宋诗','song-poetry','','[]','祖席爲誰設，諸公愧二疎。',72,'全唐诗/poet.song.200000.json','["祖席爲誰設，諸公愧二疎。", "雖無人主眷，頼有史官書。", "故里山川近，都門供帳初。", "百城圖畫筆，幾兩送寒車。", "老氏先知足，逋翁晚定儲。", "蕭生亦宮傅，歲晏竟何如。"]'),
('af8c2406-5488-42af-a86d-8639acb17749','竹溪直院盛稱起予草堂詩之善暇日覽之多有可恨者因效顰作十首亦前人廣騷反騷之意內二十九首用舊題惟歲寒知松柏被褐懷珠玉三首效山谷餘十八首別命題或追錄少作並存于卷以訓童蒙之意 四更山吐月','劉克莊','宋','宋诗','song-poetry','','[]','夜境沉沉寂，高城忽四更。',72,'全唐诗/poet.song.200000.json','["夜境沉沉寂，高城忽四更。", "山收霾凈盡，月吐魄初生。", "已過三通鼓，猶殘二尺檠。", "始疑千嶂合，徐覺半窗明。", "顧兔空留照，荒鷄太少情。", "應須煩玉斧，缺處更修成。"]'),
('cbcd022c-0ea4-4425-896e-919ecc290c8a','竹溪直院盛稱起予草堂詩之善暇日覽之多有可恨者因效顰作十首亦前人廣騷反騷之意內二十九首用舊題惟歲寒知松柏被褐懷珠玉三首效山谷餘十八首別命題或追錄少作並存于卷以訓童蒙之意 鷄鳴度關','劉克莊','宋','宋诗','song-poetry','','[]','關法晨方度，其如夜未明。',72,'全唐诗/poet.song.200000.json','["關法晨方度，其如夜未明。", "危機真虎口，急計假鷄鳴。", "唱罷城烏起，聞來野雉驚。", "秦人百二險，齊客兩三聲。", "珠履顔何厚，狐裘計已行。", "昭王見事緩，食頃遣追兵。"]'),
('44a4c288-2d28-433a-970f-c80f538baf3f','竹溪直院盛稱起予草堂詩之善暇日覽之多有可恨者因效顰作十首亦前人廣騷反騷之意內二十九首用舊題惟歲寒知松柏被褐懷珠玉三首效山谷餘十八首別命題或追錄少作並存于卷以訓童蒙之意 墮淚碑','劉克莊','宋','宋诗','song-poetry','','[]','治化無深淺，要諸久始知。',72,'全唐诗/poet.song.200000.json','["治化無深淺，要諸久始知。", "遺民它日淚，太傅向來碑。", "反袂緣何事，輕裘若在時。", "勳名一片石，尸祝百年思。", "不比山公醉，惟應湛輩悲。", "征南亦深刻，感慨者爲誰。"]'),
('5014c485-989a-407b-9a65-3ee6a0dca648','竹溪直院盛稱起予草堂詩之善暇日覽之多有可恨者因效顰作十首亦前人廣騷反騷之意內二十九首用舊題惟歲寒知松柏被褐懷珠玉三首效山谷餘十八首別命題或追錄少作並存于卷以訓童蒙之意 五言長城','劉克莊','宋','宋诗','song-poetry','','[]','五字非容易，鬚曾斷幾莖。',72,'全唐诗/poet.song.200000.json','["五字非容易，鬚曾斷幾莖。", "身雖居破屋，人比作長城。", "塞北李都尉，江東阮步兵。", "偏師攻不下，老將望而驚。", "立幟騷壇峻，降旗敵壘平。", "可憐秦系輩，淺陋欲爭衡。"]'),
('1709fca6-50b0-4c2d-a1ef-35abd5094273','竹溪直院盛稱起予草堂詩之善暇日覽之多有可恨者因效顰作十首亦前人廣騷反騷之意內二十九首用舊題惟歲寒知松柏被褐懷珠玉三首效山谷餘十八首別命題或追錄少作並存于卷以訓童蒙之意 杏壇','劉克莊','宋','宋诗','song-poetry','','[]','夫子昔居地，流傳後代看。',72,'全唐诗/poet.song.200000.json','["夫子昔居地，流傳後代看。", "竹藏壁中簡，杏落水邊壇。", "流藻尤蘩盛，依槐免折殘。", "一時雩舞樂，千古孔林寒。", "漁父繫舟聽，門人捨瑟嘆。", "世多伐木者，吾道欲行難。"]'),
('010816bd-7a19-414c-abce-854ae51237b4','竹溪直院盛稱起予草堂詩之善暇日覽之多有可恨者因效顰作十首亦前人廣騷反騷之意內二十九首用舊題惟歲寒知松柏被褐懷珠玉三首效山谷餘十八首別命題或追錄少作並存于卷以訓童蒙之意 圍棋賭墅','劉克莊','宋','宋诗','song-poetry','','[]','安石心夷曠，難將淺見窺。',72,'全唐诗/poet.song.200000.json','["安石心夷曠，難將淺見窺。", "能拚百弓墅，只賭一枰棋。", "苻虜投鞭急，羊生對弈遲。", "土山今乞汝，泉石更由誰。", "侍女收殘局，羣兒走捷旗。", "拊箏并折屐，無喜亦無悲。"]'),
('70331e5f-5090-4833-b6f7-21e3474768ca','竹溪直院盛稱起予草堂詩之善暇日覽之多有可恨者因效顰作十首亦前人廣騷反騷之意內二十九首用舊題惟歲寒知松柏被褐懷珠玉三首效山谷餘十八首別命題或追錄少作並存于卷以訓童蒙之意 飲馬長城窟','劉克莊','宋','宋诗','song-poetry','','[]','絕塞多爲窟，秦時所築城。',72,'全唐诗/poet.song.200000.json','["絕塞多爲窟，秦時所築城。", "因憐吾馬渴，教飲彼泉清。", "霜雪盧龍塞，風烟驃騎營。", "遠從貳師壘，瞥過武安坑。", "心警投鞭虜，身先荷杵兵。", "寧爲伏波死，不作李陵生。"]'),
('2587812f-6171-430a-a7a6-e4353ed8791d','竹溪直院盛稱起予草堂詩之善暇日覽之多有可恨者因效顰作十首亦前人廣騷反騷之意內二十九首用舊題惟歲寒知松柏被褐懷珠玉三首效山谷餘十八首別命題或追錄少作並存于卷以訓童蒙之意 鴈足書','劉克莊','宋','宋诗','song-poetry','','[]','塞鴈先荒徼，猨弓莫射渠。',72,'全唐诗/poet.song.200000.json','["塞鴈先荒徼，猨弓莫射渠。", "心懷南向意，足有北來書。", "翔集鴻毛迅，緘題鳥跡疎。", "上言存魏闕，下說厭穹廬。", "隴右平安遠，雲中探報虛。", "不知子卿婦，錦字託誰歟。"]'),
('f1676810-40a5-4006-931d-9e6af7df8c03','竹溪直院盛稱起予草堂詩之善暇日覽之多有可恨者因效顰作十首亦前人廣騷反騷之意內二十九首用舊題惟歲寒知松柏被褐懷珠玉三首效山谷餘十八首別命題或追錄少作並存于卷以訓童蒙之意 門多長者車','劉克莊','宋','宋诗','song-poetry','','[]','小徑通車轍，全家隠薜蘿。',72,'全唐诗/poet.song.200000.json','["小徑通車轍，全家隠薜蘿。", "俗人望崖返，長者及門多。", "往往知蝸舍，時時叩雀羅。", "鷄栖伯厚去，犢駕太丘過。", "驥尾聊同託，驪駒且莫歌。", "平生疑泄柳，不納意如何。"]'),
('f0b8b4b2-4846-47b4-b29d-bd1081cae999','竹溪直院盛稱起予草堂詩之善暇日覽之多有可恨者因效顰作十首亦前人廣騷反騷之意內二十九首用舊題惟歲寒知松柏被褐懷珠玉三首效山谷餘十八首別命題或追錄少作並存于卷以訓童蒙之意 笛裏關山月','劉克莊','宋','宋诗','song-poetry','','[]','月裏誰橫笛，秋深戰壘閑。',72,'全唐诗/poet.song.200000.json','["月裏誰橫笛，秋深戰壘閑。", "別吹新曲調，偏照舊關山。", "響激商飆起，聲隨隴水潺。", "遠傳邊塞外，高入廣寒間。", "解白嫦娥髮，能蒼壯士顔。", "倚樓人謾拜，何日凱歌還。"]'),
('127cfa51-f381-4700-9c79-91a597af2f15','竹溪直院盛稱起予草堂詩之善暇日覽之多有可恨者因效顰作十首亦前人廣騷反騷之意內二十九首用舊題惟歲寒知松柏被褐懷珠玉三首效山谷餘十八首別命題或追錄少作並存于卷以訓童蒙之意 濟河焚舟','劉克莊','宋','宋诗','song-poetry','','[]','河勢尤湍急，滔滔去莫留。',72,'全唐诗/poet.song.200000.json','["河勢尤湍急，滔滔去莫留。", "此行期死敵，既濟遂焚舟。", "背水陳師出，乘風縱燎休。", "若非拚血戰，不復渡黄流。", "竹帛今猶載，桑榆晚始收。", "後來燒棧道，毋乃祖餘謀。"]'),
('1783ffc5-f47c-49c9-abde-113de52f6e13','竹溪直院盛稱起予草堂詩之善暇日覽之多有可恨者因效顰作十首亦前人廣騷反騷之意內二十九首用舊題惟歲寒知松柏被褐懷珠玉三首效山谷餘十八首別命題或追錄少作並存于卷以訓童蒙之意 漁父辭劍','劉克莊','宋','宋诗','song-poetry','','[]','父隠於漁者，憐渠後騎追。',72,'全唐诗/poet.song.200000.json','["父隠於漁者，憐渠後騎追。", "得船從此逝，贈劍漠然辭。", "一葉吾貧甚，千金子寶之。", "僅存釣竿在，焉用太阿爲。", "齊客彈何鄙，徐君挂尚疑。", "不如葦間叟，千古勵清規。"]'),
('5bd8afe9-eab3-43d0-88fc-23add57e6cad','竹溪直院盛稱起予草堂詩之善暇日覽之多有可恨者因效顰作十首亦前人廣騷反騷之意內二十九首用舊題惟歲寒知松柏被褐懷珠玉三首效山谷餘十八首別命題或追錄少作並存于卷以訓童蒙之意 扁舟五湖','劉克莊','宋','宋诗','song-poetry','','[]','種蠡功名士，吾評蠡最優。',72,'全唐诗/poet.song.200000.json','["種蠡功名士，吾評蠡最優。", "五湖足春水，一葉寄扁舟。", "變姓乘單舸，翻身退急流。", "千金徒鑄象，萬里孰馴鷗。", "震澤鱸堪膾，蘇臺鹿已遊。", "君王既稱霸，求盡沼吳謀。"]'),
('71feb5e7-8d80-422a-bc56-ee9503b7b5ea','竹溪直院盛稱起予草堂詩之善暇日覽之多有可恨者因效顰作十首亦前人廣騷反騷之意內二十九首用舊題惟歲寒知松柏被褐懷珠玉三首效山谷餘十八首別命題或追錄少作並存于卷以訓童蒙之意 瓜田不納履','劉克莊','宋','宋诗','song-poetry','','[]','君子防微謹，嫌疑遠未然。',72,'全唐诗/poet.song.200000.json','["君子防微謹，嫌疑遠未然。", "從來納履處，不傍種瓜田。", "樊圃芸初熟，耕畦瓞已綿。", "黄臺雖可摘，東郭未嘗穿。", "尾虎懲危道，揮蠅慕昔賢。", "浪云擇地蹈，濡血在山前。"]'),
('298c7a90-5a99-4b38-952f-d623586c286b','竹溪直院盛稱起予草堂詩之善暇日覽之多有可恨者因效顰作十首亦前人廣騷反騷之意內二十九首用舊題惟歲寒知松柏被褐懷珠玉三首效山谷餘十八首別命題或追錄少作並存于卷以訓童蒙之意 李下不整冠','劉克莊','宋','宋诗','song-poetry','','[]','李下雖云僻，行人冷處看。',72,'全唐诗/poet.song.200000.json','["李下雖云僻，行人冷處看。", "彼方垂美實，渠可整巍冠。", "纔見花初縞，俄驚核可鑽。", "吾寧墊雨過，君欲切雲難。", "鶑集枝多折，螬侵顆半殘。", "誰令服章甫，拘束畏傍觀。"]'),
('6e01a4a8-0a47-4aca-a48b-de5c82aa2541','竹溪直院盛稱起予草堂詩之善暇日覽之多有可恨者因效顰作十首亦前人廣騷反騷之意內二十九首用舊題惟歲寒知松柏被褐懷珠玉三首效山谷餘十八首別命題或追錄少作並存于卷以訓童蒙之意 無絃琴','劉克莊','宋','宋诗','song-poetry','','[]','□□□琴癖，淵明獨不然。',72,'全唐诗/poet.song.200000.json','["□□□琴癖，淵明獨不然。", "所藏聊備物，欲拊更無絃。", "焦尾珍無價，朱絲絕有年。", "曾參徽外趣，肯向譜中傳。", "抱在王門下，彈於日影邊。", "兩生爲巧累，益見此翁賢。"]'),
('f662a05f-4759-4340-bf64-d22d74741ab1','竹溪直院盛稱起予草堂詩之善暇日覽之多有可恨者因效顰作十首亦前人廣騷反騷之意內二十九首用舊題惟歲寒知松柏被褐懷珠玉三首效山谷餘十八首別命題或追錄少作並存于卷以訓童蒙之意 夢見周公','劉克莊','宋','宋诗','song-poetry','','[]','汲汲懷人夢，皇皇救世功。',72,'全唐诗/poet.song.200000.json','["汲汲懷人夢，皇皇救世功。", "有心哉魯叟，所見者周公。", "政績簡編在，精神寤寐通。", "宛如尚爲左，忘却已遷東。", "鳳去經綸遠，麟來筆削終。", "空令千載下，跪奠兩楹中。"]'),
('cfb67d48-c3ea-4486-9523-c3feee7c942c','竹溪直院盛稱起予草堂詩之善暇日覽之多有可恨者因效顰作十首亦前人廣騷反騷之意內二十九首用舊題惟歲寒知松柏被褐懷珠玉三首效山谷餘十八首別命題或追錄少作並存于卷以訓童蒙之意 棋聲花院閉','劉克莊','宋','宋诗','song-poetry','','[]','靜院閉花時，沉沉晝漏移。',72,'全唐诗/poet.song.200000.json','["靜院閉花時，沉沉晝漏移。", "偶然聲出戶，應是客圍碁。", "夜寂推枰響，機深落子遲。", "惱禪天女去，入定老僧知。", "鵠至難傳藝，鶑啼許借枝。", "須臾分局勢，何待爛柯爲。"]'),
('a8b18032-79f7-4405-b5dc-d3625a929c4d','竹溪直院盛稱起予草堂詩之善暇日覽之多有可恨者因效顰作十首亦前人廣騷反騷之意內二十九首用舊題惟歲寒知松柏被褐懷珠玉三首效山谷餘十八首別命題或追錄少作並存于卷以訓童蒙之意 蒲鞭','劉克莊','宋','宋诗','song-poetry','','[]','陌上兒童說，時清長吏賢。',72,'全唐诗/poet.song.200000.json','["陌上兒童說，時清長吏賢。", "豈能無朴教，不過示蒲鞭。", "采彼輕柔質，施諸牧御權。", "坐令强梗者，若撻市朝然。", "院舍棠陰合，圜扉草色鮮。", "弛笞能敗子，威愛貴兼全。"]'),
('90495cdb-8930-485f-9d3d-1b9b26175dbc','竹溪直院盛稱起予草堂詩之善暇日覽之多有可恨者因效顰作十首亦前人廣騷反騷之意內二十九首用舊題惟歲寒知松柏被褐懷珠玉三首效山谷餘十八首別命題或追錄少作並存于卷以訓童蒙之意 隔竹敲茶臼','劉克莊','宋','宋诗','song-poetry','','[]','午杵誰敲臼，山童髻兩髽。',72,'全唐诗/poet.song.200000.json','["午杵誰敲臼，山童髻兩髽。", "偶因聲隔竹，不覺意思茶。", "北牖沉沉靜，南牆故故遮。", "微聞孤杵響，初試一旗斜。", "門掩王猷宅，泉甘陸羽家。", "搜腸攪文字，毋乃太清耶。"]'),
('f6468b76-877e-4f70-b3e7-58690a5093ee','竹溪直院盛稱起予草堂詩之善暇日覽之多有可恨者因效顰作十首亦前人廣騷反騷之意內二十九首用舊題惟歲寒知松柏被褐懷珠玉三首效山谷餘十八首別命題或追錄少作並存于卷以訓童蒙之意 西狩獲麟','劉克莊','宋','宋诗','song-poetry','','[]','獲處從西鄙，胡然瑞物臻。',72,'全唐诗/poet.song.200000.json','["獲處從西鄙，胡然瑞物臻。", "子因書曰狩，世始識爲麟。", "出匪於中國，來常以聖人。", "皆云麕且角，誰辨獸而仁。", "已嘆吾無位，于嗟汝不辰。", "茂陵好奇怪，得者惜非真。"]'),
('f815d0be-247f-4573-91f4-0ee63b8d0f2e','竹溪直院盛稱起予草堂詩之善暇日覽之多有可恨者因效顰作十首亦前人廣騷反騷之意內二十九首用舊題惟歲寒知松柏被褐懷珠玉三首效山谷餘十八首別命題或追錄少作並存于卷以訓童蒙之意 客星','劉克莊','宋','宋诗','song-poetry','','[]','不爲劉郎屈，蕭然釣遠汀。',72,'全唐诗/poet.song.200000.json','["不爲劉郎屈，蕭然釣遠汀。", "當時無此客，其象見於星。", "龍衮思同學，羊裘謁廣庭。", "九行仰黄道，一曜動青冥。", "帝座容伸足，雲臺肯繪形。", "少微非大隠，光彩謾熒熒。"]'),
('f9a6a146-7420-4c92-adcb-bb59d5187065','竹溪直院盛稱起予草堂詩之善暇日覽之多有可恨者因效顰作十首亦前人廣騷反騷之意內二十九首用舊題惟歲寒知松柏被褐懷珠玉三首效山谷餘十八首別命題或追錄少作並存于卷以訓童蒙之意 掬水月在手','劉克莊','宋','宋诗','song-poetry','','[]','月體無拘礙，那堪得水清。',72,'全唐诗/poet.song.200000.json','["月體無拘礙，那堪得水清。", "暫從掬處動，還在水中明。", "長物瓢安用，寒光握不盈。", "注眸蟾彩亂，入掌蚌珠生。", "顧兔攀難住，騎鯨捉太輕。", "猶勝倒持版，去作晉公卿。"]'),
('da4e549b-263d-44d7-b858-c9977ca9ff34','竹溪直院盛稱起予草堂詩之善暇日覽之多有可恨者因效顰作十首亦前人廣騷反騷之意內二十九首用舊題惟歲寒知松柏被褐懷珠玉三首效山谷餘十八首別命題或追錄少作並存于卷以訓童蒙之意 弄花香滿衣','劉克莊','宋','宋诗','song-poetry','','[]','偶弄閑花久，春濃晚露晞。',72,'全唐诗/poet.song.200000.json','["偶弄閑花久，春濃晚露晞。", "是誰設香供，終日滿人衣。", "戲把繁枝玩，常愁一片飛。", "疑薰沉水過，似惹御罏歸。", "若愛流芳遠，深憐逐臭非。", "平生好奇服，未忍改菲菲。"]'),
('4a71dfde-eb0a-4f5b-b263-735e20dfa50f','竹溪直院盛稱起予草堂詩之善暇日覽之多有可恨者因效顰作十首亦前人廣騷反騷之意內二十九首用舊題惟歲寒知松柏被褐懷珠玉三首效山谷餘十八首別命題或追錄少作並存于卷以訓童蒙之意 肅時雨若','劉克莊','宋','宋诗','song-poetry','','[]','肅在於方寸，高高已嘿知。',72,'全唐诗/poet.song.200000.json','["肅在於方寸，高高已嘿知。", "端能令雨若，焉敢諉天時。", "此念淵冰凜，其機影響隨。", "寶薰一隊起，銀竹四簷垂。", "有物皆膏潤，無民更怨咨。", "諄諄書喜閔，麟筆寓箴規。"]'),
('74bffc2f-0ebb-4b86-acee-d5f1c7592921','竹溪直院盛稱起予草堂詩之善暇日覽之多有可恨者因效顰作十首亦前人廣騷反騷之意內二十九首用舊題惟歲寒知松柏被褐懷珠玉三首效山谷餘十八首別命題或追錄少作並存于卷以訓童蒙之意 渴不飲盜泉水','劉克莊','宋','宋诗','song-poetry','','[]','飲啄於身切，宜無决擇然。',72,'全唐诗/poet.song.200000.json','["飲啄於身切，宜無决擇然。", "豈其陽忍渴，嫌以盜名泉。", "北澤行猶至，東陵惡莫湔。", "羞爲濫觴者，寧作挂瓢賢。", "激齒希高士，流涎異醉仙。", "枯腸一勺足，勿傍石門邊。"]'),
('9100c7b0-eeb2-4991-ae91-513b1f7009e5','竹溪直院盛稱起予草堂詩之善暇日覽之多有可恨者因效顰作十首亦前人廣騷反騷之意內二十九首用舊題惟歲寒知松柏被褐懷珠玉三首效山谷餘十八首別命題或追錄少作並存于卷以訓童蒙之意 熱不息惡木陰','劉克莊','宋','宋诗','song-poetry','','[]','觸熱慵休息，誰知志士心。',72,'全唐诗/poet.song.200000.json','["觸熱慵休息，誰知志士心。", "既名爲惡木，不可就繁陰。", "炎赫當三伏，輪囷欲百尋。", "蔽牛徒隠映，下馬復沉吟。", "濁世無孤竹，中原有鄧林。", "飄然遠遊興，散髮更披襟。"]'),
('d0c26c19-1a8a-4d03-8b83-af41d17ea4e7','竹溪直院盛稱起予草堂詩之善暇日覽之多有可恨者因效顰作十首亦前人廣騷反騷之意內二十九首用舊題惟歲寒知松柏被褐懷珠玉三首效山谷餘十八首別命題或追錄少作並存于卷以訓童蒙之意 洗硯魚吞墨','劉克莊','宋','宋诗','song-poetry','','[]','一硯常摩拊，寧容點涴痕。',72,'全唐诗/poet.song.200000.json','["一硯常摩拊，寧容點涴痕。", "洗教殘墨去，乞與小魚吞。", "巖石微塵浣，漥泉寸鬣翻。", "安知馬肝紫，姑愛麝膠渾。", "體製該秦篆，飛騰慕禹門。", "校人勿烹汝，腹有素書存。"]'),
('6fe61a86-b6b5-421c-80a3-4bfd1e48b6ec','竹溪直院盛稱起予草堂詩之善暇日覽之多有可恨者因效顰作十首亦前人廣騷反騷之意內二十九首用舊題惟歲寒知松柏被褐懷珠玉三首效山谷餘十八首別命題或追錄少作並存于卷以訓童蒙之意 烹茶鶴避煙','劉克莊','宋','宋诗','song-poetry','','[]','吾鶴尤馴擾，俄如引避然。',72,'全唐诗/poet.song.200000.json','["吾鶴尤馴擾，俄如引避然。", "何曾厭茅舍，多是爲茶煙。", "活計窮桑苧，枯腸老玉川。", "蒼頭猶爨下，丹頂已松顛。", "渴飲誰能免，高飛爾自賢。", "須臾休茗事，却下竹傍邊。"]'),
('3813b3a8-5043-4c28-9116-4238eb5687dc','竹溪直院盛稱起予草堂詩之善暇日覽之多有可恨者因效顰作十首亦前人廣騷反騷之意內二十九首用舊題惟歲寒知松柏被褐懷珠玉三首效山谷餘十八首別命題或追錄少作並存于卷以訓童蒙之意 僧敲月下門','劉克莊','宋','宋诗','song-poetry','','[]','古寺何年廢，松門月似冰。',72,'全唐诗/poet.song.200000.json','["古寺何年廢，松門月似冰。", "間然孰爲主，敲者只歸僧。", "地僻禪扃寂，天高兔魄升。", "周遊何處晚，剝啄有誰譍。", "未易分鄰燭，又難上佛燈。", "安知無島輩，開戶結詩盟。"]'),
('dfeffa42-6cac-43cd-bb86-91a25858d26e','竹溪直院盛稱起予草堂詩之善暇日覽之多有可恨者因效顰作十首亦前人廣騷反騷之意內二十九首用舊題惟歲寒知松柏被褐懷珠玉三首效山谷餘十八首別命題或追錄少作並存于卷以訓童蒙之意 惜花春起早','劉克莊','宋','宋诗','song-poetry','','[]','清早披衣起，春深好事家。',72,'全唐诗/poet.song.200000.json','["清早披衣起，春深好事家。", "非干眠警枕，自是惜名花。", "培溉疎泉脈，攀翻带露葩。", "看常先曉蝶，來未散晨鴉。", "風惡爲臺避，晴烘著幙遮。", "古人云晝短，莫待夕陽斜。"]'),
('45184989-5f71-4561-8445-7b5fe0f4e6e4','竹溪直院盛稱起予草堂詩之善暇日覽之多有可恨者因效顰作十首亦前人廣騷反騷之意內二十九首用舊題惟歲寒知松柏被褐懷珠玉三首效山谷餘十八首別命題或追錄少作並存于卷以訓童蒙之意 愛月夜眠遲','劉克莊','宋','宋诗','song-poetry','','[]','性癖多幽事，尤於愛月偏。',72,'全唐诗/poet.song.200000.json','["性癖多幽事，尤於愛月偏。", "遠從天際待，遲至夜深眠。", "方恨冰輪缺，俄欣玉鏡圓。", "且哦丹桂下，未傍大槐邊。", "快欲騎鯨去，輕如化蝶然。", "徘徊惜餘景，窗下映陳編。"]'),
('d77650a4-c980-4ca5-97d0-4621ae1feaca','竹溪直院盛稱起予草堂詩之善暇日覽之多有可恨者因效顰作十首亦前人廣騷反騷之意內二十九首用舊題惟歲寒知松柏被褐懷珠玉三首效山谷餘十八首別命題或追錄少作並存于卷以訓童蒙之意 師直爲壯','劉克莊','宋','宋诗','song-poetry','','[]','勝負無常數，先觀曲直知。',72,'全唐诗/poet.song.200000.json','["勝負無常數，先觀曲直知。", "隠然壯吾國，孰敢敵王師。", "致討皆聲罪，徂征必有辭。", "一言明逆順，大勢决雄雌。", "縞素炎圖定，包茅霸業基。", "後儒喜穿鑿，妄意說升陑。"]'),
('dede8108-3a6a-4e26-b3b5-d9aaea241882','竹溪直院盛稱起予草堂詩之善暇日覽之多有可恨者因效顰作十首亦前人廣騷反騷之意內二十九首用舊題惟歲寒知松柏被褐懷珠玉三首效山谷餘十八首別命題或追錄少作並存于卷以訓童蒙之意 歲寒知松柏 其一','劉克莊','宋','宋诗','song-poetry','','[]','植物惟松柏，蒼蒼貫四時。',72,'全唐诗/poet.song.200000.json','["植物惟松柏，蒼蒼貫四時。", "歲雖寒不改，人到老方知。", "風籟龍吟冷，冰枝鶴立危。", "一株獨青在，萬木後凋誰。", "齊寢樵蘇矣，秦宮點涴之。", "斧斤尋未已，善保棟梁姿。"]'),
('072e1cd1-5f68-4a10-8258-64c335bc60bd','竹溪直院盛稱起予草堂詩之善暇日覽之多有可恨者因效顰作十首亦前人廣騷反騷之意內二十九首用舊題惟歲寒知松柏被褐懷珠玉三首效山谷餘十八首別命題或追錄少作並存于卷以訓童蒙之意 歲寒知松柏 其二','劉克莊','宋','宋诗','song-poetry','','[]','松柏無姿媚，平時未易看。',72,'全唐诗/poet.song.200000.json','["松柏無姿媚，平時未易看。", "要知渠特操，直待歲隆寒。", "塞草枯先白，江楓冷變丹。", "凜然友青士，至此識蒼官。", "物遁天刑少，人全晚節難。", "惟應漆園叟，與蕣合而觀。"]'),
('4c978aba-81e1-4c3f-96fc-5580890674fd','竹溪直院盛稱起予草堂詩之善暇日覽之多有可恨者因效顰作十首亦前人廣騷反騷之意內二十九首用舊題惟歲寒知松柏被褐懷珠玉三首效山谷餘十八首別命題或追錄少作並存于卷以訓童蒙之意 被褐懷珠玉','劉克莊','宋','宋诗','song-poetry','','[]','珠玉嫌輕衒，深藏意自佳。',72,'全唐诗/poet.song.200000.json','["珠玉嫌輕衒，深藏意自佳。", "不歸胡賈手，却入褐夫懷。", "寬博寧儒戲，從容與道偕。", "用之薦郊廟，捨則媚淵崖。", "龍起驚空藏，虹來貫小齋。", "平生不求售，非爲價難諧。"]'),
('29320224-b14b-442f-97f2-935cc03e7bc8','送明甫赴銅鉛場六言七首  其一','劉克莊','宋','宋诗','song-poetry','','[]','文度何須膝上，阿奴姑可目前。',28,'全唐诗/poet.song.200000.json','["文度何須膝上，阿奴姑可目前。", "載馳載驅王事，一喜一懼父年。"]'),
('6dcae574-948b-4384-975d-032c0860ef0a','送明甫赴銅鉛場六言七首  其二','劉克莊','宋','宋诗','song-poetry','','[]','鹽鐵論兒讀否，聚歛臣子攻之。',28,'全唐诗/poet.song.200000.json','["鹽鐵論兒讀否，聚歛臣子攻之。", "公卿大夫民賊，賢良文學汝師。"]'),
('1ac8b9b0-75f2-4f9a-9970-242fd67ba7df','送明甫赴銅鉛場六言七首  其三','劉克莊','宋','宋诗','song-poetry','','[]','山程行店絕少，官舍去家匪遥。',28,'全唐诗/poet.song.200000.json','["山程行店絕少，官舍去家匪遥。", "吾聞粉□□□，□□紅巾已梟。"]'),
('15a7276b-fa36-4031-aa23-53e2ec36640e','送明甫赴銅鉛場六言七首  其四','劉克莊','宋','宋诗','song-poetry','','[]','旦市有攫金者，地靈豈愛寶哉。',28,'全唐诗/poet.song.200000.json','["旦市有攫金者，地靈豈愛寶哉。", "零陵貪而乳盡，合浦清而蚌迴。"]'),
('02e1249c-b338-4fa7-9ac6-8a3dcd0fc438','送明甫赴銅鉛場六言七首  其五','劉克莊','宋','宋诗','song-poetry','','[]','世祿鮮由禮法，家駒勿使荒嬉。',28,'全唐诗/poet.song.200000.json','["世祿鮮由禮法，家駒勿使荒嬉。", "但願兒讀十紙，孰云孫隔一皮。"]'),
('ba3a2c0c-9369-46e3-94d8-08cfffd35f5a','送明甫赴銅鉛場六言七首  其六','劉克莊','宋','宋诗','song-poetry','','[]','化蝶但貪睡美，舐犢尚爲愛牽。',28,'全唐诗/poet.song.200000.json','["化蝶但貪睡美，舐犢尚爲愛牽。", "三年不見心痗，十日無書眼穿。"]'),
('8b8b086a-8bdc-4d85-b0c9-52a45ebf3639','戊午生朝和居厚弟五絕  其一','劉克莊','宋','宋诗','song-poetry','','[]','懶值懸弧渾不記，老當還笏復奚疑。',32,'全唐诗/poet.song.200000.json','["懶值懸弧渾不記，老當還笏復奚疑。", "潞公未得爲全福，晚惜齋旄尚涕垂。"]'),
('65ab2349-e564-47ef-aae4-9a35d4923b0c','戊午生朝和居厚弟五絕  其二','劉克莊','宋','宋诗','song-poetry','','[]','符輩安能剗且編，可憐辛苦事雕鎸。',32,'全唐诗/poet.song.200000.json','["符輩安能剗且編，可憐辛苦事雕鎸。", "絕絃舉世無能聽，覆瓿他時未必傳。"]'),
('34f4e121-358a-441e-8b43-2b73679099fe','戊午生朝和居厚弟五絕  其三','劉克莊','宋','宋诗','song-poetry','','[]','□□□□□□□，□□□□□□□。',32,'全唐诗/poet.song.200000.json','["□□□□□□□，□□□□□□□。", "□□□□□□從，晚福全輸於少公。"]'),
('9c5c8cf3-5f39-44e4-ac57-531b5a8d69ee','戊午生朝和居厚弟五絕  其四','劉克莊','宋','宋诗','song-poetry','','[]','靈龜曳尾防鑽殻，老蚌潜光怕剖珠。',32,'全唐诗/poet.song.200000.json','["靈龜曳尾防鑽殻，老蚌潜光怕剖珠。", "史筆久無兩龔傳，畫家曾有二疎圖。"]'),
('69d8c9e6-1bc5-4f4a-bf7f-744ba6803aa1','戊午生朝和居厚弟五絕  其五','劉克莊','宋','宋诗','song-poetry','','[]','曾結詩絇玉座傍，放狂歸去老知章。',32,'全唐诗/poet.song.200000.json','["曾結詩絇玉座傍，放狂歸去老知章。", "鈍遲一任嘲元白，迂闊皆因駮錄黄。"]'),
('36043b4a-0e35-470c-8a58-5fc48a379d7b','昔與仙遊傅常博父子游從識其幼子方總角晚歸田里忽袖二詩見訪余開八秩君亦六十矣感歎之餘因次其韻  其一','劉克莊','宋','宋诗','song-poetry','','[]','議郎座上識郎君，竊意趨庭有異聞。',64,'全唐诗/poet.song.200000.json','["議郎座上識郎君，竊意趨庭有異聞。", "客屨今無同輩在，書燈昔與長公分。", "蟲冰寒暑余侵耄，螢雪光陰子尚勤。", "見說架籤猶萬卷，肯將濁臭博清芬。"]'),
('fea52ea2-05ba-4775-b51e-34e54061afe5','昔與仙遊傅常博父子游從識其幼子方總角晚歸田里忽袖二詩見訪余開八秩君亦六十矣感歎之餘因次其韻  其二','劉克莊','宋','宋诗','song-poetry','','[]','窗下陳編懶更窺，還丹難染鏡中絲。',64,'全唐诗/poet.song.200000.json','["窗下陳編懶更窺，還丹難染鏡中絲。", "後生可畏前賢遠，妄校皆封老將奇。", "辟穀差賢東郭乞，歸耕莫待北山移。", "鳳凰池聽渠儂奪，不奪溪邊放鴨池。"]'),
('323757c2-c9e3-4425-9b63-a59533afbcf0','送方蒙仲赴辟江閫分韻得既字','劉克莊','宋','宋诗','song-poetry','','[]','昔忝玉麟招，主君解衣衣。',240,'全唐诗/poet.song.200000.json','["昔忝玉麟招，主君解衣衣。", "於時事會來，中原方鼎沸。", "封侯命大謬，更僕談未既。", "俯仰四十年，歲月堪累欷。", "多壘諸公辱，萬竈大農費。", "玁狁至于涇，顓臾近於費。", "譬如寢積薪，徒幸火然未。", "邊人厭虜暴，別都尚王氣。", "管鑰居守尊，衮鉞宗臣貴。", "呼吸草檄書，蒐揀拔茅彙。", "粲粲玄英孫，魯叟之所畏。", "枚鄒願游梁，陳阮亦客魏。", "非惟揖將軍，抑可歡大尉。", "殺羊必及斟，啖鵝肯移毅。", "拙謀鄙畫江，長策在耕渭。", "駕馭雄狡服，拊摩軍民慰。", "要當掃旄頭，寧論爛羊胃。", "病翁越世久，嚼蠟淡無味。", "膽薄怯觀井，憂深遑恤緯。", "臨分執玉手，苦言君勿諱。"]'),
('f5ab06a4-3c8d-42c0-85d7-bbd24315b1c7','再送蒙仲二首  其一','劉克莊','宋','宋诗','song-poetry','','[]','昔人曾歎擇棲難，今子翱游二相間。',64,'全唐诗/poet.song.200000.json','["昔人曾歎擇棲難，今子翱游二相間。", "對弈未妨看露布，論詩未合上齋壇。", "沉來鐵鏁真兒戲，吟退氈裘却凱還。", "班固作銘繇捷表，待揩老眼細傳觀。"]'),
('e1391db1-b773-41fe-b554-77f4b4446f05','再送蒙仲二首  其二','劉克莊','宋','宋诗','song-poetry','','[]','送君懷舊一銷魂，謝墅孫陵髣髴存。',64,'全唐诗/poet.song.200000.json','["送君懷舊一銷魂，謝墅孫陵髣髴存。", "下瀨樓船皆萬斛，曲江宮殿尚千門。", "笑陳狎客爲俳體，與晉諸賢洗淚痕。", "定有奇謀裨玉帳，莫揮麈尾事清言。"]'),
('fff384f7-711c-4400-8e0d-2072c6baf373','題讀碑圖','劉克莊','宋','宋诗','song-poetry','','[]','二人共讀道旁碑，一敏一鈍天賦之。',98,'全唐诗/poet.song.200000.json','["二人共讀道旁碑，一敏一鈍天賦之。", "敏者過目躍騎去，鈍者停鞭方凝思。", "哀哉德祖丹頸禍，伏於伯喈黄絹辭。", "古人服善有公是，回也知十賜知二。", "聖師笑曰女弗如，未聞端木惎顔氏。", "嗚呼向使顔氏逢若人，未知何地堪容身。"]'),
('5450d0d7-0bf9-42fe-bd71-a5117fe35210','溪庵放言十首  其一','劉克莊','宋','宋诗','song-poetry','','[]','石槨隄防速朽，金棺粧點湼槃。',28,'全唐诗/poet.song.200000.json','["石槨隄防速朽，金棺粧點湼槃。", "說乾矢橛差勝，戀臭皮袋一般。"]'),
('3757a63b-f4fb-4669-ab0a-6288170bb578','溪庵放言十首  其二','劉克莊','宋','宋诗','song-poetry','','[]','八斛四斗舍利，一丈六尺金身。',28,'全唐诗/poet.song.200000.json','["八斛四斗舍利，一丈六尺金身。", "右脅已寂已滅，雙趺是妄是真。"]'),
('b2cfa695-0157-4858-a843-d0fd2012be8f','溪庵放言十首  其三','劉克莊','宋','宋诗','song-poetry','','[]','擬拉陶潛入社，不消王翰卜鄰。',28,'全唐诗/poet.song.200000.json','["擬拉陶潛入社，不消王翰卜鄰。", "有夢通華胥國，無德薰晉鄙人。"]'),
('cda10723-2326-48af-8679-a768899d7821','溪庵放言十首  其四','劉克莊','宋','宋诗','song-poetry','','[]','客子相過有携，先生爛醉如泥。',28,'全唐诗/poet.song.200000.json','["客子相過有携，先生爛醉如泥。", "暮年尚可三爵，他日不煩隻鷄。"]'),
('82289bee-37a6-4c41-92a5-64c55a7fcab2','溪庵放言十首  其五','劉克莊','宋','宋诗','song-poetry','','[]','辟疆驅名士出，穰侯怕說客來。',28,'全唐诗/poet.song.200000.json','["辟疆驅名士出，穰侯怕說客來。", "樗庵無一錢事，柴門作八字開。"]'),
('cd85f5a2-6905-4013-9613-97992b8cf1bb','溪庵放言十首  其六','劉克莊','宋','宋诗','song-poetry','','[]','少而汲汲皇皇，老猶踽踽凉凉。',28,'全唐诗/poet.song.200000.json','["少而汲汲皇皇，老猶踽踽凉凉。", "即今歸□□□，□□起瞻四方。"]'),
('afbfbf5a-8850-4717-a787-7190632028cf','溪庵放言十首  其七','劉克莊','宋','宋诗','song-poetry','','[]','蒙叟之言卓詭，尹喜之事誕夸。',28,'全唐诗/poet.song.200000.json','["蒙叟之言卓詭，尹喜之事誕夸。", "白雲騰上尸假，紫氣橫空眼花。"]'),
('9f8f6e49-b403-4cc7-90b4-fa60761a0a78','溪庵放言十首  其八','劉克莊','宋','宋诗','song-poetry','','[]','林處士功行滿，譙先生鬚眉蒼。',28,'全唐诗/poet.song.200000.json','["林處士功行滿，譙先生鬚眉蒼。", "見說兩川喪亂，不知二叟在亡。"]'),
('d630ff4a-a7c7-46d8-9839-6d05ee41305d','溪庵放言十首  其九','劉克莊','宋','宋诗','song-poetry','','[]','廢陵有斧柏盜，清野無澆松人。',28,'全唐诗/poet.song.200000.json','["廢陵有斧柏盜，清野無澆松人。", "百年幸生佛國，一點不吹戰塵。"]'),
('99a3eb0a-94d8-4bdf-a809-12d2b01ce5fd','溪庵放言十首  其一○','劉克莊','宋','宋诗','song-poetry','','[]','市朝易得虛誇，鄉井難諱實年。',28,'全唐诗/poet.song.200000.json','["市朝易得虛誇，鄉井難諱實年。", "還笏殿前已晚，飾巾牖下差賢。"]'),
('fd8cc9e5-1133-4e66-b781-34e644c617ac','別宋倅一首','劉克莊','宋','宋诗','song-poetry','','[]','往昔少司農，朱幡牧刺桐。',48,'全唐诗/poet.song.200000.json','["往昔少司農，朱幡牧刺桐。", "見碑懷叔子，有廟祀文翁。", "家法惟清白，軍儲必腐紅。", "遥知門戶肅，不與賈胡通。"]'),
('cd33c493-81a1-436d-a920-a7d9de6a4307','酈生長揖圖','劉克莊','宋','宋诗','song-poetry','','[]','高陽狂生六十餘，入謁自通臣博徒。',123,'全唐诗/poet.song.200000.json','["高陽狂生六十餘，入謁自通臣博徒。", "劉季嫚士如庸奴，對客濯足以兩姝。", "生云足下扶義初，奈何不禮長者乎。", "隆準一笑延坐隅，與隨何輩載後車。", "刻六國印識尤迂，向微留侯幾誤渠。", "胡雛聞人說漢書，千載而下猶揶揄。", "掉舌所得良區區，投身沸鼎何其愚。", "嗚呼，博徒果不賢腐儒。"]'),
('236f5f3e-37b9-42e8-bb64-2d3532fd7fc6','觀調發四首  其一','劉克莊','宋','宋诗','song-poetry','','[]','路傍紛紛送者誰，相顧淚下如綆縻。',88,'全唐诗/poet.song.200000.json','["路傍紛紛送者誰，相顧淚下如綆縻。", "妻牽郎衣留不得，兒抱爺頸尤可悲。", "寄聲征夫且止淚，矯情勿爲識者窺。", "國貧端坐養士耳，汝曹衣廩民血髓。", "邊頭戰士寒墮指，霜風獵獵陣雲起，湓城善地亦靠裏。"]'),
('f80027e0-28fd-4bbd-9013-9a4e2257f8b3','觀調發四首  其二','劉克莊','宋','宋诗','song-poetry','','[]','南州健兒生佛國，平時寬博如逢掖。',96,'全唐诗/poet.song.200000.json','["南州健兒生佛國，平時寬博如逢掖。", "一朝烟塵起荆益，半夜虎符來抽摘。", "逗撓法嚴羽檄迫，倉皇受甲面藍色。", "病夫少也曾從戎，今成新豐折臂翁。", "兒郎行矣早策功，安知行間無呂蒙。", "虜來定作太尉公，虜去暴露賞亦濃。"]'),
('d6da82f8-2ed0-4f1b-8cb8-2bdf253ffb94','觀調發四首  其三','劉克莊','宋','宋诗','song-poetry','','[]','大胡自來未易當，謂鞭可投沙可囊。',96,'全唐诗/poet.song.200000.json','["大胡自來未易當，謂鞭可投沙可囊。", "廟謨先事自爲備，天塹雖險難撤防。", "健兒白叟鄉之望，願聞一語以自壯。", "老儒無以激發君，歷歷爲君說名將。", "武襄貴不除黥文，韓岳亦隸河北軍。", "當時繿縷何足云，異日掛劍圖元勳。"]'),
('bbb92536-3864-4968-b5a9-1ec16d45c1d9','觀調發四首  其四','劉克莊','宋','宋诗','song-poetry','','[]','胡馬止能戰平地，安知東南有長技。',96,'全唐诗/poet.song.200000.json','["胡馬止能戰平地，安知東南有長技。", "大江無時起風濤，下瀨樓船如屋高。", "丕堅二子曾奪魄，曰彼有人此勍敵。", "當時百萬鳥獸奔，况爾小醜真游魂。", "婦語藁砧閈語罷，鼓行勿信傍人嚇。", "明年漢淮春水生，凱旋笳吹來相迎。"]'),
('f3fbb73d-c9bf-415d-a2f8-f9285b30c302','九日二首  其一','劉克莊','宋','宋诗','song-poetry','','[]','拒霜過了菊又慳，紈扇知收覺薄寒。',64,'全唐诗/poet.song.200000.json','["拒霜過了菊又慳，紈扇知收覺薄寒。", "鄰有新篘謀醉易，家無舊繡補衣難。", "今誰狂客同吹帽，老不中書合免冠。", "人到暮年親舊少，登臨非復曩時歡。"]'),
('cf20957d-2529-43e6-87d8-8deaacb5b867','九日二首  其二','劉克莊','宋','宋诗','song-poetry','','[]','戲馬呼鷹蓋世豪，廢臺千載委蓬蒿。',64,'全唐诗/poet.song.200000.json','["戲馬呼鷹蓋世豪，廢臺千載委蓬蒿。", "不愁絳縣疑年甲，生怕清溪照鬢毛。", "濁酒悶人聊飲濕，小樓携客準登高。", "落英果可充腸否，空和陶詩續楚騷。"]'),
('3362d3d0-b63e-4bd4-b682-da39d3a41da6','三和友人有所思韻','劉克莊','宋','宋诗','song-poetry','','[]','某邱某水晚重遊，絕勝才翁在許州。',64,'全唐诗/poet.song.200000.json','["某邱某水晚重遊，絕勝才翁在許州。", "懶學少年條痛楚，且同騷客賦牢愁。", "懸知五鬼爲渠祟，不曉三彭有底仇。", "兀坐蓬窗無意緒，凍蛩唧唧更鳴秋。"]'),
('632eb1ca-0b77-4ab4-af11-f9b14f320d99','四和','劉克莊','宋','宋诗','song-poetry','','[]','昔年東觀接英遊，歲晚南柯各拜州。',64,'全唐诗/poet.song.200000.json','["昔年東觀接英遊，歲晚南柯各拜州。", "炊黍有時成幻夢，著書自古要窮愁。", "散花魔女聊相惱，□□□□□□仇。", "詔募佽飛求跅弛，與公投筆去防秋。"]'),
('14ef9e98-a68f-4473-853b-1274cd2b30e4','雜題十首  其一','劉克莊','宋','宋诗','song-poetry','','[]','雞絮交懽遠，琵琶寄恨深。',24,'全唐诗/poet.song.200000.json','["雞絮交懽遠，琵琶寄恨深。", "早知胡地冷，永巷亦甘心。"]'),
('3141dc1b-714a-45a7-9783-8c3f82606043','雜題十首  其二','劉克莊','宋','宋诗','song-poetry','','[]','鴈足書良是，鸞膠事已非。',24,'全唐诗/poet.song.200000.json','["鴈足書良是，鸞膠事已非。", "如何子卿內，不待藁砧歸。"]'),
('63482ed6-b372-4dcc-99bc-b2cd3bef8c66','雜題十首  其三','劉克莊','宋','宋诗','song-poetry','','[]','人事多翻覆，由來不可量。',24,'全唐诗/poet.song.200000.json','["人事多翻覆，由來不可量。", "安知議郎女，遠嫁左賢王。"]'),
