('92b048e7-b365-464d-84b6-e68849784d89','雜題十首  其八','劉克莊','宋','宋诗','song-poetry','','[]','父魄下沉淵，兒聲上徹天。',24,'全唐诗/poet.song.200000.json','["父魄下沉淵，兒聲上徹天。", "向令逢孔氏，是亦女參騫。"]'),
('60004546-880d-4bb8-a3cc-72219f8371b8','雜題十首  其九','劉克莊','宋','宋诗','song-poetry','','[]','淑妃寒食語，千載尚堪哀。',24,'全唐诗/poet.song.200000.json','["淑妃寒食語，千載尚堪哀。", "不念同光帝，□□□□□。"]'),
('d8996f86-2ae3-4dcc-8e4f-3cddbfd8d28c','雜題十首  其一○','劉克莊','宋','宋诗','song-poetry','','[]','劉季開基主，周昌託子臣。',24,'全唐诗/poet.song.200000.json','["劉季開基主，周昌託子臣。", "不能活如意，何况戚夫人。"]'),
('29811d14-aa0e-4426-b928-0e10f3be7218','送方楷之官','劉克莊','宋','宋诗','song-poetry','','[]','博雅今蕭翼，招延小孟嘗。',48,'全唐诗/poet.song.200000.json','["博雅今蕭翼，招延小孟嘗。", "雖操牙算子，不廢□□□。", "祕篋珍儲富，公車薦墨香。", "惟應猿鶴怨，三載□□房。"]'),
('12a2725b-2310-4072-98d2-6d0c8441ae8b','余自戊申春得疾止酒十年戊午秋開戒小飲二首  其一','劉克莊','宋','宋诗','song-poetry','','[]','久罷長鯨吸，寧逃鼴鼠嘲。',48,'全唐诗/poet.song.200000.json','["久罷長鯨吸，寧逃鼴鼠嘲。", "不蒙藥王力，悞絕麴生交。", "撲鼻詩情動，澆胸世事拋。", "暮齡尋舊好，如以漆投膠。"]'),
('8d107603-1b90-4782-9c54-42f904a699d4','余自戊申春得疾止酒十年戊午秋開戒小飲二首  其二','劉克莊','宋','宋诗','song-poetry','','[]','自是病軀孱，元非飲量慳。',48,'全唐诗/poet.song.200000.json','["自是病軀孱，元非飲量慳。", "災星俄引去，美祿稍支還。", "兀兀醺酣後，蘧蘧解脫間。", "祖云誰縛汝，妙語頗相關。"]'),
('3f589824-9602-4606-998c-4454b1d730d1','漳蘭爲丁竊貨其半紀實四首  其一','劉克莊','宋','宋诗','song-poetry','','[]','五十盆蒼翠，皆從異縣求。',48,'全唐诗/poet.song.200000.json','["五十盆蒼翠，皆從異縣求。", "不能防狡窟，未免破鴻溝。", "慘甚兵初過，苛于吏倍抽。", "渠儂慕銅臭，肯爲國香謀。"]'),
('1086c504-2c31-4c39-abbd-a23418abd64d','漳蘭爲丁竊貨其半紀實四首  其二','劉克莊','宋','宋诗','song-poetry','','[]','主人拙樊圃，家賊巧穿窬。',48,'全唐诗/poet.song.200000.json','["主人拙樊圃，家賊巧穿窬。", "鼠子敢予侮，麟翁以盜書。", "空搔雙白鬢，不奈一長鬚。", "自笑關防晚，花傍且燕居。"]'),
('fa26fc34-4285-4ea6-8134-0d0adc081d3c','漳蘭爲丁竊貨其半紀實四首  其三','劉克莊','宋','宋诗','song-poetry','','[]','池遠疎澆溉，牆低劣蔽遮。',48,'全唐诗/poet.song.200000.json','["池遠疎澆溉，牆低劣蔽遮。", "初無虎守杏，况有蝶穿花。", "薄采難紉佩，深培待茁芽。", "嗟余愧迂叟，招汝興仍賒。"]'),
('7bebedb6-2e9a-4f58-8ca7-ce073399943b','漳蘭爲丁竊貨其半紀實四首  其四','劉克莊','宋','宋诗','song-poetry','','[]','離騷賞風韻，百卉莫之先。',48,'全唐诗/poet.song.200000.json','["離騷賞風韻，百卉莫之先。", "菊止香九日，蕕曾臭十年。", "麝房吾割愛，鮑肆爾垂涎。", "晏相惜花者，紅梅被竊然。"]'),
('59f05320-d67f-4de7-a4d8-8af335530b26','蒙仲以二畫壽予生朝各題一詩 四皓圖','劉克莊','宋','宋诗','song-poetry','','[]','人彘昔擅寵，奪嫡謀甚工。',96,'全唐诗/poet.song.200000.json','["人彘昔擅寵，奪嫡謀甚工。", "留侯莫容喙，何况短後雄。", "挽回龍準帝，全頼皓首翁。", "昔去避嬴世，今來安劉宗。", "呂嫗及新君，略未聞褒崇。", "豈非羽翼成，翩然返橘中。", "奈何一代史，不載四叟終。", "商山有遺廟，郭謂太古風。"]'),
('98df8e68-9bd6-47b3-a1db-7f79371e4155','蒙仲以二畫壽予生朝各題一詩 二疎圖','劉克莊','宋','宋诗','song-poetry','','[]','□漢七葉主，勵精致中興。',96,'全唐诗/poet.song.200000.json','["□漢七葉主，勵精致中興。", "非惟霸王雜，亦以刑名繩。", "哀哉三能臣，來如蛾赴燈。", "賢矣二大夫，逝若魚脫罾。", "韓蘚至崛彊，異世猶服膺。", "嗟余歸已晚，釣游記昔曾。", "雖無都門餞，幸有下澤乘。", "獨恨賜金盡，無以懽親朋。"]'),
('dc2f54b2-4c22-4763-8bd1-a4a65f074aa1','冬煖海棠盛開三絕  其一','劉克莊','宋','宋诗','song-poetry','','[]','敗荷折蓼溪村景，黄葉青苔野老家。',32,'全唐诗/poet.song.200000.json','["敗荷折蓼溪村景，黄葉青苔野老家。", "頼有海棠相煖熱，小春重放一番花。"]'),
('5ff280a2-2ec0-40e9-af49-7de8feb133a4','冬煖海棠盛開三絕  其二','劉克莊','宋','宋诗','song-poetry','','[]','少爲紫陌看花郎，歲晚維摩住病坊。',32,'全唐诗/poet.song.200000.json','["少爲紫陌看花郎，歲晚維摩住病坊。", "忽被彩雲瞞老眼，錯呼青女作紅娘。"]'),
('48d8fc61-2371-4d48-b8b5-97bc458cecc2','冬煖海棠盛開三絕  其三','劉克莊','宋','宋诗','song-poetry','','[]','當年手種滿河陽，人樹而今各老蒼。',32,'全唐诗/poet.song.200000.json','["當年手種滿河陽，人樹而今各老蒼。", "誰向棠陰遺老說，潘郎不是舊潘郎。"]'),
('41775dae-7735-49e0-8445-6d50e838a298','余作生墳何生謙致檜十株答以六言二首  其一','劉克莊','宋','宋诗','song-poetry','','[]','高聳心抽筆直，下蟠上銳塔圓。',28,'全唐诗/poet.song.200000.json','["高聳心抽筆直，下蟠上銳塔圓。", "深入蟄龍穴處，肯傍眠牛石邊。"]'),
('6c141033-1d76-41cf-9e63-68b57ddd7972','余作生墳何生謙致檜十株答以六言二首  其二','劉克莊','宋','宋诗','song-poetry','','[]','一奴荷鍤足矣，二客穿塚誰哉。',28,'全唐诗/poet.song.200000.json','["一奴荷鍤足矣，二客穿塚誰哉。", "宰上又添十檜，庭前不必三槐。"]'),
('4c25bb70-a4a0-42b0-9b6e-3d1e62a93836','題崔白訪戴圖','劉克莊','宋','宋诗','song-poetry','','[]','好事過子雲，謫仙訪賀老。',120,'全唐诗/poet.song.200000.json','["好事過子雲，謫仙訪賀老。", "載醪談文字，其樂侔擊考。", "子猷稍崖異，入剡殊草草。", "船頭一籧篨，船尾一村僚。", "飛揚滕巽怒，飄瞥林岫縞。", "何曾携爨具，清景自可飽。", "溪邊處士廬，雪深無人掃。", "肯來斯已奇，倏去良亦好。", "游子有饑色，主人省行攪。", "異世覺繪事，拊掌爲絕倒。"]'),
('78c529b8-13e2-482f-b796-7d5a3ad9c0fc','題賺蘭亭圖','劉克莊','宋','宋诗','song-poetry','','[]','山陰繭紙見者希，辨才傳之於永師。',208,'全唐诗/poet.song.200000.json','["山陰繭紙見者希，辨才傳之於永師。", "行年八十手不釋，棲之梁上鬼莫窺。", "虬鬚天子欲得之，威以禍福僧詭辭。", "智勇至此無所施，相國房公乃設奇。", "東臺御史奉詔馳，易服變姓謁老緇。", "止客置醴因聯詩，評書訂畫猶塤箎。", "稍稍益狎不見疑，卷而懷之若拾遺。", "須臾□都得臺移，都督傳詔來龍墀。", "僧絕復蘇成白癡，始悟學究即繡衣。", "文皇如堯房如夔，磊磊落落兩曜垂。", "譎取一帖安肯爲，帖歸天上神護持。", "搨本之價猶不貲，他日昭陵以自隨。", "溫韜掘者果是非，世人空寶定武碑。"]'),
('16ae1899-61e1-44e1-91e7-56b7ef250319','溪庵種蓻六言八首  其一','劉克莊','宋','宋诗','song-poetry','','[]','且與古梅爲友，未論茯苓可仙。',28,'全唐诗/poet.song.200000.json','["且與古梅爲友，未論茯苓可仙。", "一寸靈根蟠地，十年黛色參天。"]'),
('cbcaa189-c224-4a57-bdfc-0e6f216f95ce','溪庵種蓻六言八首  其二','劉克莊','宋','宋诗','song-poetry','','[]','卿輩敗人清思，此君有歲寒心。',28,'全唐诗/poet.song.200000.json','["卿輩敗人清思，此君有歲寒心。", "寧許子猷借宅，莫放阿戎入林。"]'),
('fa52f532-fe1a-4a72-945f-349acbd2a3f3','溪庵種蓻六言八首  其三','劉克莊','宋','宋诗','song-poetry','','[]','悟漆園自伐語，愛淮南招隠章。',28,'全唐诗/poet.song.200000.json','["悟漆園自伐語，愛淮南招隠章。", "臭與流芳孰愈，老而彌辣何妨。"]'),
('a20eb2eb-58a3-4c81-af03-6f96d94ae115','溪庵種蓻六言八首  其四','劉克莊','宋','宋诗','song-poetry','','[]','此翁見事常遲，八秩尚移荔枝。',28,'全唐诗/poet.song.200000.json','["此翁見事常遲，八秩尚移荔枝。", "何曾無戴白老，會須有擘紅時。"]'),
('154e6794-3c70-4def-a93c-c6712063015e','溪庵種蓻六言八首  其五','劉克莊','宋','宋诗','song-poetry','','[]','功名胡蝶夢裏，心力橐駝傳中。',28,'全唐诗/poet.song.200000.json','["功名胡蝶夢裏，心力橐駝傳中。", "環合千林蒼翠，參差數株白紅。"]'),
('63c077ae-38e5-4d2e-ac72-5f47ac613ee6','溪庵種蓻六言八首  其六','劉克莊','宋','宋诗','song-poetry','','[]','閬苑花神妬艷，晏家園吏偷春。',28,'全唐诗/poet.song.200000.json','["閬苑花神妬艷，晏家園吏偷春。", "當時傳一二本，今日化千億身。"]'),
('e8ec7137-368c-488c-98cd-63ef3a014ec3','溪庵種蓻六言八首  其七','劉克莊','宋','宋诗','song-poetry','','[]','蟠踞祠前得地，生長石間棄才。',28,'全唐诗/poet.song.200000.json','["蟠踞祠前得地，生長石間棄才。", "子美咏歌不足，之罘苦招未來。"]'),
('e2632681-728e-47fa-915d-3edded95506b','溪庵種蓻六言八首  其八','劉克莊','宋','宋诗','song-poetry','','[]','杜曲有攢眉老，漢庭無友辱人。',28,'全唐诗/poet.song.200000.json','["杜曲有攢眉老，漢庭無友辱人。", "但看靈妃啟齒，不煩里女傚顰。"]'),
('10b7de24-e456-44ac-bd14-2cd3266c303d','竹溪惠白鷼三絕  其一','劉克莊','宋','宋诗','song-poetry','','[]','白雪通身潔，丹砂傅頂紅。',24,'全唐诗/poet.song.200000.json','["白雪通身潔，丹砂傅頂紅。", "贈余有深意，誌義與閑通。"]'),
('92542fec-50bd-41d4-81c5-9d80de15a2c1','竹溪惠白鷼三絕  其二','劉克莊','宋','宋诗','song-poetry','','[]','鸚鵡鷦鷯賦，鷼寧愧二蟲。',24,'全唐诗/poet.song.200000.json','["鸚鵡鷦鷯賦，鷼寧愧二蟲。", "吾衰邊幅窘，姑置小池中。"]'),
('1e74db74-bfa0-483c-940d-7ca63092bbab','竹溪惠白鷼三絕  其三','劉克莊','宋','宋诗','song-poetry','','[]','世有殊尤物，天慳賦詠才。',24,'全唐诗/poet.song.200000.json','["世有殊尤物，天慳賦詠才。", "恨渠生較晚，不及見鄒枚。"]'),
('e058eef6-2462-4ba8-b5a7-eb52adcffd17','挽宋泉倅','劉克莊','宋','宋诗','song-poetry','','[]','連牆終歲少相過，時聽書聲警睡魔。',64,'全唐诗/poet.song.200000.json','["連牆終歲少相過，時聽書聲警睡魔。", "懶續膠絃歡意薄，雖分風月皺眉多。", "廉如玉雪誰知者，仕止牙緋奈命何。", "昨送華軒今哭墓，傷心相挽不成歌。"]'),
('4927f527-7ef9-4af6-b7b9-14b406ab6bf0','種蓮一首','劉克莊','宋','宋诗','song-poetry','','[]','姝麗如同産，朱鉛各異施。',24,'全唐诗/poet.song.200000.json','["姝麗如同産，朱鉛各異施。", "吾方參素女，渠自比□□。"]'),
('ae04587d-fcf3-4f35-9bcf-df44106cb1cd','志仁監簿示五言十五韻夸徐潭之勝次韻一首','劉克莊','宋','宋诗','song-poetry','','[]','嵐翠屏環墅，溪光練抹坤。',180,'全唐诗/poet.song.200000.json','["嵐翠屏環墅，溪光練抹坤。", "尚書華棟改，先輩釣磯存。", "久卧漳濱疾，誰招楚澤魂。", "昔慙葵衛足，今喜葉歸根。", "自誌臺卿墓，休爭謝傅墩。", "牧慵貪草暖，鳥急怕林昏。", "時許樵分席，何煩客掃門。", "早嫌皮袋臭，晚悟髑髏尊。", "童子便高枕，偷兒瞰短垣。", "歲寒始知柏，劫火不焚璠。", "恩未忘簪履，衰難戀廐軒。", "抽身脫膠擾，掩耳避啾喧。", "聯句那無藉，藏書幸有繁。", "故交頻煖熱，新貴斷寒暄。", "籬落多疎闕，猶須折柳樊。"]'),
('dcb69f39-2066-4a9e-b067-b85717210c7c','和鄉守朱監丞勸駕一首','劉克莊','宋','宋诗','song-poetry','','[]','龔陳盛事記當年，重見奎星聚舊躔。',64,'全唐诗/poet.song.200000.json','["龔陳盛事記當年，重見奎星聚舊躔。", "瑞日賦工豈迷色，慶雲詩妙似非烟。", "馳千里足相期遠，占百花頭孰敢先。", "老子扶衰看晝錦，瓊林春好莫留連。"]'),
('4d3f6a47-62b0-4120-902e-127db4edeeb4','送德甫姪省試','劉克莊','宋','宋诗','song-poetry','','[]','絕出雕蟲輩，相期竹馬年。',48,'全唐诗/poet.song.200000.json','["絕出雕蟲輩，相期竹馬年。", "二魁家有樣，四世里興賢。", "雪鬢吾還笏，霜蹄汝著鞭。", "微痾真換骨，骨換不難仙。"]'),
('e6321031-c8da-4f49-b6d1-2151c75ce16c','餞鄉守宋監丞二首  其一','劉克莊','宋','宋诗','song-poetry','','[]','束起蒲鞭教令清，郡人未識疾呼聲。',64,'全唐诗/poet.song.200000.json','["束起蒲鞭教令清，郡人未識疾呼聲。", "甌閩莫不興於學，虞芮忘其所以爭。", "父老見棠思舊愛，兒童騎竹若初迎。", "何須更說郎官省，小却猶當拜水衡。"]'),
('1779968f-0112-4efd-89e0-911eaa96343e','餞鄉守宋監丞二首  其二','劉克莊','宋','宋诗','song-poetry','','[]','牛屋漁磯在履封，晚將身世託春風。',64,'全唐诗/poet.song.200000.json','["牛屋漁磯在履封，晚將身世託春風。", "荒原拾穗誰憐我，小隊尋花屢屈公。", "耄有鬚眉如蓋老，衰無歌誦美文翁。", "明時各遂飛潜性，去矣鞭鸞碧落中。"]'),
('56219136-60e9-4c36-b7f1-1678d6fe0153','贈音上人','劉克莊','宋','宋诗','song-poetry','','[]','脫白披緇迹涉奇，傍人能說舉幡時。',64,'全唐诗/poet.song.200000.json','["脫白披緇迹涉奇，傍人能說舉幡時。", "禪家合掌來參請，烏寺摇頭不住持。", "喜捨未逢大檀越，實封輸與小沙彌。", "是凡是聖都休問，且爲渠看一袖詩。"]'),
('c3d27d45-d05e-4e42-8566-2aec5b5b82ba','贈王月軒用意一韻','劉克莊','宋','宋诗','song-poetry','','[]','江湖少菰米，京洛足風塵。',48,'全唐诗/poet.song.200000.json','["江湖少菰米，京洛足風塵。", "生命主窮鬼，贈詩多貴人。", "芒鞋雙堠遠，斗糴一家貧。", "吾力輕於羽，安能舉百鈞。"]'),
('0a8ccfc4-0a59-493e-8650-454c0aca7927','己未元日','劉克莊','宋','宋诗','song-poetry','','[]','久向優場脫戲衫，亦無布袋杖頭擔。',64,'全唐诗/poet.song.200000.json','["久向優場脫戲衫，亦無布袋杖頭擔。", "化彌勒身千百億，問絳人年七十三。", "諸老蕭疎留後殿，高僧滅度少同參。", "未應春事全無分，醉折緗桃蒲帽簪。"]'),
('2a4ba7f3-d235-49b7-9e18-3ddb3bf56a4f','淮捷一首','劉克莊','宋','宋诗','song-poetry','','[]','掃地南來蜂出窠，裔夷謀夏欲如何。',64,'全唐诗/poet.song.200000.json','["掃地南來蜂出窠，裔夷謀夏欲如何。", "傳聞撻覽斃一矢，驚走單于騎六騾。", "匹馬隻輪番部曲，寸天尺地漢山河。", "晉公幕府多名士，不欠寒儒作凱歌。"]'),
('00ddc288-136b-4d8b-9191-cf40d6a4b8ed','凱歌十首呈賈樞使  其一','劉克莊','宋','宋诗','song-poetry','','[]','孔明籌筆即天威，謝傅圍棋亦事機。',32,'全唐诗/poet.song.200000.json','["孔明籌筆即天威，謝傅圍棋亦事機。", "武騎散群望洋退，佛貍忍渴飲溲歸。"]'),
('3c125305-d5a8-460b-b5a4-be835ec9b1ed','凱歌十首呈賈樞使  其二','劉克莊','宋','宋诗','song-poetry','','[]','翦稱名將豈其然，汲汲惟求宅與田。',32,'全唐诗/poet.song.200000.json','["翦稱名將豈其然，汲汲惟求宅與田。", "見說淮兵殊死戰，相公喝犒是私錢。"]'),
('5d5f6b4c-bfbf-44bd-8877-2735a243d574','凱歌十首呈賈樞使  其三','劉克莊','宋','宋诗','song-poetry','','[]','活俘萬戶虜無酋，拔寨宵奔黑祲收。',32,'全唐诗/poet.song.200000.json','["活俘萬戶虜無酋，拔寨宵奔黑祲收。", "不用偏師追出塞，殺胡林只在揚州。"]'),
('c16c61c9-96a7-4d43-a59d-d9f6bb9d95d1','凱歌十首呈賈樞使  其四','劉克莊','宋','宋诗','song-poetry','','[]','東南立國惟王謝，西北籌邊只范韓。',32,'全唐诗/poet.song.200000.json','["東南立國惟王謝，西北籌邊只范韓。", "公不衮衣假黄鉞，吾能右衽更巍冠。"]'),
('e3077457-4daf-4c53-bc1a-9ab3cb0c6323','凱歌十首呈賈樞使  其五','劉克莊','宋','宋诗','song-poetry','','[]','君親一念與天通，麾下人人可即戎。',32,'全唐诗/poet.song.200000.json','["君親一念與天通，麾下人人可即戎。", "豈敢全軀顧妻子，相公將母在軍中。"]'),
('c68efdf8-7b29-4896-ab52-311d6ea01ad7','凱歌十首呈賈樞使  其六','劉克莊','宋','宋诗','song-poetry','','[]','將謂長淮已蕩平，豈知什塹又顛坑。',32,'全唐诗/poet.song.200000.json','["將謂長淮已蕩平，豈知什塹又顛坑。", "從今莫近他城子，怕有南人夜斫營。"]'),
('90ef523c-fe1f-4c91-9b31-97cc58ce033a','凱歌十首呈賈樞使  其七','劉克莊','宋','宋诗','song-poetry','','[]','清野都無寸草留，暴師塞下欲何求。',32,'全唐诗/poet.song.200000.json','["清野都無寸草留，暴師塞下欲何求。", "東風借便天亡敵，春水方生早去休。"]'),
('ce7d232d-cfb9-4354-b82f-5bbb0e6f0a28','凱歌十首呈賈樞使  其八','劉克莊','宋','宋诗','song-poetry','','[]','羽檄聯翩趣募兵，單槍一劍覓功名。',32,'全唐诗/poet.song.200000.json','["羽檄聯翩趣募兵，單槍一劍覓功名。", "健兒爭欲趨淮閫，宣相相看若父兄。"]'),
('039ab1c2-0947-434b-b8aa-674905a56cfe','凱歌十首呈賈樞使  其九','劉克莊','宋','宋诗','song-poetry','','[]','殘黨分兵盡撲除，遊魂多不返穹廬。',32,'全唐诗/poet.song.200000.json','["殘黨分兵盡撲除，遊魂多不返穹廬。", "肅清執至龍顔喜，又奏淮西有捷書。"]'),
('5783f039-42ac-4069-b40e-d715389fc60c','凱歌十首呈賈樞使  其一○','劉克莊','宋','宋诗','song-poetry','','[]','自古勳名勒鼎彝，老於文學即今誰。',32,'全唐诗/poet.song.200000.json','["自古勳名勒鼎彝，老於文學即今誰。", "腐儒尚可軍馬司，試作平淮第二碑。"]'),
('b45dbef7-593b-42f2-a2da-f2145090c958','飲良翁宮教新第二首  其一','劉克莊','宋','宋诗','song-poetry','','[]','拂袖歸來計未疎，別規爽塏卜新居。',64,'全唐诗/poet.song.200000.json','["拂袖歸來計未疎，別規爽塏卜新居。", "即今獨擅百弓地，當日惟携一束書。", "戶外何須置行馬，坐中不必盡懸魚。", "渠亦若與人家國，輸與興公賦遂初。"]'),
('7ac31078-f2f2-48a0-9072-027901d69976','飲良翁宮教新第二首  其二','劉克莊','宋','宋诗','song-poetry','','[]','負郭依山遠市廛，高宜臺榭下宜田。',64,'全唐诗/poet.song.200000.json','["負郭依山遠市廛，高宜臺榭下宜田。", "徑當膏抹從盤谷，似向丹青見輞川。", "別墅暮年□□□，□□□□□南遷。", "與君幸已抽身了，共結黄雞白酒緣。"]'),
('203573fe-33f9-4ef0-88fa-1da57533dc43','次韻二首  其一','劉克莊','宋','宋诗','song-poetry','','[]','老懶尤於筆硯疎，難陪騎省賦閑居。',64,'全唐诗/poet.song.200000.json','["老懶尤於筆硯疎，難陪騎省賦閑居。", "去周柱下誰爲史，傳鄴侯家尚有書。", "臺饋不煩公粟肉，戶租難辦客車魚。", "側旁萬一鄰堪買，便擬誅茅近太初。"]'),
('59aadcde-f030-445e-8fc4-76f8c3afcc97','次韻二首  其二','劉克莊','宋','宋诗','song-poetry','','[]','半生竊祿取禾廛，晚節休官失秫田。',64,'全唐诗/poet.song.200000.json','["半生竊祿取禾廛，晚節休官失秫田。", "伴陸先生遊甫里，同陶徵士訪斜川。", "鳳池信美其如奪，鶑谷雖幽不願遷。", "自笑劉牆如許短，謫仙壇未易扳緣。"]'),
('999413a8-4b2c-4974-9b58-2b0ccec7a30e','翌日宮教惠詩次韻二首  其一','劉克莊','宋','宋诗','song-poetry','','[]','忘機漚鳥日相親，鼻祖曾言畏四鄰。',64,'全唐诗/poet.song.200000.json','["忘機漚鳥日相親，鼻祖曾言畏四鄰。", "幸有山林容此老，不將籬落寄他人。", "誰能交結今韓呂，猶記周旋昔鄭陳。", "晞髮中庭蹻足卧，絕勝雅拜望車塵。"]'),
('e08e4ea0-491b-4650-be65-3b83e30629cd','翌日宮教惠詩次韻二首  其二','劉克莊','宋','宋诗','song-poetry','','[]','即令身在水雲間，不著斯人玉筍班。',64,'全唐诗/poet.song.200000.json','["即令身在水雲間，不著斯人玉筍班。", "子美步歸猶戀闕，浩然肩聳徑還山。", "人情薄似平原酒，世路危於灧澦灘。", "華棟把茅皆幻假，祝君黄髮映朱顔。"]'),
('dbf0d2e0-e229-426d-8a29-52e42d5ab81a','次韻二首  其一','劉克莊','宋','宋诗','song-poetry','','[]','阮生未老各情親，誰道先生不覿鄰。',64,'全唐诗/poet.song.200000.json','["阮生未老各情親，誰道先生不覿鄰。", "莫管彈丸驚鴨者，豈無沽酒與魚人。", "何曾膝上推文度，亦許車中載小陳。", "賜第京師即山鑄，得如跳出軟紅塵。"]'),
('49369b59-d438-467c-b557-30b1ef4bcf2c','次韻二首  其二','劉克莊','宋','宋诗','song-poetry','','[]','投老參陪杖屨間，頗容摘宋更薰班。',64,'全唐诗/poet.song.200000.json','["投老參陪杖屨間，頗容摘宋更薰班。", "端能面我九年壁，不惜分君一半山。", "絕喜庚桑來畏壘，懶爲涑水續君灘。", "夷居巷處何嘗陋，但看當年孔與顔。"]'),
('ac96c3d9-a268-4ec9-8a57-882b591cf3d7','題聽蛙方君寫生六言','劉克莊','宋','宋诗','song-poetry','','[]','少濟南生十歲，與磻溪叟同庚。',28,'全唐诗/poet.song.200000.json','["少濟南生十歲，與磻溪叟同庚。", "陳巖方氏耆雋，後村老子師兄。"]'),
('c98abae7-2373-46d7-9776-1a47f2aee81e','小飲','劉克莊','宋','宋诗','song-poetry','','[]','暮年衰老讀書慵，惟有杯中興尚濃。',64,'全唐诗/poet.song.200000.json','["暮年衰老讀書慵，惟有杯中興尚濃。", "枕麴惰人真遠祖，看花跛子亦同宗。", "鮆魚蝦䱹何虧汝，螺蠃螟蛉妄議儂。", "帝賜醉鄉爲食邑，此生不必更移封。"]'),
('74ec86cd-0636-40c3-ab30-2f51918a09ab','試筆六言二首  其一','劉克莊','宋','宋诗','song-poetry','','[]','病鶴尚能孤唳，凍螢相守殘編。',28,'全唐诗/poet.song.200000.json','["病鶴尚能孤唳，凍螢相守殘編。", "世間有豁達老，天上無愚戇仙。"]'),
('21a556b5-575a-4591-9746-01c93008a2b6','試筆六言二首  其二','劉克莊','宋','宋诗','song-poetry','','[]','薰玉蕤香解穢，挽銀河水滌塵。',28,'全唐诗/poet.song.200000.json','["薰玉蕤香解穢，挽銀河水滌塵。", "雖非補造化筆，不似食烟火人。"]'),
('a8b699e0-9b38-4576-b817-b4da73f8f0ca','即事一首','劉克莊','宋','宋诗','song-poetry','','[]','過了田光盛壯時，年今望八復奚爲。',64,'全唐诗/poet.song.200000.json','["過了田光盛壯時，年今望八復奚爲。", "薄澆磊磈嫌紅酒，懶讀聱牙喜白詩。", "釋子書求名卵塔，社人卜請記叢祠。", "吾文誰道難施用，後有中郎賞斷碑。"]'),
('12e74181-da1c-475f-bd4f-b763462cdd7e','田舍二首  其一','劉克莊','宋','宋诗','song-poetry','','[]','雨逗餘寒曉露濃，絮衣著破索重縫。',64,'全唐诗/poet.song.200000.json','["雨逗餘寒曉露濃，絮衣著破索重縫。", "清狂昔作戴花監，衰病今爲賣菜傭。", "負耒耦耕沮桀溺，操盂三祝棄句龍。", "暮年飽識西疇事，不問家丘問老農。"]'),
('8de5def0-9f93-44f3-9e8a-69534136f752','田舍二首  其二','劉克莊','宋','宋诗','song-poetry','','[]','白布衫寬烏角巾，誰知曾扈屬車塵。',64,'全唐诗/poet.song.200000.json','["白布衫寬烏角巾，誰知曾扈屬車塵。", "行婆內翰共鄰曲，田父拾遺相主賓。", "設苜蓿盤殊菲薄，沽茅柴酒半漓淳。", "直令爵齒如荀爽，晚節依然愧逸民。"]'),
('df8c7613-e442-42c7-bb42-003288b9c7f7','挽林法曹實甫二首  其一','劉克莊','宋','宋诗','song-poetry','','[]','老學多推誼，諸公孰薦雄。',48,'全唐诗/poet.song.200000.json','["老學多推誼，諸公孰薦雄。", "却行吾日暮，渴睡汝冬烘。", "宰木經春雨，園花逐曉風。", "寢門哀未盡，寓在薤歌中。"]'),
('e238090c-c53d-4924-8c4a-1a3b6ca50a2d','挽林法曹實甫二首  其二','劉克莊','宋','宋诗','song-poetry','','[]','昔我叨馳馹，惟君伴聚螢。',48,'全唐诗/poet.song.200000.json','["昔我叨馳馹，惟君伴聚螢。", "病翁尚佔畢，良友忽幽冥。", "古有東方贊，今無貞曜銘。", "不知吟幾些，叫得屈原醒。"]'),
('47409c3e-f31d-4b29-9ee2-1b61430da94e','翀甫姪西上','劉克莊','宋','宋诗','song-poetry','','[]','同向溪邊卜一丘，獨憐出處不同謀。',64,'全唐诗/poet.song.200000.json','["同向溪邊卜一丘，獨憐出處不同謀。", "吾今老矣佚吾老，子好遊乎與子遊。", "漫對芝蘭懷幼度，可教白馬笑之罘。", "人生無過家山好，京洛風塵莫久留。"]'),
('ad3bb8d6-71fc-4b40-8a46-cdb942a4958d','答林逮贄卷因以送行','劉克莊','宋','宋诗','song-poetry','','[]','都忘几桉有華牋，但怪虹光夜屬天。',64,'全唐诗/poet.song.200000.json','["都忘几桉有華牋，但怪虹光夜屬天。", "唐律胚胎梨嶺作，古文骨髓艾軒傳。", "蚤陳董大夫三策，肯覓原夫輩一聯。", "若過溪邊叩宗旨，爲余問訊玉堂仙。"]'),
('c24b1f80-0620-49c3-8e23-294b5729d110','寄題竹溪平遠軒','劉克莊','宋','宋诗','song-poetry','','[]','顛米含毫野處名，略安欄檻不施扃。',64,'全唐诗/poet.song.200000.json','["顛米含毫野處名，略安欄檻不施扃。", "原田足雨陂塘白，天海無雲島嶼青。", "鄰叟扶犂耕斥鹵，行人休樹濯清泠。", "何時去作軒中客，併欲傳公道德經。"]'),
('c4b1986a-33f1-470a-a5c6-6f96c8996996','司令爲牡丹集次坐客韻','劉克莊','宋','宋诗','song-poetry','','[]','古人曾道四并難，酒量黄花頓覺寬。',64,'全唐诗/poet.song.200000.json','["古人曾道四并難，酒量黄花頓覺寬。", "誰與蔡歐脩舊譜，且爲姚魏煖春寒。", "飲狂尚欲簪巾舞，漏盡何妨秉燭看。", "國色老顔不相稱，世間何處有還丹。"]'),
('ff3b26ef-1945-4171-8841-3252cc15ea43','挽李法曹一鳳內子','劉克莊','宋','宋诗','song-poetry','','[]','□□藁砧死，先疇自墾耕。',48,'全唐诗/poet.song.200000.json','["□□藁砧死，先疇自墾耕。", "雙飛鸞影拆，獨力燕巢成。", "教子鄹人母，持家寡婦清。", "今無彤史筆，猶幸有鄉評。"]'),
('1992beaa-212e-4c7c-8c6a-7fde0c485845','東澗爲余序後稿余以國帖唐碑古壺潤筆反成□桃拋引小詩謝之','劉克莊','宋','宋诗','song-poetry','','[]','玄晏欣然託序行，縕袍被衮豈非榮。',64,'全唐诗/poet.song.200000.json','["玄晏欣然託序行，縕袍被衮豈非榮。", "家徒四壁窮難諱，字答三縑禮尚輕。", "金薤銀鈎俱妙絕，石泉香餠太清生。", "如何更費公搜索，緘送松煤與水晶。"]'),
('5e16a3d4-d3ba-4980-b4aa-7b9412fe9bac','次韻竹溪一首','劉克莊','宋','宋诗','song-poetry','','[]','藏山覆瓿兩相癡，辛苦纔供世俗嗤。',64,'全唐诗/poet.song.200000.json','["藏山覆瓿兩相癡，辛苦纔供世俗嗤。", "壯不如人徒自悔，老能學易未過時。", "懶猶堪草歸田賦，鈍豈能吟對御詩。", "惟有聃書宜北面，存元守黑畏人知。"]'),
('86b9812a-80ec-46c0-9cf9-e7d4d295395a','諸家牡丹已謝小圃忽開兩朵皆大如斗戲題二絕  其一','劉克莊','宋','宋诗','song-poetry','','[]','地荒豈有雕欄護，日烈元無繡幕遮。',32,'全唐诗/poet.song.200000.json','["地荒豈有雕欄護，日烈元無繡幕遮。", "九十種俱開謝了，末稍開到後村花。"]'),
('44e08882-c327-4f49-9877-36f24c2a5779','諸家牡丹已謝小圃忽開兩朵皆大如斗戲題二絕  其二','劉克莊','宋','宋诗','song-poetry','','[]','踏青人被色香迷，擊壤翁看蓓蕾知。',32,'全唐诗/poet.song.200000.json','["踏青人被色香迷，擊壤翁看蓓蕾知。", "漏籍譜中無可恨，花開殿後未爲遲。"]'),
('7b1e24a8-bcff-4d0d-b7be-8ef0b0762f34','記牡丹事二首  其一','劉克莊','宋','宋诗','song-poetry','','[]','暴骸獨柳冤誰雪，藁葬青山過者悲。',32,'全唐诗/poet.song.200000.json','["暴骸獨柳冤誰雪，藁葬青山過者悲。", "甘露殿中空誦賦，沉香亭畔更無詩。"]'),
('8a82473f-80d0-4b5e-bd93-b3b8ba3d3c52','記牡丹事二首  其二','劉克莊','宋','宋诗','song-poetry','','[]','西洛名園墮劫灰，揚州風物更堪哀。',32,'全唐诗/poet.song.200000.json','["西洛名園墮劫灰，揚州風物更堪哀。", "縱携買笑千金去，難喚能行一朵來。"]'),
('e0b74bb4-f3ce-40ce-8bb7-e5080e12e6fa','送勳姪銓試','劉克莊','宋','宋诗','song-poetry','','[]','十日陰霾潦未乾，可堪送汝上征鞍。',64,'全唐诗/poet.song.200000.json','["十日陰霾潦未乾，可堪送汝上征鞍。", "店荒待米晨炊晏，橋毀呼船野渡難。", "尚喜山公銓綜允，莫愁冰氏戶門寒。", "筆耕無準先疇薄，且著青衫揖上官。"]'),
('4a4109d7-5ba8-4665-83c0-bad68a0cc499','送方添倅','劉克莊','宋','宋诗','song-poetry','','[]','忠惠橫經地，今將五十秋。',48,'全唐诗/poet.song.200000.json','["忠惠橫經地，今將五十秋。", "諸生迎謁廟，吾子往監州。", "吏散齋堂靜，朋來鄭校修。", "勿嫌員外置，風月滿鴻溝。"]'),
('539f7bd5-b6d4-4487-ac9a-45e7218e5f51','即事二首  其一','劉克莊','宋','宋诗','song-poetry','','[]','厨人失職晏忘炊，頼是先生貫忍饑。',64,'全唐诗/poet.song.200000.json','["厨人失職晏忘炊，頼是先生貫忍饑。", "一客覆羹真小事，舉家食粥已多時。", "自憐氣餒鮮難膾，漸覺身輕鶴可騎。", "屈指故交無厚祿，未知太保李公誰。"]'),
('cd93f897-c494-487c-8e86-fff26b34c4bd','即事二首  其二','劉克莊','宋','宋诗','song-poetry','','[]','厨荒竈鬼未須嗔，君看先師尚在陳。',64,'全唐诗/poet.song.200000.json','["厨荒竈鬼未須嗔，君看先師尚在陳。", "老退休貪太倉腐，清虛聊嚥上池津。", "今無能采金膏者，古有曾逢石髓人。", "自笑冰衡三百戶，難分圭撮餉比鄰。"]'),
('98aa7d97-42e8-420a-a492-3d9ae1bfc5c6','六言五首爲倉部弟壽  其一','劉克莊','宋','宋诗','song-poetry','','[]','映青藜燈娛目，吸金莖露入脾。',28,'全唐诗/poet.song.200000.json','["映青藜燈娛目，吸金莖露入脾。", "寧作履霜逐子，肯隨向火乞兒。"]'),
('a5f1d6ed-ece5-4715-a5cb-84b3ddd9a489','六言五首爲倉部弟壽  其二','劉克莊','宋','宋诗','song-poetry','','[]','幼道一生第五，文淵萬里建侯。',28,'全唐诗/poet.song.200000.json','["幼道一生第五，文淵萬里建侯。", "假令加驃騎號，何如騎款段游。"]'),
('421aff10-58d6-4188-b84e-8bf891f91414','六言五首爲倉部弟壽  其三','劉克莊','宋','宋诗','song-poetry','','[]','天既勞我佚我，侯偶得之失之。',28,'全唐诗/poet.song.200000.json','["天既勞我佚我，侯偶得之失之。", "安用爾銅魚使，且伴吾竹馬嬉。"]'),
('6609ee8f-4b0c-473b-913f-7090a72eace3','六言五首爲倉部弟壽  其四','劉克莊','宋','宋诗','song-poetry','','[]','薄田足可躬稼，餘俸尚堪買山。',28,'全唐诗/poet.song.200000.json','["薄田足可躬稼，餘俸尚堪買山。", "家庭有箇郊畤，姬院欠他素蠻。"]'),
('a2e9b133-cc06-4629-b884-5623c1eb97fc','六言五首爲倉部弟壽  其五','劉克莊','宋','宋诗','song-poetry','','[]','丹田舊種梨棗，冰柈新摘荔蕉。',28,'全唐诗/poet.song.200000.json','["丹田舊種梨棗，冰柈新摘荔蕉。", "年年此夜待月，年年此日迎潮。"]'),
('b371660d-4c49-405b-9153-7fd9ef0c56c5','荔厄一首','劉克莊','宋','宋诗','song-poetry','','[]','怒潦浮槎去，狂飆拔木飛。',48,'全唐诗/poet.song.200000.json','["怒潦浮槎去，狂飆拔木飛。", "不饒後村荔，如奪首陽薇。", "任土包茅闕，過時碩果稀。", "誰言長卿渴，且嚥上池肥。"]'),
('d4a46723-33b4-4bcb-911d-cab1fbcfe1b1','以宋香方紅送聽蛙翁答柬云兩年來啖荔顆則動氣按本草等書云荔枝能蠲渴補髓未聞其動氣也口占一首發翁一笑','劉克莊','宋','宋诗','song-poetry','','[]','奩封名品餉耆年，誼比□芹曝背然。',64,'全唐诗/poet.song.200000.json','["奩封名品餉耆年，誼比□芹曝背然。", "帖報能生采薪疾，譜言曾有荔枝仙。", "朵頤笑我脾神餒，節腹知君氣□全。", "來歲郎官香爛熟，定分千顆沃饞涎。"]'),
('a1013e81-e366-49e0-b988-402849bce80d','挽方倅景楫二首  其一','劉克莊','宋','宋诗','song-poetry','','[]','上世曾通好，君尊昔托孤。',48,'全唐诗/poet.song.200000.json','["上世曾通好，君尊昔托孤。", "初聞携一束，俄見賦三都。", "皆謂終童雋，安知董相迂。", "禿翁老無力，愛助尚區區。"]'),
('c7a60d0f-19a6-44ec-b79f-90bbca724d05','挽方倅景楫二首  其二','劉克莊','宋','宋诗','song-poetry','','[]','屢薦於諸老，斯人可在廷。',48,'全唐诗/poet.song.200000.json','["屢薦於諸老，斯人可在廷。", "不令客翹館，僅使直都廳。", "史漫存融表，墳猶待愈銘。", "西風已蕭瑟，哀鐸更堪聽。"]'),
('5b25f444-f22d-44a0-acf3-6b16247688ba','仲晦監簿和放翁七十三吟三篇華予初度走筆□韻答之  其一','劉克莊','宋','宋诗','song-poetry','','[]','鏡中雪鬢數莖新，歸作田間負耒民。',64,'全唐诗/poet.song.200000.json','["鏡中雪鬢數莖新，歸作田間負耒民。", "仕五十年難諱老，封三百戶敢嫌貧。", "諸無物實師龐藴，萬苦非真試子春。", "到得邢楊遭勘辨，始知鐵漢是全人。"]'),
('70aae48f-b05e-4793-bbe7-697ff0bba654','仲晦監簿和放翁七十三吟三篇華予初度走筆□韻答之  其二','劉克莊','宋','宋诗','song-poetry','','[]','諸公衮衮幾番新，留得淳熙一老民。',64,'全唐诗/poet.song.200000.json','["諸公衮衮幾番新，留得淳熙一老民。", "就枕驚回鷄攪睡，委巢飛去燕欺貧。", "貪生尚惜桑榆景，排悶全憑麯米春。", "頼有平生金石友，年年歲歲記陳人。"]'),
('59aff5a0-dfaf-474c-ba43-a2cc02cb5402','仲晦監簿和放翁七十三吟三篇華予初度走筆□韻答之  其三','劉克莊','宋','宋诗','song-poetry','','[]','□□下飾墨尤新，以史名官不治民。',64,'全唐诗/poet.song.200000.json','["□□下飾墨尤新，以史名官不治民。", "後死漫爲諸老殿，粗完深愧兩翁貧。", "譬牛山木全高壽，讓馬堘花鬭早春。", "兀坐空齋形對影，載醪裹飯更無人。"]'),
('d2174d08-2390-411e-a841-382bca54c9e1','送强甫赴惠安六言十首  其一','劉克莊','宋','宋诗','song-poetry','','[]','宰社如宰天下，其難舉者莫勝。',28,'全唐诗/poet.song.200000.json','["宰社如宰天下，其難舉者莫勝。", "忍事吸醋三斗，不飲彊飯二升。"]'),
('965372ab-23ad-4c06-9015-e75e60f3b4a1','送强甫赴惠安六言十首  其二','劉克莊','宋','宋诗','song-poetry','','[]','予奪平心足矣，痛癢以身體之。',28,'全唐诗/poet.song.200000.json','["予奪平心足矣，痛癢以身體之。", "薤本何須先拔，蒲鞭不可妄施。"]'),
('80365ecc-447f-474c-afd7-a166e9a69c5d','送强甫赴惠安六言十首  其三','劉克莊','宋','宋诗','song-poetry','','[]','古云若保赤子，亦曰如烹小鮮。',28,'全唐诗/poet.song.200000.json','["古云若保赤子，亦曰如烹小鮮。", "雉馴萬物遂性，犬吠一村廢眠。"]'),
('fefb3ffb-6760-457b-afee-9bcb31f963f5','送强甫赴惠安六言十首  其四','劉克莊','宋','宋诗','song-poetry','','[]','巽以行權亦可，方於事上未然。',28,'全唐诗/poet.song.200000.json','["巽以行權亦可，方於事上未然。", "或迎使者負弩，或爲刺史挽船。"]'),
('48183624-b5bd-4754-bd6d-1ba65550026a','送强甫赴惠安六言十首  其五','劉克莊','宋','宋诗','song-poetry','','[]','腦上筆不會插，心頭肉其忍剜。',28,'全唐诗/poet.song.200000.json','["腦上筆不會插，心頭肉其忍剜。", "乍可儂無花判，莫教渠有租瘢。"]'),
('c26750e6-fda3-4938-b315-ce50003922d6','送强甫赴惠安六言十首  其六','劉克莊','宋','宋诗','song-poetry','','[]','警報環四面至，急符寓一分寬。',28,'全唐诗/poet.song.200000.json','["警報環四面至，急符寓一分寬。", "吾兒行矣無怨，太守似元次山。"]'),
('312070d7-40af-4cbe-b968-3d51555c38a0','送强甫赴惠安六言十首  其七','劉克莊','宋','宋诗','song-poetry','','[]','彼民若不駭輿，迺翁可就安車。',28,'全唐诗/poet.song.200000.json','["彼民若不駭輿，迺翁可就安車。", "擊鮮之力不足，啜菽之歡有餘。"]'),
('f6dd69da-67e8-43bb-9fd6-a4b1f0d0c9a7','送强甫赴惠安六言十首  其八','劉克莊','宋','宋诗','song-poetry','','[]','村叟昔嘗爲宰，溪民今未忘吾。',28,'全唐诗/poet.song.200000.json','["村叟昔嘗爲宰，溪民今未忘吾。", "汝父德薄勿效，前有子野易□。"]'),
('56e6a23e-c160-4412-97d0-0536c73c0895','送强甫赴惠安六言十首  其九','劉克莊','宋','宋诗','song-poetry','','[]','得百里地雖小，作三年計勿忙。',28,'全唐诗/poet.song.200000.json','["得百里地雖小，作三年計勿忙。", "但願彼禾稼熟，莫愁汝松菊荒。"]'),
('c535daa2-0ea9-489c-9ed4-366faafbe1f6','送强甫赴惠安六言十首  其一○','劉克莊','宋','宋诗','song-poetry','','[]','或問漢庭名卿，僅數洛陽耆英。',28,'全唐诗/poet.song.200000.json','["或問漢庭名卿，僅數洛陽耆英。", "汝見諸公執贄，各爲老子寄聲。"]'),
('999c25c9-5b34-427f-bddb-03f927510c12','別陳宗院','劉克莊','宋','宋诗','song-poetry','','[]','送客頻張酒，迎賓久倚轅。',48,'全唐诗/poet.song.200000.json','["送客頻張酒，迎賓久倚轅。", "何曾薄西邸，不忍□□□。", "宦拙從渠巧，甥榮覺舅尊。", "福唐遺父老，應看□□□。"]'),
('34db8e41-244e-442d-9b68-d20d6fa14179','憶昔二首  其一','劉克莊','宋','宋诗','song-poetry','','[]','憶惜金鞭觀玉臺，當年並駕盡龍騋。',64,'全唐诗/poet.song.200000.json','["憶惜金鞭觀玉臺，當年並駕盡龍騋。", "恰逢居易投詩去，又報奇章袖贄來。", "病謝交游空感舊，老無氣力尚憐才。", "孟陽殘錦都能幾，莫爲諸君更剪裁。"]'),
('07951fae-43f6-4a6e-8794-42573415cbf4','憶昔二首  其二','劉克莊','宋','宋诗','song-poetry','','[]','猶記顓蒙昔未開，自鞭寧待父師哉。',64,'全唐诗/poet.song.200000.json','["猶記顓蒙昔未開，自鞭寧待父師哉。", "殘編常到鷄聲徹，警枕頻驚蝶夢迴。", "且可徧參學童子，未應一跳至如來。", "叢林箇箇談宗旨，誰是禪家大辯才。"]'),
('f5f4bd8f-453e-4c41-b5e3-b9fefbf37b74','縱筆二首  其一','劉克莊','宋','宋诗','song-poetry','','[]','忽忽韶顔變老蒼，叵堪屋角兩輪忙。',64,'全唐诗/poet.song.200000.json','["忽忽韶顔變老蒼，叵堪屋角兩輪忙。", "羣花獨菊香尤晚，大木惟樗壽最長。", "眉有白毫垂過眼，腹無墨汁苦搜腸。", "荒村偶有優旃至，且伴兒童看戲場。"]'),
('79c7f679-04f3-416d-ab7b-07bde681c073','縱筆二首  其二','劉克莊','宋','宋诗','song-poetry','','[]','髮似秋霜身槁枝，相逢驚怪此翁誰。',64,'全唐诗/poet.song.200000.json','["髮似秋霜身槁枝，相逢驚怪此翁誰。", "能啖范丈韲鹽日，曾識荆公疥癬時。", "不待姓名尊德齒，要知戒臘□鬚眉。", "融修漢士中翹楚，商略總堪大小兒。"]'),
('b39801b6-525c-4ccc-a0de-da4786dbfadf','即事二首  其一','劉克莊','宋','宋诗','song-poetry','','[]','碧玉去隨年少易，絳桃留待主君難。',64,'全唐诗/poet.song.200000.json','["碧玉去隨年少易，絳桃留待主君難。", "喚郎豈有雲神女，觴客寧無黑牡丹。", "漢上謾爲留佩惱，湘東曾被淡粧瞞。", "維摩老病禪房冷，一點青燈伴夜闌。"]'),
('5f1950b8-4dad-43c6-af36-834ba0ae62bc','即事二首  其二','劉克莊','宋','宋诗','song-poetry','','[]','非人不暖豈其然，卷起桃笙設艾氈。',64,'全唐诗/poet.song.200000.json','["非人不暖豈其然，卷起桃笙設艾氈。", "老物可憎吾頓覺，盛時一失汝堪憐。", "有分香妓空遺臭，無散花魔莫惱禪。", "多謝小窗半規月，夜深長伴絳紗邊。"]'),
('ab84deb4-50ff-421d-a722-35ca2a1e81ea','老歡','劉克莊','宋','宋诗','song-poetry','','[]','功名幻妄炊粱枕，歲月奔忙下坂輪。',64,'全唐诗/poet.song.200000.json','["功名幻妄炊粱枕，歲月奔忙下坂輪。", "昔作時來木居士，今爲暑退竹夫人。", "白襦裙穩於歸衮，黄獨苗甘似食珍。", "老漢禿殘惟齒髮，不妨句子尚尖新。"]'),
('29843221-1fce-49a0-8ed0-b0bcde0aacff','余常用小端硯失之經年忽在常賣人手中以錢贖歸紀實二首  其一','劉克莊','宋','宋诗','song-poetry','','[]','幾年共學久相於，中道如遺忽棄予。',64,'全唐诗/poet.song.200000.json','["幾年共學久相於，中道如遺忽棄予。", "韞匵而藏機不密，竊鈎雖小法當誅。", "匹夫有罪因懷璧，象罔無心偶得珠。", "戒飭家僮嚴護守，即今鼠子巧穿窬。"]'),
('049b33ca-155b-4558-b466-5ef9058d0501','余常用小端硯失之經年忽在常賣人手中以錢贖歸紀實二首  其二','劉克莊','宋','宋诗','song-poetry','','[]','得來矻矻相親附，颺去頻頻入夢思。',64,'全唐诗/poet.song.200000.json','["得來矻矻相親附，颺去頻頻入夢思。", "盜璧相爭笞掠汝，竊弓子筆亦誅之。", "償金在我寧從厚，拜石爲兄苦好奇。", "待喚良工鎸硯背，偷兒携出有人知。"]'),
('023d620f-86aa-477d-88cd-d5d0246a8573','挽趙碩人二首  其一','劉克莊','宋','宋诗','song-poetry','','[]','華轂早于飛，深知夢幻非。',48,'全唐诗/poet.song.200000.json','["華轂早于飛，深知夢幻非。", "幽閒林下氣，澹素嫁時衣。", "客不聞轑釜，兒猶寶斷機。", "天風環珮遠，兜率是真歸。"]'),
('d73630d6-cd4d-4e3a-8f9e-b47ff66ba92d','挽趙碩人二首  其二','劉克莊','宋','宋诗','song-poetry','','[]','苦戀萊衣樂，非貪漢繡行。',48,'全唐诗/poet.song.200000.json','["苦戀萊衣樂，非貪漢繡行。", "上方優斡腹，兒未可陳情。", "風木終身恨，朝華過眼榮。", "誰言彤史廢，阡表自崢嶸。"]'),
('f4198525-552f-45ae-bb20-5024cf107bb1','送宇文倅二首  其一','劉克莊','宋','宋诗','song-poetry','','[]','昔以縣爲灘，于今倅亦難。',48,'全唐诗/poet.song.200000.json','["昔以縣爲灘，于今倅亦難。", "縱令急符下，且放大絃寬。", "航海船粳白，游山譜荔丹。", "應憐銅墨吏，舒慘在毫端。"]'),
('4fd21e5c-f4d7-4e12-b57a-3e351a01ca43','送宇文倅二首  其二','劉克莊','宋','宋诗','song-poetry','','[]','祖佐文忠幙，初新肅愍祠。',48,'全唐诗/poet.song.200000.json','["祖佐文忠幙，初新肅愍祠。", "昔曾瞻古柏，今始識孫枝。", "西鄙方頭重，南轅若背馳。", "漢朝如諭蜀，草檄舍君誰。"]'),
('726ad272-0d41-4fb4-88e0-62696b34d183','挽鄭令人二首  其一','劉克莊','宋','宋诗','song-poetry','','[]','迺翁自是里名儒，箴史遺言幼染濡。',64,'全唐诗/poet.song.200000.json','["迺翁自是里名儒，箴史遺言幼染濡。", "設饌禮如初作婦，貤封誼不忍先姑。", "色絲尤妙於前製，彤管從刪以後無。", "一事可紓存沒恨，即今丹穴有雙雛。"]'),
('b1b905fe-43c9-41fe-9254-990a044875c1','挽鄭令人二首  其二','劉克莊','宋','宋诗','song-poetry','','[]','宗伯中朝第一人，向來曾卜太初鄰。',64,'全唐诗/poet.song.200000.json','["宗伯中朝第一人，向來曾卜太初鄰。", "凝香侯有孤高趣，擁絮翁餘老病身。", "嗟汝棄予寧返顧，祝公存我勿傷神。", "瑞雲道遠西風冷，想見齋居百歲新。"]'),
('3b6d6fdc-c2fb-4f53-ad66-080a809e4fae','哭趙百微少蓬二首  其一','劉克莊','宋','宋诗','song-poetry','','[]','書筒舊歲尚諄諄，曾幾何時哭蜀珍。',64,'全唐诗/poet.song.200000.json','["書筒舊歲尚諄諄，曾幾何時哭蜀珍。", "對紫薇邊還老手，近紅雲處立長身。", "禁中視草蒙天笑，湖外埋輪觸相嗔。", "直氣雄辭俱已矣，西風懷友一沾巾。"]'),
('44749f9d-085f-4c51-a1df-a6b280f4b98d','哭趙百微少蓬二首  其二','劉克莊','宋','宋诗','song-poetry','','[]','長君尤歲輩流稀，君直西垣我北扉。',64,'全唐诗/poet.song.200000.json','["長君尤歲輩流稀，君直西垣我北扉。", "襆被本無桑下戀，聯鞍猶記柳邊歸。", "錦殘尚足邱遲用，斤妙曾看郢客揮。", "聞卜菟裘殊未定，吳中埋玉是耶非。"]'),
('6d38da1a-2ecc-4b93-929f-8ff053ef4e1a','夢與尤木石論史感舊七絕句  其一','劉克莊','宋','宋诗','song-poetry','','[]','學士朋來似堵牆，共看老筆出提綱。',32,'全唐诗/poet.song.200000.json','["學士朋來似堵牆，共看老筆出提綱。", "綉韉張蓋傳呼寵，不比倡優蓄子長。"]'),
('c79b33ed-0330-4e3a-8061-37b37822c9e9','夢與尤木石論史感舊七絕句  其二','劉克莊','宋','宋诗','song-poetry','','[]','錫山落在暮雲邊，幾載無書寄老仙。',32,'全唐诗/poet.song.200000.json','["錫山落在暮雲邊，幾載無書寄老仙。", "公藝九齡余望八，夢商史稿覺悽然。"]'),
('0150c036-2728-44f5-a01a-6f6f3dfe51ff','夢與尤木石論史感舊七絕句  其三','劉克莊','宋','宋诗','song-poetry','','[]','加璧年高公誤矣，免冠髮禿上憐之。',32,'全唐诗/poet.song.200000.json','["加璧年高公誤矣，免冠髮禿上憐之。", "懸知黄鵠飛難返，獨恨青牛去稍遲。"]'),
('57f22015-cd81-4873-b542-e59232932398','夢與尤木石論史感舊七絕句  其四','劉克莊','宋','宋诗','song-poetry','','[]','眼昏漸覺聚螢難，閑殺蘭臺舊史官。',32,'全唐诗/poet.song.200000.json','["眼昏漸覺聚螢難，閑殺蘭臺舊史官。", "縱使青藜重下照，細書如蟻不能看。"]'),
('a1a5b9c9-a996-444b-a3ac-4519921c86ad','夢與尤木石論史感舊七絕句  其五','劉克莊','宋','宋诗','song-poetry','','[]','金榜朱扉此帝居，舊游恍似夢清都。',32,'全唐诗/poet.song.200000.json','["金榜朱扉此帝居，舊游恍似夢清都。", "可憐白首充修撰，到了藏山一字無。"]'),
('b53cb3c3-1d84-42e2-9d7b-d16d38130589','夢與尤木石論史感舊七絕句  其六','劉克莊','宋','宋诗','song-poetry','','[]','徑畈山栖謝宦情，竹溪巷處閉柴荆。',32,'全唐诗/poet.song.200000.json','["徑畈山栖謝宦情，竹溪巷處閉柴荆。", "然藜曾伴劉中壘，起蕝誰招魯兩生。"]'),
('a573455c-1a40-4023-8b93-2725929c3571','夢與尤木石論史感舊七絕句  其七','劉克莊','宋','宋诗','song-poetry','','[]','久軒雖貴尚儒癯，商略斯人似蔡謨。',32,'全唐诗/poet.song.200000.json','["久軒雖貴尚儒癯，商略斯人似蔡謨。", "給札曾來爲學士，拂衣不愛作司徒。"]'),
('88c8089e-12f7-47d9-9c54-83d14a871d17','菊','劉克莊','宋','宋诗','song-poetry','','[]','性遲故故待霜天，珠蕾金苞带露鮮。',64,'全唐诗/poet.song.200000.json','["性遲故故待霜天，珠蕾金苞带露鮮。", "曾有餐之充雅操，又云飲者享高年。", "騷留楚客芳菲在，史視胡公糞土然。", "莫道先生真鼻塞，幽薌常在枕囊邊。"]'),
('9daa7afa-ce52-4cfb-808d-bfb9ad57757e','芙蓉','劉克莊','宋','宋诗','song-poetry','','[]','紛紛亭錦映池塘，艷冶姿容淡泊粧。',64,'全唐诗/poet.song.200000.json','["紛紛亭錦映池塘，艷冶姿容淡泊粧。", "醉去恍疑曾被酒，集來未必可爲裳。", "有懷絕色真如面，誰改新名作斷腸。", "只合尊前簪老監，石丁之事太微茫。"]'),
('f8b7d508-d1f3-45a0-a5f4-727c5a252216','送葉制參','劉克莊','宋','宋诗','song-poetry','','[]','聞說秋防急，安危寄閫臣。',48,'全唐诗/poet.song.200000.json','["聞說秋防急，安危寄閫臣。", "無心致羔雁，有分上麒麟。", "氈帽環吾境，綸巾頼此人。", "晉朝陶庾輩，豈必靠江神。"]'),
('8b45ca8c-796d-429a-8e93-47fe19c3c6cc','題方海豐詩卷','劉克莊','宋','宋诗','song-poetry','','[]','詩境高吟太白倫，梧州下筆李潮親。',64,'全唐诗/poet.song.200000.json','["詩境高吟太白倫，梧州下筆李潮親。", "今觀天馬非凡種，肯厭家雞問外人。", "力大鰲來吞釣餌，心專虱看似車輪。", "盛年出手追風雅，莫與香奩作後塵。"]'),
('b7e4dd6d-3cde-4979-8a9f-812d29d1665d','訓蒙二首  其一','劉克莊','宋','宋诗','song-poetry','','[]','漢魏以前猶古雅，宋齊而下稍淫哇。',64,'全唐诗/poet.song.200000.json','["漢魏以前猶古雅，宋齊而下稍淫哇。", "剪裁貧女機中素，撲賣都人擔上花。", "括帖不離初學記，管蠡烏覩大方家。", "世間跛鼈難鞭策，安得龍媒出渥洼。"]'),
('2aae1222-9836-4dc7-a1d2-495d7a632f50','訓蒙二首  其二','劉克莊','宋','宋诗','song-poetry','','[]','少喜浮名謬激昂，晚溫故讀稍精詳。',64,'全唐诗/poet.song.200000.json','["少喜浮名謬激昂，晚溫故讀稍精詳。", "易全何患乾坤毀，騷在堪爭日月光。", "漆簡字更經學誤，玉臺體出選詩亡。", "殘年欲尚鞭吾後，誰道先生已耄荒。"]'),
('09d60ae9-ec65-4dce-9a78-6c5c0f00a242','船子和尚遺跡在華亭朱涇之間圭上人即其所誅茅名西亭精舍介竹溪求詩於余寄題三絕  其一','劉克莊','宋','宋诗','song-poetry','','[]','誠和尚昔挂孤帆，圭上人今架小庵。',32,'全唐诗/poet.song.200000.json','["誠和尚昔挂孤帆，圭上人今架小庵。", "老去身無安頓處，挑包便擬作禪參。"]'),
('9068b4f8-713c-4d9c-90f2-b3954fd2ecf1','船子和尚遺跡在華亭朱涇之間圭上人即其所誅茅名西亭精舍介竹溪求詩於余寄題三絕  其二','劉克莊','宋','宋诗','song-poetry','','[]','自昔吳僧標致清，經禪之外有詩名。',32,'全唐诗/poet.song.200000.json','["自昔吳僧標致清，經禪之外有詩名。", "士衡止在東家住，恨不同聽鶴唳聲。"]'),
('906e8a62-b786-4534-a7af-2e1e9f44c581','船子和尚遺跡在華亭朱涇之間圭上人即其所誅茅名西亭精舍介竹溪求詩於余寄題三絕  其三','劉克莊','宋','宋诗','song-poetry','','[]','萬頃烟波百尺絲，禪家宗旨有誰知。',32,'全唐诗/poet.song.200000.json','["萬頃烟波百尺絲，禪家宗旨有誰知。", "自嫌固陋如高叟，却爲僧箋把釣詩。"]'),
('e71cf3ec-f38e-43d1-92ea-4d72662b5d0e','意一元樞稱張君平星術相法小詩將行','劉克莊','宋','宋诗','song-poetry','','[]','雖別號君平，誰知異姓名。',48,'全唐诗/poet.song.200000.json','["雖別號君平，誰知異姓名。", "嚴惟下簾坐，張乃挈家行。", "烽火連畿輔，冰霜滯客程。", "吾窮有詩耳，資汝謁公卿。"]'),
('cd7278ac-aef4-4644-a27d-5af04999e196','久不得池陽書','劉克莊','宋','宋诗','song-poetry','','[]','黑幟游魂尚未還，列城處處受風寒。',64,'全唐诗/poet.song.200000.json','["黑幟游魂尚未還，列城處處受風寒。", "遥知魯女悲而嘯，深愧龐公遺以安。", "道遠家人無恙否，時危身世苟全難。", "何時火伴并鄰里，沽酒刲羊賀木蘭。"]'),
('b8647a95-d9ec-4c9e-a129-f586dfa153c0','挽顧君任倅二首  其一','劉克莊','宋','宋诗','song-poetry','','[]','有酒常相覓，無金尚欲揮。',48,'全唐诗/poet.song.200000.json','["有酒常相覓，無金尚欲揮。", "竟騎黄鶴去，誰見素騾飛。", "華屋俄零露，蓉城果是非。", "自嫌聞道淺，懷舊忽沾衣。"]'),
('d9773a37-ebf2-417b-8b04-274654ce70bb','挽顧君任倅二首  其二','劉克莊','宋','宋诗','song-poetry','','[]','占斷慈恩塔，歸來履道坊。',48,'全唐诗/poet.song.200000.json','["占斷慈恩塔，歸來履道坊。", "耆英真率社，少尹釣游鄉。", "子可傳汾曲，甥能述渭陽。", "如聞無恙日，治塚建祠堂。"]'),
('ac431605-73e6-4020-a42c-4ebefad9c858','又一首','劉克莊','宋','宋诗','song-poetry','','[]','流輩多凋謝，君侯獨典刑。',48,'全唐诗/poet.song.200000.json','["流輩多凋謝，君侯獨典刑。", "德公耆舊傳，子野老人星。", "宦路羞由徑，家山預卜塋。", "何須更封樹，手種萬松青。"]'),
('d7d411c4-cb8b-46ad-b47f-7daac9d1a05b','記顔六言三首  其一','劉克莊','宋','宋诗','song-poetry','','[]','謗之則喪家狗，譽之則人中龍。',28,'全唐诗/poet.song.200000.json','["謗之則喪家狗，譽之則人中龍。", "華髮去周柱下，深衣立魯門東。"]'),
('8115a8d0-132a-41ce-8618-f70705a99041','記顔六言三首  其二','劉克莊','宋','宋诗','song-poetry','','[]','坐客驚問誰子，小孫道是吾翁。',28,'全唐诗/poet.song.200000.json','["坐客驚問誰子，小孫道是吾翁。", "文章呼延太尉，鬚眉張鎬相公。"]'),
('4999761a-64d1-4db1-bb38-9a48d763a365','記顔六言三首  其三','劉克莊','宋','宋诗','song-poetry','','[]','無空函達元子，有報書絕山公。',28,'全唐诗/poet.song.200000.json','["無空函達元子，有報書絕山公。", "非牛溪負苓者，即鹿門采藥翁。"]'),
('f4c90418-c742-4cd0-8f14-326a36647a36','贈天台通上人','劉克莊','宋','宋诗','song-poetry','','[]','老倦逢迎揖客稀，上人乃肯顧柴扉。',64,'全唐诗/poet.song.200000.json','["老倦逢迎揖客稀，上人乃肯顧柴扉。", "愧無林下茶瓜待，忽有空中杖錫飛。", "師瘦能吟無本句，吾窮難贈大顛衣。", "此行不枉觀南海，探得珊瑚滿載歸。"]'),
('fe827182-a0a5-496b-af73-c3b5c48be9ad','送三趙','劉克莊','宋','宋诗','song-poetry','','[]','聞說金雞下帝傍，徑從楚澤返虞庠。',64,'全唐诗/poet.song.200000.json','["聞說金雞下帝傍，徑從楚澤返虞庠。", "當時只道芻言切，今日徐思欖味長。", "中壘幾封知有漢，奉天一詔可存唐。", "却憐依附冰山者，不信雲開見太陽。"]'),
('5676187b-a515-4af5-8bd2-5cb74fc0d08a','次君疇洪卿韻送宗學趙優奏','劉克莊','宋','宋诗','song-poetry','','[]','欲爲乾坤掃積陰，萬言忠憤上穹臨。',64,'全唐诗/poet.song.200000.json','["欲爲乾坤掃積陰，萬言忠憤上穹臨。", "相嗔平地風波惡，主聖如天雨露深。", "葛藟尚爲庇根計，戎葵難改向陽心。", "明時安肯尋斤斧，自古高材出鄧林。"]'),
('03d2188d-f7fe-4027-9d4f-36c71807b3a3','次韻趙優奏良爌投贈二首  其一','劉克莊','宋','宋诗','song-poetry','','[]','不留妄念著胸中，弋者何心更慕鴻。',64,'全唐诗/poet.song.200000.json','["不留妄念著胸中，弋者何心更慕鴻。", "疇昔直前焚戇草，即今殿後著談叢。", "放言遣興詩瓢滿，野史誅姦筆鉞公。", "埋骨家山百無恨，聖賢厄蔡更徂東。"]'),
('827f58f9-0b0f-475d-94f3-dc61a5c78ca2','次韻趙優奏良爌投贈二首  其二','劉克莊','宋','宋诗','song-poetry','','[]','禿翁無物可將行，在野安能致魯生。',64,'全唐诗/poet.song.200000.json','["禿翁無物可將行，在野安能致魯生。", "曾伏端門攻鬼質，始知中壘是宗英。", "君如丹鳳鳴尤偉，彼化黄熊罪尚輕。", "田里誦言仁聖悔，天其或者再昇平。"]'),
('f205ab08-568d-4097-bf77-3087c3c9c2eb','七十四吟十首  其一','劉克莊','宋','宋诗','song-poetry','','[]','早衰安敢望年高，鏡裏雙眉有白毫。',64,'全唐诗/poet.song.200000.json','["早衰安敢望年高，鏡裏雙眉有白毫。", "消夜賭棋張畫燭，怯寒添絮入綈袍。", "百骸受病惟詩健，萬事輸人獨飲豪。", "梨栗滿山皆碩果，何須海上訪蟠桃。"]'),
('71581f29-025b-478c-9d7e-15ce18f90e68','七十四吟十首  其二','劉克莊','宋','宋诗','song-poetry','','[]','鄰雞呼覺强冠簪，病起屠蘇且淺斟。',64,'全唐诗/poet.song.200000.json','["鄰雞呼覺强冠簪，病起屠蘇且淺斟。", "旋讀生書無記性，冥搜警句有貪心。", "生慙族老封高尚，死慕先賢謚醉吟。", "自笑此翁迂闊甚，後千百世待知音。"]'),
('35e26418-dc4e-47f1-88a8-5efe194def96','七十四吟十首  其三','劉克莊','宋','宋诗','song-poetry','','[]','兒縈薄宦女從夫，誰伴龐翁擁地爐。',64,'全唐诗/poet.song.200000.json','["兒縈薄宦女從夫，誰伴龐翁擁地爐。", "頗憶都嘗煨芋否，肯歸同賣漉籬無。", "春游捉轡惟宗武，晨起稱觴僅阿奴。", "一句汝曹牢記取，家山差穩似江湖。"]'),
('5330da7a-1f81-4f4b-9887-bdc510cf7d95','七十四吟十首  其四','劉克莊','宋','宋诗','song-poetry','','[]','萬里當年慕建侯，而今癡坐衲蒙頭。',64,'全唐诗/poet.song.200000.json','["萬里當年慕建侯，而今癡坐衲蒙頭。", "臭皮袋有形爲累，古錦囊無句可收。", "拾穗翁饑歌不輟，散花人黠去難留。", "荒村不辦肩輿者，未害先生策杖游。"]'),
('86a3f0ed-74c6-42ac-b6c3-655e12969c28','七十四吟十首  其五','劉克莊','宋','宋诗','song-poetry','','[]','養生之說要形勞，井臼何須晚自操。',64,'全唐诗/poet.song.200000.json','["養生之說要形勞，井臼何須晚自操。", "齒豁未須煩祝鯁，臂攣殊不礙持螯。", "除驅病祟無靈劑，禆補脾神頼老饕。", "尚有一襟哀郢淚，久疎夜飲省春遨。"]'),
('af33615b-860c-4287-bcbf-07e447688378','七十四吟十首  其六','劉克莊','宋','宋诗','song-poetry','','[]','翠華未可議時巡，自古安危繫重臣。',64,'全唐诗/poet.song.200000.json','["翠華未可議時巡，自古安危繫重臣。", "聞說紫巖親督戰，孰云赤壁後無人。", "諸公盡作鑽天令，老子重爲擊壤民。", "萬里陰霾冰霰合，一通露布挽迴春。"]'),
('728a9fa2-c3ca-40cc-aaee-7cb04c9bb62f','七十四吟十首  其七','劉克莊','宋','宋诗','song-poetry','','[]','黠兒蒙蔽聚羣陰，豈料雲收杲日臨。',64,'全唐诗/poet.song.200000.json','["黠兒蒙蔽聚羣陰，豈料雲收杲日臨。", "壞證遺憂與宗社，捷書分喜到山林。", "擎天畢竟還高手，偃月從初謬用心。", "客自京師傳吉語，放歌不覺有和音。"]'),
('09f967ae-6bf4-4d08-aa73-000436ea2118','七十四吟十首  其八','劉克莊','宋','宋诗','song-poetry','','[]','戍邕潰卒導蕃夷，聞說衡湘被禍奇。',64,'全唐诗/poet.song.200000.json','["戍邕潰卒導蕃夷，聞說衡湘被禍奇。", "羣盜忍殘勝業柏，六丁應護中興碑。", "赭君山木渠何罪，招國殤魂鬼亦悲。", "早晚嶽雲俱汛掃，挽天河水洗瘡痍。"]'),
('926321fa-c72c-4b79-8939-0f54d956f16c','七十四吟十首  其九','劉克莊','宋','宋诗','song-poetry','','[]','遊戲人間又一年，非儒非佛復非仙。',64,'全唐诗/poet.song.200000.json','["遊戲人間又一年，非儒非佛復非仙。", "歷官甘出倚相後，序齒叨居絳老先。", "世難見花常濺淚，時平逢麴亦流涎。", "無端風月相勾引，不是先生愛放顛。"]'),
('6f1b468a-eb32-4b50-b7e6-c6a49e4f1d0a','七十四吟十首  其一○','劉克莊','宋','宋诗','song-poetry','','[]','提鼇批鳳霎時榮，身與浮名孰重輕。',64,'全唐诗/poet.song.200000.json','["提鼇批鳳霎時榮，身與浮名孰重輕。", "摩詰已爲病居士，伯倫終是大先生。", "彼拳雞肋恃朝氣，此把蟹螯猶宿酲。", "未必頹然真茗艼，老人羞共少年爭。"]'),
('183cd2bf-d5a1-4606-9987-337a29e3e736','送伯紀禮部造朝兼簡息菴二首  其一','劉克莊','宋','宋诗','song-poetry','','[]','傳聞東澗拜南宮，朝野皆忻泰道通。',64,'全唐诗/poet.song.200000.json','["傳聞東澗拜南宮，朝野皆忻泰道通。", "不比唐家超子厚，壹如元祐起坡公。", "官箴健論猶當續，雪月浮文不必工。", "十載帝城無點墨，有懷難託北飛鴻。"]'),
('70b84919-180d-4a44-81aa-6123d35c974e','送伯紀禮部造朝兼簡息菴二首  其二','劉克莊','宋','宋诗','song-poetry','','[]','謝遣弓旌久掩關，十年坐閲幾蒲團。',64,'全唐诗/poet.song.200000.json','["謝遣弓旌久掩關，十年坐閲幾蒲團。", "老臣憊不堪將橐，丞相嗔因乞挂冠。", "廟算渾如孤注賭，林栖未保一枝安。", "暮雲萬疊江閩遠，相見除非插羽翰。"]'),
('d773d63a-cd01-48e4-81a9-cb231ac9cdd2','居厚弟和七十四吟再賦  其一','劉克莊','宋','宋诗','song-poetry','','[]','用世文章莫太高，空言詎有補絲毫。',64,'全唐诗/poet.song.200000.json','["用世文章莫太高，空言詎有補絲毫。", "呼來誰遣批黄敕，謫去何須著錦袍。", "齒耋自應陪九老，詩低不足列三豪。", "僕家夢得無標致，愛說玄都觀裏桃。"]'),
('cf128cac-7ed1-43c3-be06-14678dc42693','居厚弟和七十四吟再賦  其二','劉克莊','宋','宋诗','song-poetry','','[]','聞說朝家念履簪，朵頤安肯學羊斟。',64,'全唐诗/poet.song.200000.json','["聞說朝家念履簪，朵頤安肯學羊斟。", "批塗曾舉詞臣職，芹曝終懷野老心。", "曉鏡鬢鬚難染摘，夜檠手口尚披吟。", "世間蚓竅更鳴和，未識王孫半嶺音。"]'),
('ef604819-2e10-4241-ba74-b5a6b7ea028d','居厚弟和七十四吟再賦  其三','劉克莊','宋','宋诗','song-poetry','','["\u897f\u6e56"]','久拋弓冶作耕夫，故步人猶記鐵爐。',64,'全唐诗/poet.song.200000.json','["久拋弓冶作耕夫，故步人猶記鐵爐。", "已老安能歌競病，從初不合識之無。", "房帷那復伶玄妾，部曲惟餘穎士奴。", "春暖小車時一出，絕勝朝士典西湖。"]'),
('1abe6b2c-683e-4f26-9e1d-0a44244bf66c','居厚弟和七十四吟再賦  其四','劉克莊','宋','宋诗','song-poetry','','[]','麾下偏裨盡拜侯，執俘已漆月氐頭。',64,'全唐诗/poet.song.200000.json','["麾下偏裨盡拜侯，執俘已漆月氐頭。", "飲江馬去黄旗捷，巢幕烏來黑眚收。", "上不解衣常北顧，公宜歸衮勿東留。", "幾時四野狼烟息，爛醉花間秉燭遊。"]'),
('78b381ac-34e8-427b-9887-44894ad9de46','居厚弟和七十四吟再賦  其五','劉克莊','宋','宋诗','song-poetry','','[]','曾厭承明儤直勞，中宵麻卷攬衣操。',64,'全唐诗/poet.song.200000.json','["曾厭承明儤直勞，中宵麻卷攬衣操。", "退閑久已袖雙手，老懶渠能注二螯。", "雲水生涯今易足，人天供養昔非饕。", "三家村未聞戎捷，但見樗翁又出遨。"]'),
('288ddd50-0164-44cb-95c5-d02fab263e09','居厚弟和七十四吟再賦  其六','劉克莊','宋','宋诗','song-poetry','','[]','列城若箇是張巡，拊髀方思志義臣。',64,'全唐诗/poet.song.200000.json','["列城若箇是張巡，拊髀方思志義臣。", "懷印綬亡多委郡，援鍪弧死更無人。", "肆雞竿赦還遷客，出褭蹄金聚散民。", "待得玄冥解嚴了，東皇太乙又行春。"]'),
('49317f07-9689-45c0-bd1c-917264b7ba0c','居厚弟和七十四吟再賦  其七','劉克莊','宋','宋诗','song-poetry','','[]','光堯倉卒幸山陰，或者譌傳蹕再臨。',64,'全唐诗/poet.song.200000.json','["光堯倉卒幸山陰，或者譌傳蹕再臨。", "長算决於春思殿，捷書來自殺胡林。", "奔逃尤甚騎豬窘，懲創從前飲馬心。", "强作凱歌殊下俚，不如商頌有遺音。"]'),
('872e7b03-438e-4b2d-8211-96ff7f12f665','居厚弟和七十四吟再賦  其八','劉克莊','宋','宋诗','song-poetry','','[]','雪埋磴道古壇夷，疇昔茲遊境絕奇。',64,'全唐诗/poet.song.200000.json','["雪埋磴道古壇夷，疇昔茲遊境絕奇。", "石上猶存周故轍，山尖難訪禹殘碑。", "雲開天柱峯雖出，血作陳清水可悲。", "帝賞戰功無吝色，定分寶枕療金痍。"]'),
('ac6d90f3-e3a4-4d08-aacf-4cc950fe58c4','居厚弟和七十四吟再賦  其九','劉克莊','宋','宋诗','song-poetry','','[]','占斷溪山不紀年，俗開謗道是獃仙。',64,'全唐诗/poet.song.200000.json','["占斷溪山不紀年，俗開謗道是獃仙。", "馬遲甘殿他人後，棋劣常輸敵手先。", "饑咬菜根美熊掌，窮燒柏子當龍涎。", "可憐陳竇無精識，欲以繩維大厦顛。"]'),
('75c4a399-f869-489e-a43a-169517549cd3','居厚弟和七十四吟再賦  其一○','劉克莊','宋','宋诗','song-poetry','','[]','得喪傍觀有悴榮，此翁勘破一毫輕。',64,'全唐诗/poet.song.200000.json','["得喪傍觀有悴榮，此翁勘破一毫輕。", "讌披香殿猶前日，出大槐宮已隔生。", "未許季咸覘老態，旋呼伯雅解春酲。", "不知觸氏并蠻氏，勝負元因底事爭。"]'),
('43d7f801-89b0-47ad-9f29-c00898dd4892','景定初元即事十首  其一','劉克莊','宋','宋诗','song-poetry','','[]','祲掃青山峽，功高赤壁磯。',24,'全唐诗/poet.song.200000.json','["祲掃青山峽，功高赤壁磯。", "只宜奉頭竄，莫待剖羓歸。"]'),
('f8113466-15b3-494b-a7f1-9f885d7163c4','景定初元即事十首  其二','劉克莊','宋','宋诗','song-poetry','','[]','糲食憂民瘠，茅廬念士寒。',24,'全唐诗/poet.song.200000.json','["糲食憂民瘠，茅廬念士寒。", "一生憐此老，錯把兩眉攢。"]'),
('5926855f-2a41-4a17-8ae3-210ec333d45f','景定初元即事十首  其三','劉克莊','宋','宋诗','song-poetry','','[]','諸老雲臺上，人人畫一籌。',24,'全唐诗/poet.song.200000.json','["諸老雲臺上，人人畫一籌。", "奈何令退士，長抱杞人憂。"]'),
('b7c1b68a-d051-4fd4-8cf9-3a03808ddf21','景定初元即事十首  其四','劉克莊','宋','宋诗','song-poetry','','[]','昨朝捷旗至，明日警書馳。',24,'全唐诗/poet.song.200000.json','["昨朝捷旗至，明日警書馳。", "避殿猶如故，來庭定幾時。"]'),
('cbc8791d-3e99-46a8-956f-887f9f235f8a','景定初元即事十首  其五','劉克莊','宋','宋诗','song-poetry','','[]','臣繇賀捷表，臣結中興碑。',24,'全唐诗/poet.song.200000.json','["臣繇賀捷表，臣結中興碑。", "亙古雄辭在，於今老學誰。"]'),
('99d7e722-0cf1-4059-869e-086273a67a47','景定初元即事十首  其六','劉克莊','宋','宋诗','song-poetry','','[]','客駭蒙倛面，兒扶痀瘻身。',24,'全唐诗/poet.song.200000.json','["客駭蒙倛面，兒扶痀瘻身。", "有時臨鏡問，此老是何人。"]'),
('de3137ae-9ccd-40d0-aa4b-3411b316e2c4','景定初元即事十首  其七','劉克莊','宋','宋诗','song-poetry','','[]','溪水拍浮滿，野花紅白多。',24,'全唐诗/poet.song.200000.json','["溪水拍浮滿，野花紅白多。", "老夫被牽率，信步出雞窠。"]'),
('72007571-0fa0-43be-83ec-2c512d0b1006','景定初元即事十首  其八','劉克莊','宋','宋诗','song-poetry','','[]','飲狂插紅杏，醉倒藉蒼苔。',24,'全唐诗/poet.song.200000.json','["飲狂插紅杏，醉倒藉蒼苔。", "董子窺園出，龐公上塚迴。"]'),
('1badc380-3b9c-4cfb-a87b-4f2e448248c4','景定初元即事十首  其九','劉克莊','宋','宋诗','song-poetry','','[]','邕題碑板富，郊因詩句窮。',24,'全唐诗/poet.song.200000.json','["邕題碑板富，郊因詩句窮。", "濡毫乏精婢，隨馬有奚童。"]'),
('b579c10c-d4f5-4e40-af08-9e745a929906','景定初元即事十首  其一○','劉克莊','宋','宋诗','song-poetry','','[]','倦攬今書尺，時將晉帖看。',24,'全唐诗/poet.song.200000.json','["倦攬今書尺，時將晉帖看。", "殷生與宰相，一體問平安。"]'),
('c7c6b474-50de-4fed-98a4-b6001c7d7fd2','送延平張生歸南溪','劉克莊','宋','宋诗','song-poetry','','[]','問訊南溪水，韓張泛幾迴。',24,'全唐诗/poet.song.200000.json','["問訊南溪水，韓張泛幾迴。", "侍郎何處在，司業有孫來。"]'),
('d21d246f-8db4-4210-b405-4ef21eb32c25','挽翁仲山常卿二首  其一','劉克莊','宋','宋诗','song-poetry','','[]','進由孤士列華簪，曾對薰風和舜琴。',64,'全唐诗/poet.song.200000.json','["進由孤士列華簪，曾對薰風和舜琴。", "資善禮行貂豎肅，議郎疏出馬羣瘖。", "畿民猶說張京兆，宮媛皆知李翰林。", "麾去招來關氣數，浩穹於此本無心。"]'),
('d73e4e72-717d-4a13-9f70-0d97be948de0','挽翁仲山常卿二首  其二','劉克莊','宋','宋诗','song-poetry','','[]','昔駕輶軒忝外臺，愛文學掾有高才。',64,'全唐诗/poet.song.200000.json','["昔駕輶軒忝外臺，愛文學掾有高才。", "曾留太白論文去，亦辱奇章贄卷來。", "玉樹枝成終古訣，紫薇花對別人開。", "時危國蹙英賢夭，空撚霜髭賦八哀。"]'),
('bdbd1e14-7840-402a-b91c-293dfd249db0','挽參與蔡公三首  其一','劉克莊','宋','宋诗','song-poetry','','[]','蔡公遂委篤，朝野共歔欷。',48,'全唐诗/poet.song.200000.json','["蔡公遂委篤，朝野共歔欷。", "子不稅冕去，王將以衮歸。", "風濤如此急，人物眇然稀。", "自古難全傳，今無一可譏。"]'),
('893e173d-72ad-4725-83c0-9c7b236c5f43','挽參與蔡公三首  其二','劉克莊','宋','宋诗','song-poetry','','[]','磊落多奇節，源流自父師。',48,'全唐诗/poet.song.200000.json','["磊落多奇節，源流自父師。", "力扶舉幡士，顯拒賣珠兒。", "無復金甌覆，空令玉鉞悲。", "太常誰議謚，可不采吾詩。"]'),
('096cd9b3-e614-4302-9739-8c02537432b1','挽參與蔡公三首  其三','劉克莊','宋','宋诗','song-poetry','','[]','昔任高陽里，登堂執束脩。',48,'全唐诗/poet.song.200000.json','["昔任高陽里，登堂執束脩。", "深知二郎故，曾接兩翁游。", "面棘新班峻，然藜舊話休。", "空藏笥中帖，世世寶銀鈎。"]'),
('9a6bd0af-4870-4a9c-be86-e2ed6d1204cb','贈術者施元龍','劉克莊','宋','宋诗','song-poetry','','[]','信上多人物，華宗譜最蕃。',48,'全唐诗/poet.song.200000.json','["信上多人物，華宗譜最蕃。", "遥遥忘世胄，僕僕傍誰門。", "眼毒偏奇中，心靈每預言。", "禿翁無阿堵，何以贈南轅。"]'),
('544bbc57-de69-46d5-847d-5a5b276b5cf5','題孫母陳孺人墓誌','劉克莊','宋','宋诗','song-poetry','','[]','誨子如陶母，持身比伯姬。',48,'全唐诗/poet.song.200000.json','["誨子如陶母，持身比伯姬。", "携扶同出峽，僑寄未還枝。", "阡有時而表，魂無所不之。", "一端差慰意，徐字與楊碑。"]'),
('0434bba4-967f-4f40-a042-bdf803a35fa5','讀陳湯傳','劉克莊','宋','宋诗','song-poetry','','[]','短後衣裝腰寶刀，空言無實世滔滔。',64,'全唐诗/poet.song.200000.json','["短後衣裝腰寶刀，空言無實世滔滔。", "掉齊虜舌何其易，斬郅支頭豈不豪。", "異代武夫猶奪氣，當時文吏苦吹毛。", "漢廷誰是持衡者，只罪邀功不賞勞。"]'),
('378f0a32-afc9-4b47-a92f-e2b46903f7e8','書事十首  其一','劉克莊','宋','宋诗','song-poetry','','[]','幼作淳熙版籍民，老逢景定改元新。',64,'全唐诗/poet.song.200000.json','["幼作淳熙版籍民，老逢景定改元新。", "殘年且盡杯中物，他日誰澆柏下人。", "長鑱谷中忙斸雪，小車花外徧尋春。", "吾評子美饑寒態，不似堯夫快活身。"]'),
('6076d175-e4fc-4294-9ffa-9838e870a28f','書事十首  其二','劉克莊','宋','宋诗','song-poetry','','[]','罪己綸言徧九州，桑榆雖晚尚堪收。',64,'全唐诗/poet.song.200000.json','["罪己綸言徧九州，桑榆雖晚尚堪收。", "下山東詔爭扶聽，讀奉天書有淚流。", "加霍嫖姚冠軍號，拜車丞相富民侯。", "崆峒麥熟無人刈，何日王師且少休。"]'),
('620fba28-beaa-43cc-926e-54766774914b','書事十首  其三','劉克莊','宋','宋诗','song-poetry','','[]','天塹猶艱限臭夷，江邊蚌鷸久相持。',64,'全唐诗/poet.song.200000.json','["天塹猶艱限臭夷，江邊蚌鷸久相持。", "昔珠簾閣俱清野，今琵琶亭亦浚池。", "戶萬八千封作麽，計三十六走安之。", "平生師慕堯夫者，老去無端也皺眉。"]'),
('d1cc3b44-458d-456e-8952-10452bb00fb9','書事十首  其四','劉克莊','宋','宋诗','song-poetry','','[]','生長承平玩細娛，變興倉卒不支吾。',64,'全唐诗/poet.song.200000.json','["生長承平玩細娛，變興倉卒不支吾。", "輕裘太守拋鈴下，寶玦郎君泣路隅。", "諜報長驅殊未覺，經書大去可勝誅。", "世間果有桃源否，千載無人更問途。"]'),
('b22f3f61-034d-4a4d-945d-f10d53687a94','書事十首  其五','劉克莊','宋','宋诗','song-poetry','','[]','旦旦尋斤傑木衰，艱危深動聽鼙思。',64,'全唐诗/poet.song.200000.json','["旦旦尋斤傑木衰，艱危深動聽鼙思。", "賜龍墀對詢韜畧，復雁門踦建義旗。", "古有轝迎聾主簿，今誰卧載臏軍師。", "不應在野無賢雋，林密山深世未知。"]'),
('2961c152-45af-466a-be2e-18b876d02460','書事十首  其六','劉克莊','宋','宋诗','song-poetry','','[]','魁柄推移偶屬渠，可堪一擲付狂疏。',64,'全唐诗/poet.song.200000.json','["魁柄推移偶屬渠，可堪一擲付狂疏。", "文中子處無熏染，桑大夫邊竊緒餘。", "癡物汝爲何等相，纖兒吾惜好家居。", "時人悞把朱崖比，若比朱崖儘欠書。"]'),
('7e8e9576-7289-43c9-9592-a0b06936e559','書事十首  其七','劉克莊','宋','宋诗','song-poetry','','[]','不知邊信近何如，但見朝朝發虎符。',64,'全唐诗/poet.song.200000.json','["不知邊信近何如，但見朝朝發虎符。", "河北幾於九節度，漠南奚止五單于。", "黑天肥瘞猶存孽，紅賊巢荒尚有雛。", "安得四方皆猛士，旄頭掃盡一塵無。"]'),
('5698847c-34b9-4e5d-9255-1c5365c02f41','書事十首  其八','劉克莊','宋','宋诗','song-poetry','','[]','晉士材疏辯舌優，俗雖虛誕尚清脩。',64,'全唐诗/poet.song.200000.json','["晉士材疏辯舌優，俗雖虛誕尚清脩。", "可容卿等數百輩，亦過江來第一流。", "元老縱然揮玉麈，七賢已有執牙籌。", "後來靈寶真兒態，書畫惟憑奪與偷。"]'),
('3a58edbd-87ef-4b6b-bb00-3efae9e2506e','書事十首  其九','劉克莊','宋','宋诗','song-poetry','','[]','戰鼙非起自漁陽，到寇皆由偃月堂。',64,'全唐诗/poet.song.200000.json','["戰鼙非起自漁陽，到寇皆由偃月堂。", "相國裘雖來賀捷，蚩尤旗尚未收芒。", "厨車古有刑都市，寶劍今誰請尚方。", "莫倚聖朝家法恕，前盧後蔡亦投荒。"]'),
('e67e5cef-1856-48a2-a2f7-032cd4c165a7','書事十首  其一○','劉克莊','宋','宋诗','song-poetry','','[]','漢重貂璫鼎軸輕，力扶弱勢頼公卿。',64,'全唐诗/poet.song.200000.json','["漢重貂璫鼎軸輕，力扶弱勢頼公卿。", "劾侯常侍如張□，訟石中書有更生。", "伺夜九頭猶作祟，過時百舌未收聲。", "虞廷可是無儀鳳，底事相看噤不鳴。"]'),
('a168aa19-685c-48cd-834a-5ce4a2267a30','錄顔魯公事','劉克莊','宋','宋诗','song-poetry','','[]','世亂朝危節少全，魯公大義薄雲天。',64,'全唐诗/poet.song.200000.json','["世亂朝危節少全，魯公大義薄雲天。", "憫忠親以舌舐血，駡賊尸猶爪透拳。", "曾餌仙丹元不死，求容鬼質豈其然。", "郎君自有翹材客，焉識堂堂父執賢。"]'),
('2f0d0a96-2f28-41a2-9faf-e17dc9e4ff25','挽史館資政木石尢公三首  其一','劉克莊','宋','宋诗','song-poetry','','[]','往年羣玉頂，典領偶然同。',48,'全唐诗/poet.song.200000.json','["往年羣玉頂，典領偶然同。", "我去如廷秀，君來似放翁。", "周聃駕牛出，魯叟感麟逢。", "縱有招魂些，誰爲寄浙中。"]'),
('df8d9cb4-892d-4617-a235-38dffff6799e','挽史館資政木石尢公三首  其二','劉克莊','宋','宋诗','song-poetry','','[]','雖云鈎二府，終未到頭聽。',48,'全唐诗/poet.song.200000.json','["雖云鈎二府，終未到頭聽。", "密勿多中赤，淹留了汗青。", "讒能離主眷，史果有天刑。", "太息崇儒世，申公不在廷。"]'),
('da5d6409-fea4-4c10-ab50-b241f869c8fe','挽史館資政木石尢公三首  其三','劉克莊','宋','宋诗','song-poetry','','[]','歷代名書畫，中原古鼎彝。',48,'全唐诗/poet.song.200000.json','["歷代名書畫，中原古鼎彝。", "不教蕭翼看，常怕米顛知。", "此物空盈笈，何人與掌匙。", "貴無它嗜好，焉用太清爲。"]'),
('adb2d029-f190-47e6-a75b-8e87816061fb','贈崇安劉相士','劉克莊','宋','宋诗','song-poetry','','[]','向來種花地，曾與五夫鄰。',48,'全唐诗/poet.song.200000.json','["向來種花地，曾與五夫鄰。", "有客我同姓，見君如故人。", "赤身窮至骨，碧眼妙通神。", "且問兩元老，何時定秉鈞。"]'),
('f0648448-4b77-4b44-812b-4d7475ed4282','得江西報六言十首  其一','劉克莊','宋','宋诗','song-poetry','','[]','大江已浪頭白，中原未棗兒紅。',28,'全唐诗/poet.song.200000.json','["大江已浪頭白，中原未棗兒紅。", "折北不愁春水，吠南何必秋風。"]'),
('900a248a-c2ad-4623-ab95-97ac9c552f13','得江西報六言十首  其二','劉克莊','宋','宋诗','song-poetry','','[]','巧發過如蠆毒，困鬭尤防獸窮。',28,'全唐诗/poet.song.200000.json','["巧發過如蠆毒，困鬭尤防獸窮。", "老种有騎河語，小姚無劫寨功。"]'),
('6cf24251-e28b-482c-8f15-605bef187071','得江西報六言十首  其三','劉克莊','宋','宋诗','song-poetry','','[]','師整亦勁敵也，將能彼有人焉。',28,'全唐诗/poet.song.200000.json','["師整亦勁敵也，將能彼有人焉。", "國老可當十萬，兒輩止消八千。"]'),
('986cfe08-9890-4810-a918-0a7c5fa3ac8f','得江西報六言十首  其四','劉克莊','宋','宋诗','song-poetry','','[]','石天祠有烟焰，游帷觀亦腥膻。',28,'全唐诗/poet.song.200000.json','["石天祠有烟焰，游帷觀亦腥膻。", "小龍子入於海，老仙翁飛上天。"]'),
('0d66ba89-11a6-4c55-aeeb-c3279a3defca','得江西報六言十首  其五','劉克莊','宋','宋诗','song-poetry','','[]','金騎越天塹至，水犀破雪浪迴。',28,'全唐诗/poet.song.200000.json','["金騎越天塹至，水犀破雪浪迴。", "兒單于鳴鏑走，父令公免胄來。"]'),
('5cd8d269-a40b-400f-9423-f830ed977565','得江西報六言十首  其六','劉克莊','宋','宋诗','song-poetry','','[]','□弓已耕甫里，雙旄昔牧宜春。',28,'全唐诗/poet.song.200000.json','["□弓已耕甫里，雙旄昔牧宜春。", "虎過有殘聚落，鶴歸無舊人民。"]'),
('f4090f16-9143-4299-8384-a96f1ff17903','得江西報六言十首  其七','劉克莊','宋','宋诗','song-poetry','','[]','典午無蜀可也，孫氏畫江守之。',28,'全唐诗/poet.song.200000.json','["典午無蜀可也，孫氏畫江守之。", "輕裘緩带自若，拔刀斫案不疑。"]'),
('cb10f80a-8180-4b4f-969e-6c94753f0472','得江西報六言十首  其八','劉克莊','宋','宋诗','song-poetry','','[]','羋姓公子哀郢，黍離大夫憫周。',28,'全唐诗/poet.song.200000.json','["羋姓公子哀郢，黍離大夫憫周。", "杜云野老潜哭，谷謂寒儒浪愁。"]'),
('89014288-7e55-4fbe-8905-ed6091bc1200','得江西報六言十首  其九','劉克莊','宋','宋诗','song-poetry','','[]','四野有農復業，三邊無虜游魂。',28,'全唐诗/poet.song.200000.json','["四野有農復業，三邊無虜游魂。", "作烘虱詩和友，把相牛經教孫。"]'),
('63463da4-1689-4e29-bece-b8de5e51ec10','得江西報六言十首  其一○','劉克莊','宋','宋诗','song-poetry','','[]','但見盈城盈野，誰能去食去兵。',28,'全唐诗/poet.song.200000.json','["但見盈城盈野，誰能去食去兵。", "山東河北捲土，江右湖南失耕。"]'),
('89348be7-9fa3-4ee3-99d1-37684f840219','清明','劉克莊','宋','宋诗','song-poetry','','[]','挾彈飛觥迹已陳，賞心事去負芳辰。',64,'全唐诗/poet.song.200000.json','["挾彈飛觥迹已陳，賞心事去負芳辰。", "數經風雨花尤厄，試說關山柳亦顰。", "人到蒼皤方覺老，天無紅綠不成春。", "近來未有池塘夢，誰道先生意尚新。"]'),
('c903eaf7-eda4-4937-a90d-c51c79b68a5e','嘲柳花','劉克莊','宋','宋诗','song-poetry','','[]','吹去飛來似有情，禁烟時節徧春城。',64,'全唐诗/poet.song.200000.json','["吹去飛來似有情，禁烟時節徧春城。", "比氈鋪徑何其窶，擬雪因風得許清。", "閲武活殘兒命薄，章臺走倦尹才輕。", "滿池無處看金鯽，閑猗朱闌聽唼聲。"]'),
('186e0ae0-ac35-44a6-8cd9-694acd4a5792','擷陽阡二首  其一','劉克莊','宋','宋诗','song-poetry','','[]','無論晴及雨，歲歲到寒原。',48,'全唐诗/poet.song.200000.json','["無論晴及雨，歲歲到寒原。", "下馬陵如故，書麟筆不存。", "心燈長在世，諫笏尚傳孫。", "毫髮皆翁賜，難忘罔極恩。"]'),
('009f6398-5f7a-4ffd-90c6-0fda45d5c81b','擷陽阡二首  其二','劉克莊','宋','宋诗','song-poetry','','[]','特起雖名世，相承必象賢。',48,'全唐诗/poet.song.200000.json','["特起雖名世，相承必象賢。", "亦嘗紬石室，終莫續銅川。", "頗覺卿慙長，徒知物本元。", "此生甘寂寂，白首抱遺編。"]'),
('27253751-054b-47af-9d1f-2af94f102a4b','寒食','劉克莊','宋','宋诗','song-poetry','','[]','聞道江鄉吹戰塵，叵堪鼙皷震于鄰。',64,'全唐诗/poet.song.200000.json','["聞道江鄉吹戰塵，叵堪鼙皷震于鄰。", "荒城少有飛花處，高塚多無擘紙人。", "沙塞榆枯難取火，玉關柳少化爲薪。", "遥知玉座焦勞處，閑却龍舟閣水濱。"]'),
('01676b97-6871-40ec-a700-a6d6c67ff8a1','海棠七首  其一','劉克莊','宋','宋诗','song-poetry','','[]','蜀女羞施粉，輕裝愛淡紅。',24,'全唐诗/poet.song.200000.json','["蜀女羞施粉，輕裝愛淡紅。", "抹塗尚年少，膏沐爲誰容。"]'),
('158e2b57-eeee-48e6-b813-44891ca85718','海棠七首  其二','劉克莊','宋','宋诗','song-poetry','','[]','范公蜀西曲，陸老劍南詩。',24,'全唐诗/poet.song.200000.json','["范公蜀西曲，陸老劍南詩。", "子美渠曾道，淵材輩豈知。"]'),
