('1b097ee6-2f66-4ba8-8075-b9ce74ba13a8','海棠七首  其四','劉克莊','宋','宋诗','song-poetry','','[]','一種穠纖態，三郎未必知。',24,'全唐诗/poet.song.200000.json','["一種穠纖態，三郎未必知。", "浪將妃子比，妃子太濃肥。"]'),
('09b910c8-35bd-41e3-b17c-2d0dc8e260fe','海棠七首  其五','劉克莊','宋','宋诗','song-poetry','','[]','神女漂紅者，顛姨發赤然。',24,'全唐诗/poet.song.200000.json','["神女漂紅者，顛姨發赤然。", "年年吹洗了，未必恕今年。"]'),
('dd6c72a9-ec2e-4186-90c2-4db0abe501ff','海棠七首  其六','劉克莊','宋','宋诗','song-poetry','','[]','恰見如丹粒，俄驚似紫綿。',24,'全唐诗/poet.song.200000.json','["恰見如丹粒，俄驚似紫綿。", "山翁無供帳，只就落花眠。"]'),
('5c941860-8ab9-401f-8f95-bab830fd62f3','海棠七首  其七','劉克莊','宋','宋诗','song-poetry','','[]','地行臣耄矣，稽首告天公。',24,'全唐诗/poet.song.200000.json','["地行臣耄矣，稽首告天公。", "藉草千場醉，留花十日紅。"]'),
('beb27806-e029-4683-9b78-764a610de845','送金仙玢上人主講隆壽院','劉克莊','宋','宋诗','song-poetry','','[]','昔委荆榛誰起廢，今增輪奐不爲奢。',64,'全唐诗/poet.song.200000.json','["昔委荆榛誰起廢，今增輪奐不爲奢。", "微神通力營經藏，須海潮音轉法華。", "况有緊幫王打供，豈無長者子傾家。", "此行非作衣鉢計，饒益尤多等算沙。"]'),
('3fae5d74-49cd-4b6e-a5ec-5a253f2e0fa6','久雨','劉克莊','宋','宋诗','song-poetry','','[]','晴旭常難保，春寒未易禁。',48,'全唐诗/poet.song.200000.json','["晴旭常難保，春寒未易禁。", "鋒交馬旋濘，室毀燕巢林。", "民望兵如雨，人言潦屬陰。", "何當抉雲霧，放出太陽臨。"]'),
('c402e6cb-ed69-48d3-86c0-eed99b2ee540','漁村林太淵相訪','劉克莊','宋','宋诗','song-poetry','','[]','不但親傳亦鮑參，妙年青乃過於藍。',64,'全唐诗/poet.song.200000.json','["不但親傳亦鮑參，妙年青乃過於藍。", "一斑昔已窺而見，三顧吾何德以堪。", "之子鳳兮真有種，汝曹犢耳可無慙。", "自嫌老病難留客，只伴樗翁數刻談。"]'),
('2aad0b98-f4b7-4b3e-b3a0-c9e9a03c1b7a','竹溪痔後齒痛小詩問訊','劉克莊','宋','宋诗','song-poetry','','[]','天壽斯文嘿護持，區區二豎莫兒嬉。',64,'全唐诗/poet.song.200000.json','["天壽斯文嘿護持，區區二豎莫兒嬉。", "炊糜足以留佳客，啖麵賢於聘上醫。", "渴見紫芝常入夢，共游黄蘗屢愆期。", "溪邊雨過春泥滑，借問門前裹飯誰。"]'),
('1f6078f2-8862-43d6-9055-df70dd64a945','臨江使君陳華叟哀詩二首  其一','劉克莊','宋','宋诗','song-poetry','','[]','衆聞鳴鏑驚麕散，獨奮空拳躍馬迎。',64,'全唐诗/poet.song.200000.json','["衆聞鳴鏑驚麕散，獨奮空拳躍馬迎。", "嚼齒駡聲殊未絕，歸元血面尚如生。", "睢陽合祀無南八，河北諸城有杲卿。", "可惜援師來已晚，當時巷戰只州兵。"]'),
('cd527fee-b3db-4bfc-a534-8257ca9f69ab','臨江使君陳華叟哀詩二首  其二','劉克莊','宋','宋诗','song-poetry','','[]','去歲相過寂寞濱，心如符券迹參辰。',64,'全唐诗/poet.song.200000.json','["去歲相過寂寞濱，心如符券迹參辰。", "骨香萬死何曾腐，膝屈千生不復伸。", "哀仲行詩誰續古，補中丞傳豈無人。", "短歌雖愧招魂作，或可留傳達史臣。"]'),
('2d1c18a6-5af1-41c9-bb1f-e469da39e267','挽方揭陽內子一首','劉克莊','宋','宋诗','song-poetry','','[]','雌燕營巢切，鳴鳩愛子均。',48,'全唐诗/poet.song.200000.json','["雌燕營巢切，鳴鳩愛子均。", "荆練孟光飾，玉雪敬姜身。", "女史無其匹，宗姬有若人。", "里中多作誄，何况忝朱陳。"]'),
('d36d700e-ae6a-4919-a8d9-e093ccb36832','挽貢士方清卿','劉克莊','宋','宋诗','song-poetry','','[]','矯俗非崖異，誅姦似刻深。',48,'全唐诗/poet.song.200000.json','["矯俗非崖異，誅姦似刻深。", "世無愛才意，天有不平心。", "陋巷貧猶樂，孤墳死尚吟。", "絕憐蔚宗史，未及共研尋。"]'),
