('f94d1844-b887-47f0-ad1c-846ac4920beb','送顔□之清漳六言三首  其二','劉克莊','宋','宋诗','song-poetry','','[]','清漳古佛竺國，尚書令魯郡公。',28,'全唐诗/poet.song.200000.json','["清漳古佛竺國，尚書令魯郡公。", "始信十年夜讀，不如明月春風。"]'),
('74f413b5-748a-453c-ad8a-a370f64a748b','送顔□之清漳六言三首  其三','劉克莊','宋','宋诗','song-poetry','','[]','昔有華陽真逸，今惟員嶠老仙。',28,'全唐诗/poet.song.200000.json','["昔有華陽真逸，今惟員嶠老仙。", "懸弧小余□歲，拈花先我兩年。"]'),
('cda9071c-b054-444a-8fe9-5bac524eb52a','送魏錄事','劉克莊','宋','宋诗','song-poetry','','[]','君去民稱頌，吾州錄事廉。',48,'全唐诗/poet.song.200000.json','["君去民稱頌，吾州錄事廉。", "平心决蠻觸，恕筆讞髠鉗。", "守法仁人勇，持身處女嚴。", "城中旗榜盛，不欠惡詩拈。"]'),
('bf506a41-e966-4a9c-b8d9-b4328f1b7d31','題竹溪近藁二首  其一','劉克莊','宋','宋诗','song-poetry','','[]','□上翁新授□□，□□字字費精研。',64,'全唐诗/poet.song.200000.json','["□上翁新授□□，□□字字費精研。", "韓嬰豈敢爲□□，郭象安能□□□。", "曾是嘔心多警語，或疑枕膝有奇傳。", "溪□□僻□□□，何日真乘入剡船。"]'),
('4aac0c73-5422-45c2-9759-e0c3692ac26c','題竹溪近藁二首  其二','劉克莊','宋','宋诗','song-poetry','','[]','□□久讓□□□，□□牆低怯淺攻。',64,'全唐诗/poet.song.200000.json','["□□久讓□□□，□□牆低怯淺攻。", "白敏居常嘲杜甫，愈謙自說效盧仝。", "三千首探驪頷寶，九萬里摶鵬背風。", "欲往從之翅羽短，碧天無際海連空。"]'),
('5caea55b-16b3-45fe-af50-8f0522512bb7','平舟場□□□□□□爲郡人劉某言某有客曰玉□□□□□□一再班荆語而別余贈以二詩□□今□□有盧繩孫貢士過門余倒屣□□□□□平舟者乃其翁也','劉克莊','宋','宋诗','song-poetry','','[]','無正文。',4,'全唐诗/poet.song.200000.json','["無正文。"]'),
('8957fef1-a8fb-4328-bbfa-1dd669f1e38a','葵霍□□□□□□小詩還贄','劉克莊','宋','宋诗','song-poetry','','[]','州牧有佳客，□□□□□。',48,'全唐诗/poet.song.200000.json','["州牧有佳客，□□□□□。", "愛吟老叉句，猶記照隣文。", "□□□□□，□□□□□。", "吾無恤孤力，懷舊意空勤。"]'),
('de4c11f2-1030-42db-b2eb-b7e5761bddaa','□□□□次竹溪韵','劉克莊','宋','宋诗','song-poetry','','[]','□□□□□□□，拂塵猶認壁間題。',64,'全唐诗/poet.song.200000.json','["□□□□□□□，拂塵猶認壁間題。", "于何林叟自拾□，却遣□□□□□。", "白也新詩追鮑庾，遷之自敘本重黎。", "不知□□□□□，□在牛欄更向西。"]'),
