('1be797fc-71cb-41e2-b0f3-d699dbaff8a7','七十八咏六言十首  其九','劉克莊','宋','宋诗','song-poetry','','[]','慕赤松子辟穀，學黄冠師餐霞。',28,'全唐诗/poet.song.200000.json','["慕赤松子辟穀，學黄冠師餐霞。", "更無半空鸞鶴，何異深山龜蛇。"]'),
('9431bb3f-4cbf-47d7-9bf4-f8851207e297','七十八咏六言十首  其一○','劉克莊','宋','宋诗','song-poetry','','[]','泛愛親疎平等，任吟古律不拘。',28,'全唐诗/poet.song.200000.json','["泛愛親疎平等，任吟古律不拘。", "武公耄猶戲謔，白公老尚囁嚅。"]'),
('69dcfe82-44e5-441e-b4d0-bb67f15b2293','挽意一徐樞二首  其一','劉克莊','宋','宋诗','song-poetry','','[]','苦言玉座常追憶，堅卧蒲輪未易招。',64,'全唐诗/poet.song.200000.json','["苦言玉座常追憶，堅卧蒲輪未易招。", "昔喜鳳來韶石奏，今愁鼇去海山摇。", "覆甌望絕民無福，亡鑑悲深帝輟朝。", "欲向蟇陵瀝巵酒，荒烟衰草路迢迢。"]'),
('930c94ee-9b93-450e-86f5-5bf014b628c3','挽意一徐樞二首  其二','劉克莊','宋','宋诗','song-poetry','','[]','長公宿草幾番春，猶幸天留一潁濱。',64,'全唐诗/poet.song.200000.json','["長公宿草幾番春，猶幸天留一潁濱。", "士欲捧盤定盟主，上看折檻記忠臣。", "翟門昔有張羅歎，徐墓今無挂劍人。", "夫子雅言武公謔，尋思一一可書紳。"]'),
('367629ef-f8fe-42c2-8685-2b8a938a37c1','答王與立上舍','劉克莊','宋','宋诗','song-poetry','','[]','漢唐科目各招延，中者端如拾芥然。',64,'全唐诗/poet.song.200000.json','["漢唐科目各招延，中者端如拾芥然。", "明水賦曾拘八韵，大廷策亦限三篇。", "竊窺古調諧軒律，留取高吟和舜絃。", "聖代作人添舍法，祝君走馬止三年。"]'),
('0863ded1-eab3-405d-9847-b572b4b20ffa','答林祖武','劉克莊','宋','宋诗','song-poetry','','[]','向來思鈍費冥搜，不覺呻吟到白頭。',64,'全唐诗/poet.song.200000.json','["向來思鈍費冥搜，不覺呻吟到白頭。", "曾與迺翁分雪案，今看吾子突烟樓。", "晚多借月留雲作，却悔升天入海求。", "大有英才被詩賺，豈如黄冊取公侯。"]'),
('8fbc1819-74dd-46ae-8330-a309f7996ac4','春寒一首','劉克莊','宋','宋诗','song-poetry','','[]','撥盡寒灰轉凜然，拋書數息煖丹田。',64,'全唐诗/poet.song.200000.json','["撥盡寒灰轉凜然，拋書數息煖丹田。", "蛩吟近作勝前作，鯨吸今年減去年。", "薄粥聊糊魯公口，重裘猶聳孟生肩。", "幾時風日妍和了，亂插山花藉草眠。"]'),
('78189ed3-2884-43c6-8e13-2d389848face','挽陳檢□一首','劉克莊','宋','宋诗','song-poetry','','[]','坊表猶元老，郊恩自復齋。',48,'全唐诗/poet.song.200000.json','["坊表猶元老，郊恩自復齋。", "美材淹選部，拙宦忤銘臺。", "尚意冰銜改，安知玉樹埋。", "吾衰阻臨穴，挽友想餘哀。"]'),
('783c58d3-b599-4f01-bea9-2d2cf1953d39','首春九日壽溪三絕  其一','劉克莊','宋','宋诗','song-poetry','','[]','隻手經營費拮据，十年栽接稍扶疏。',32,'全唐诗/poet.song.200000.json','["隻手經營費拮据，十年栽接稍扶疏。", "猶嫌檜柏純蒼翠，白白紅紅間數株。"]'),
('e5f0ef49-fc7b-4ab6-9e12-444f7089392a','首春九日壽溪三絕  其二','劉克莊','宋','宋诗','song-poetry','','[]','陶子經丘又尋壑，龐公上塚亦携家。',32,'全唐诗/poet.song.200000.json','["陶子經丘又尋壑，龐公上塚亦携家。", "可憐春事今年早，落盡桃花落杏花。"]'),
('a8f80025-f140-4644-8b7f-b389d4863280','首春九日壽溪三絕  其三','劉克莊','宋','宋诗','song-poetry','','[]','渴飲茅柴不計杯，有時跌倒在蒼苔。',32,'全唐诗/poet.song.200000.json','["渴飲茅柴不計杯，有時跌倒在蒼苔。", "松風浩蕩俄吹醒，安用龍巾拭吐哉。"]'),
('502ac209-5b49-4286-a728-a1762f9aef3a','題林文之詩卷二首  其一','劉克莊','宋','宋诗','song-poetry','','[]','叔季詞人雜雅哇，喜君詩卷美無瑕。',64,'全唐诗/poet.song.200000.json','["叔季詞人雜雅哇，喜君詩卷美無瑕。", "朋儕却走避三舍，句律斬新成一家。", "肯學小兒烹虱脛，要看大手拔鯨牙。", "村翁豈敢持衡尺，直爲癡年兩倍加。"]'),
('d3406142-9e2e-4d44-91ff-e6ebce17f3b1','題林文之詩卷二首  其二','劉克莊','宋','宋诗','song-poetry','','[]','君豪自合相推遜，吾老猶堪共切磋。',64,'全唐诗/poet.song.200000.json','["君豪自合相推遜，吾老猶堪共切磋。", "有許奇奇并怪怪，直將少少勝多多。", "風人所作葩而正，治世之音樂以和。", "他日薰絃要賡載，勿爲處士五噫歌。"]'),
('3541faad-a273-420f-8f9d-c40bf1bb2277','送歐陽上舍夢桂','劉克莊','宋','宋诗','song-poetry','','[]','許奉太夫人以往，歐迎大君子而行。',64,'全唐诗/poet.song.200000.json','["許奉太夫人以往，歐迎大君子而行。", "無慙當日四門祖，起敬同時六館生。", "反哺兒憐親老大，將雛翁喜世昇平。", "劉詩未必如韓筆，聊見臨歧折柳情。"]'),
('96c14948-20e2-4e68-a349-b4e23e4123e0','失貓一首','劉克莊','宋','宋诗','song-poetry','','[]','周遭闇室工訶夜，偃息朝簷喜曝晴。',64,'全唐诗/poet.song.200000.json','["周遭闇室工訶夜，偃息朝簷喜曝晴。", "𨁝跳似猴難攝伏，縱擒無鼠敢從橫。", "儂貪夢蝶防閑弛，汝薄魚餐去住輕。", "赤脚蒼頭俱失察，主君姑息不須驚。"]'),
('06d655f8-9ed3-4684-8b6b-4fd2d7c4d8ed','和外弟方遇立春','劉克莊','宋','宋诗','song-poetry','','[]','脫髮紛紛雪滿簪，逢春非復少年心。',64,'全唐诗/poet.song.200000.json','["脫髮紛紛雪滿簪，逢春非復少年心。", "旋分菜把來窮巷，遥憶花枝滿上林。", "寒擁絮衣看謁懶，老耽綺語業緣深。", "竹居東道風光主，乞與甘棠蔽芾陰。"]'),
('58ac1859-7fa8-4895-b2fc-609676519bd0','送海豐薛縣尉','劉克莊','宋','宋诗','song-poetry','','[]','境與潮陽接，傳聞盜已平。',48,'全唐诗/poet.song.200000.json','["境與潮陽接，傳聞盜已平。", "丁男無轉徙，弧卒有來迎。", "東作千村急，南官幾箇清。", "廉材遺訓在，努力繼家聲。"]'),
('4969f0e3-7693-47b5-836e-5f7ef4e030c0','送方善夫赴鷺洲山長二首  其一','劉克莊','宋','宋诗','song-poetry','','[]','奎畫煌煌天上來，遥知繫馬向堂階。',64,'全唐诗/poet.song.200000.json','["奎畫煌煌天上來，遥知繫馬向堂階。", "官銜怪得清如許，文館雖然冷亦佳。", "尚論鄉先宜合祀，舊傳潮學各分齋。", "未應久作諸侯客，帝有薰琴待汝諧。"]'),
('4fec1669-16bb-4ea5-8ea5-da89fb091714','送方善夫赴鷺洲山長二首  其二','劉克莊','宋','宋诗','song-poetry','','[]','柴門病後少曾開，今日人扶出郭來。',64,'全唐诗/poet.song.200000.json','["柴門病後少曾開，今日人扶出郭來。", "君奉潘輿貧亦樂，我貪漢橐老猶獃。", "明師不患無高弟，大匠何嘗有棄材。", "若見蓬仙煩問訊，掉頭一去幾時迴。"]'),
('391edb48-a79a-4aff-b9d5-453e74961ba2','老病六言十首呈竹溪  其一','劉克莊','宋','宋诗','song-poetry','','[]','賤臣通金閨歲，先帝憑玉几年。',28,'全唐诗/poet.song.200000.json','["賤臣通金閨歲，先帝憑玉几年。", "韋曲桑麻如舊，茂陵松柏參天。"]'),
('1c6d8946-0a90-4da7-b9a9-6cf5719b5469','老病六言十首呈竹溪  其二','劉克莊','宋','宋诗','song-poetry','','[]','恰則垂髫兩髧，俄然攬鏡千絲。',28,'全唐诗/poet.song.200000.json','["恰則垂髫兩髧，俄然攬鏡千絲。", "昧老聃守黑義，動墨子染白悲。"]'),
('e342aa6d-0e51-437b-a9ed-1ffebf354360','老病六言十首呈竹溪  其三','劉克莊','宋','宋诗','song-poetry','','[]','昔似子期善聽，今如祈父不聰。',28,'全唐诗/poet.song.200000.json','["昔似子期善聽，今如祈父不聰。", "怕有學人問話，向道老僧害聾。"]'),
