('8e20f920-601b-48fc-9e0b-6bf10f4363ad','紀游十首  其四','劉克莊','宋','宋诗','song-poetry','','[]','二客如龍虎，同登蟹井顛。',24,'全唐诗/poet.song.200000.json','["二客如龍虎，同登蟹井顛。", "吾今成聱叟，渠久作飛仙。"]'),
('d4eea81e-85ef-41cc-9095-7fd3f62efc91','紀游十首  其五','劉克莊','宋','宋诗','song-poetry','','[]','北郭西郊外，聯鞍共探春。',24,'全唐诗/poet.song.201000.json','["北郭西郊外，聯鞍共探春。", "惟應舊猿鳥，猶記兩詩人。"]'),
('61dcf459-02ac-4578-88a2-7343874fb0d2','紀游十首  其六','劉克莊','宋','宋诗','song-poetry','','[]','篋有亡友詩，愈久愈鮮健。',24,'全唐诗/poet.song.201000.json','["篋有亡友詩，愈久愈鮮健。", "不歸芙蓉城，定返靈芝殿。"]'),
('2e1200c2-8fac-4588-bd5b-4ad0b9988583','紀游十首  其七','劉克莊','宋','宋诗','song-poetry','','[]','照眼園花發，傷心墓草陳。',24,'全唐诗/poet.song.201000.json','["照眼園花發，傷心墓草陳。", "君謨兩字謚，迂叟九分人。"]'),
('09afd3c5-9017-434b-9b04-549db8ee0c9a','紀游十首  其八','劉克莊','宋','宋诗','song-poetry','','[]','軒豁百觚量，昂藏九尺身。',24,'全唐诗/poet.song.201000.json','["軒豁百觚量，昂藏九尺身。", "如何天奪盡，真率社中人。"]'),
('a6eacb2b-14a7-4778-ad7e-3e0c4275b9fc','紀游十首  其九','劉克莊','宋','宋诗','song-poetry','','[]','自爲遺老傳，或入少年叢。',24,'全唐诗/poet.song.201000.json','["自爲遺老傳，或入少年叢。", "我已無同輩，誰能起此翁。"]'),
('b6b8a01b-253a-4411-b8a9-9b27f7a0c5c1','紀游十首  其一○','劉克莊','宋','宋诗','song-poetry','','[]','由晉以至唐，幾人作文字。',24,'全唐诗/poet.song.201000.json','["由晉以至唐，幾人作文字。", "前有酒德頌，後惟醉鄉記。"]'),
('117751ed-0f77-4bca-b18b-763099faa1b2','和徐常丞洪秘監倡和四首  其一','劉克莊','宋','宋诗','song-poetry','','[]','一著能回一局輸，安危豈不繫茲儒。',64,'全唐诗/poet.song.201000.json','["一著能回一局輸，安危豈不繫茲儒。", "樂卿昔去曾入海，老監今歸但乞湖。", "阮子杖挑聊共出，麻姑榼送不煩沽。", "二仙占斷壺中景，不許長房跳入壺。"]'),
('d0487530-a72d-45f9-b696-7fec3018d074','和徐常丞洪秘監倡和四首  其二','劉克莊','宋','宋诗','song-poetry','','[]','紛紛博局迭贏輸，孰是真儒孰盜儒。',64,'全唐诗/poet.song.201000.json','["紛紛博局迭贏輸，孰是真儒孰盜儒。", "履道宅佳多輦石，輞川亭巧恰臨湖。", "可無詩喚劉郎和，偶有錢同鄭老沽。", "却笑吳兒拚命者，潮頭如屋靠腰壺。"]'),
('18293d46-e24b-49e7-b585-d30d4462309a','和徐常丞洪秘監倡和四首  其三','劉克莊','宋','宋诗','song-poetry','','[]','孤忠鬰積未全輸，臧氏其如命世儒。',64,'全唐诗/poet.song.201000.json','["孤忠鬰積未全輸，臧氏其如命世儒。", "歸治隠棲秦系里，去留遺愛葛仙湖。", "一辭吾已抽身退，什襲公非待價沽。", "大手會當摛玉檢，窶人只合傳冰壺。"]'),
('4eb512db-6464-4454-9517-bbb0870bb62c','和徐常丞洪秘監倡和四首  其四','劉克莊','宋','宋诗','song-poetry','','[]','公詩妙巧過般輸，蚓竅何堪和大儒。',64,'全唐诗/poet.song.201000.json','["公詩妙巧過般輸，蚓竅何堪和大儒。", "豈敢分庭掣鯨海，頗思越邑會鵝湖。", "薰蕕年老迷香臭，酒脯涎垂向市沽。", "病起带圍渾減盡，免教人誚腹如壺。"]'),
('05bd9dbc-e32c-46c3-ba8f-c03514680dcd','又四首  其一','劉克莊','宋','宋诗','song-poetry','','["\u592a\u6e56"]','咄咄清流久灌輸，帝虛館殿待名儒。',64,'全唐诗/poet.song.201000.json','["咄咄清流久灌輸，帝虛館殿待名儒。", "縱□□□□□嶺，未抵鴟夷泛太湖。", "青史方將觀晚節，黄封尚可易村沽。", "書言耳重知君意，怕聽朝雞與漏壺。"]'),
('93d8434d-08c2-4f76-b037-b8d2c6ad59ef','又四首  其二','劉克莊','宋','宋诗','song-poetry','','[]','已藁忠言未及輸，豈知窮鬼迫臞儒。',64,'全唐诗/poet.song.201000.json','["已藁忠言未及輸，豈知窮鬼迫臞儒。", "諸生蕝就漢朝野，一束芻留孺子湖。", "室有瓶儲聊自給，帘夸椀□□人沽。", "風濤如此行何適，猶幸中流得一壺。"]'),
('cd7c77a5-1e02-4454-a895-f142b46aa4e0','又四首  其三','劉克莊','宋','宋诗','song-poetry','','[]','薄收僅足了冬輸，晚覺明農勝業儒。',64,'全唐诗/poet.song.201000.json','["薄收僅足了冬輸，晚覺明農勝業儒。", "稍喜塵清如□峒，更祈田熟似蘇湖。", "小船楊柳陰中泊，大斗杏花深處沽。", "游野歸來天欲雨，雲邊玉女屢投壺。"]'),
('6d8a7973-dbd4-4688-a818-12e96377d081','又四首  其四','劉克莊','宋','宋诗','song-poetry','','[]','幸無再榷與三輸，得半猶堪活窶儒。',64,'全唐诗/poet.song.201000.json','["幸無再榷與三輸，得半猶堪活窶儒。", "寧揖劉郎歸釣瀨，肯于孟守覓崲湖。", "杯中興至休辭飲，膜外名虛不必沽。", "晨出作勞宵穩睡，管他布穀更提壺。"]'),
('51b3f3ac-7276-4060-8f30-63c351bc6b07','贈碧眼相士六言二首  其一','劉克莊','宋','宋诗','song-poetry','','[]','耳白無蓋世名，眼碧有奇中語。',28,'全唐诗/poet.song.201000.json','["耳白無蓋世名，眼碧有奇中語。", "老夫定非醉翁，斯人莫是初祖。"]'),
('29a9f63d-5833-4a59-8f89-9c837abb2afd','贈碧眼相士六言二首  其二','劉克莊','宋','宋诗','song-poetry','','[]','荀卿子論心形，許負書說氣色。',28,'全唐诗/poet.song.201000.json','["荀卿子論心形，許負書說氣色。", "我雖□□□□，□□看未成碧。"]'),
('56803ce7-54a8-437a-a736-a3f9d6f3701b','檢校樗庵花木二首  其一','劉克莊','宋','宋诗','song-poetry','','[]','我與茲山殆有緣，手栽一一已參天。',64,'全唐诗/poet.song.201000.json','["我與茲山殆有緣，手栽一一已參天。", "主林神黠□□佛，老樹精乖意是仙。", "留客看花聊席地，課僮種樹頻澆泉。", "丹成未可匆匆喫，且向溪邊住十年。"]'),
('622154cf-a6df-4299-b5bb-dc0546a17c84','檢校樗庵花木二首  其二','劉克莊','宋','宋诗','song-poetry','','[]','林密山深客少過，暮年杖履此婆娑。',64,'全唐诗/poet.song.201000.json','["林密山深客少過，暮年杖履此婆娑。", "桂開香□□□窟，檜長高於窣堵坡。", "不記玄暉紅芍藥，且栽□□□蓑荷。", "聖丘未必知爲圃，何似姑師郭橐駝。"]'),
('c555a96d-8821-42b8-8e1a-e3d5696fd671','送龍岩林主學','劉克莊','宋','宋诗','song-poetry','','[]','官冷君行勿鄙夷，儒風未有盛斯時。',64,'全唐诗/poet.song.201000.json','["官冷君行勿鄙夷，儒風未有盛斯時。", "進青衿子陳新義，爲紫陽公廣舊規。", "然否聽人來議政，尊嚴無士敢嘲師。", "虀鹽堪飽芹堪采，况值文翁適擁麾。"]'),
('ce7e3f1e-c997-45b1-a87e-b4dc4a06e3ea','北苑一首  其一','劉克莊','宋','宋诗','song-poetry','','[]','舂汲常分任，巾篝久服勤。',24,'全唐诗/poet.song.201000.json','["舂汲常分任，巾篝久服勤。", "汝何慙絡秀，吾自誌朝雲。"]'),
('d70f2829-5e27-4aab-968d-122ddbabb594','北苑一首  其二','劉克莊','宋','宋诗','song-poetry','','[]','客送西州路，兒封北苑墳。',24,'全唐诗/poet.song.201000.json','["客送西州路，兒封北苑墳。", "凄凉蒿里挽，未必九泉聞。"]'),
('4b1bb3e9-cb83-4deb-b4e2-7f0cbadfd867','即事  其一','劉克莊','宋','宋诗','song-poetry','','[]','醫書攻百病，惟有老難醫。',24,'全唐诗/poet.song.201000.json','["醫書攻百病，惟有老難醫。", "霧眼朱成碧，霜顛涅不緇。"]'),
('02b872fe-9b58-49cc-8725-87eb274d1770','即事  其二','劉克莊','宋','宋诗','song-poetry','','[]','炎凉蒼狗變，光景白駒馳。',24,'全唐诗/poet.song.201000.json','["炎凉蒼狗變，光景白駒馳。", "忽見鏡中者，驚詢汝是誰。"]'),
('d9407d99-bb19-409a-9171-93e4d7cba176','暮春一首','劉克莊','宋','宋诗','song-poetry','','[]','謝館王亭安在哉，荒村亦自有池臺。',64,'全唐诗/poet.song.201000.json','["謝館王亭安在哉，荒村亦自有池臺。", "苦嫌野蔓縈紆竹，甚愛殘花點綴苔。", "老送病來推不得，歡隨春去挽難回。", "未應寂寞無心賞，牆下葵榴次第開。"]'),
('f416db3e-9b8f-4c48-a5d2-ef953722d5b2','漫興一首','劉克莊','宋','宋诗','song-poetry','','[]','經行中野多新塚，檢點高陽少酒徒。',64,'全唐诗/poet.song.201000.json','["經行中野多新塚，檢點高陽少酒徒。", "縱不能陪雍畤禮，尚堪添入洛英圖。", "愛東臯子生沉醉，慕北山公死謚愚。", "頼有小詩自陶寫，何須著論學王符。"]'),
('656cc623-05ac-4310-a4fe-7f971cb8a537','安溪黄明府得子次徐常丞韻一首','劉克莊','宋','宋诗','song-poetry','','[]','宰公心印佛心慈，吉兆前知抱送期。',64,'全唐诗/poet.song.201000.json','["宰公心印佛心慈，吉兆前知抱送期。", "喜溢親闈占鸑鷟，來從帝所下騎麒。", "芝蘭庭戶芽初茁，荼堇原田味變飴。", "加我數年渠稍長，要看丱角出吟詩。"]'),
('f575f129-8e29-4b00-aa7f-79e79a0c63ab','錦湖新亭告成宸翰大書水村二字以落之二詩輒附賀客之後  其一','劉克莊','宋','宋诗','song-poetry','','[]','暫辭玉笋眷猶濃，朝野皆知不世逢。',64,'全唐诗/poet.song.201000.json','["暫辭玉笋眷猶濃，朝野皆知不世逢。", "賀老曾求湖一曲，希夷亦乞華三峰。", "鳳銜奎墨飛華扁，虎拜觚稜折御封。", "帝以此翁深易學，除官壹似鄭司農。"]'),
('eb0b510f-3a42-4bf7-9161-618fa284bae1','錦湖新亭告成宸翰大書水村二字以落之二詩輒附賀客之後  其二','劉克莊','宋','宋诗','song-poetry','','[]','自說秋毫盡帝恩，煌煌曦畫照乾坤。',64,'全唐诗/poet.song.201000.json','["自說秋毫盡帝恩，煌煌曦畫照乾坤。", "偶留佳客常投轄，怕礙游人不設門。", "枕麯先生傳醉種，詠梅處士有詩孫。", "何須更羨東西陝，君管南村我北村。"]'),
('5e2cd374-8f7b-4a0d-a0a7-edf4040e1171','二和  其一','劉克莊','宋','宋诗','song-poetry','','[]','主人卜晝衆懽濃，今孟嘗君豈易逢。',64,'全唐诗/poet.song.201000.json','["主人卜晝衆懽濃，今孟嘗君豈易逢。", "漲水已堪航別港，宿雲何必帽前峰。", "三千客各聞風至，一曲湖勝裂地封。", "小試此翁開濟手，不妨行樂不妨農。"]'),
('d1329fc0-515e-4bc0-9a3a-52538524db4e','二和  其二','劉克莊','宋','宋诗','song-poetry','','[]','四傍山色青環郭，八面波光練抹坤。',64,'全唐诗/poet.song.201000.json','["四傍山色青環郭，八面波光練抹坤。", "天造居然成別墅，帝招未肯入修門。", "愛蓮豈欲希周子，起蕝終難滯叔孫。", "介甫爭墩人已笑，老夫安敢又爭村。"]'),
('810f2dde-6d54-4140-a7f3-608f8225cdd7','三和  其一','劉克莊','宋','宋诗','song-poetry','','[]','野色湖光淡復濃，阿香神爻巧相逢。',64,'全唐诗/poet.song.201000.json','["野色湖光淡復濃，阿香神爻巧相逢。", "金篦莫辨烟中樹，蠟屐難登海上峰。", "帝眷驛馳丹詔問，客歸亭有白雲封。", "邊無牧馬村無犬，擊壤何妨作老農。"]'),
('66831985-e671-40f7-87ca-f064510e7d18','三和  其二','劉克莊','宋','宋诗','song-poetry','','[]','擊磬何須入於海，括囊未免取諸坤。',64,'全唐诗/poet.song.201000.json','["擊磬何須入於海，括囊未免取諸坤。", "尋盟今已白鷗社，待詔昔曾金馬門。", "魚戲罕逢同隊子，雞窠會見二毛孫。", "兩翁未易分優劣，一樂山村一水村。"]'),
('73b34f9d-57f9-4cce-a31e-962b40a9bd72','四和  其一','劉克莊','宋','宋诗','song-poetry','','[]','鯨吸仙人飲興濃，尤嫌惡客懶迎逢。',64,'全唐诗/poet.song.201000.json','["鯨吸仙人飲興濃，尤嫌惡客懶迎逢。", "逆風弱水三萬里，夢雨高唐十二峰。", "詩派相邀容入社，酒泉雖遠願移封。", "葑田畢竟勝高仰，猶可躬耕佐大農。"]'),
('c3650153-1b1c-463c-9870-d92c5a0ef7c0','四和  其二','劉克莊','宋','宋诗','song-poetry','','[]','臨淵細味心亨坎，卜築先占地勢坤。',64,'全唐诗/poet.song.201000.json','["臨淵細味心亨坎，卜築先占地勢坤。", "說易何妨遇于野，談玄亦入妙之門。", "賜金莫惜娛賓客，堆笏猶堪遺子孫。", "不比酸寒杜陵老，破茅草屋傍江村。"]'),
('e6a23473-4b52-444e-ba63-383c4cb747e4','五和  其一','劉克莊','宋','宋诗','song-poetry','','[]','霧掃山如潑黛濃，一開口笑古難逢。',64,'全唐诗/poet.song.201000.json','["霧掃山如潑黛濃，一開口笑古難逢。", "斬新種柳輞川水，火急移蓮玉井峰。", "甚愛名花當輦致，遠求佳果莫函封。", "人生惟有田園樂，未可輕將仕易農。"]'),
('6682e9c5-9ca4-4be4-8f49-753636706492','五和  其二','劉克莊','宋','宋诗','song-poetry','','[]','江湖浩渺常存闕，雲漢昭回妙闡坤。',64,'全唐诗/poet.song.201000.json','["江湖浩渺常存闕，雲漢昭回妙闡坤。", "妓或携來安石墅，客誰畔去翟公門。", "戴花老豈非同姓，拾穗翁猶有遠孫。", "殺馬毀車吾耄矣，尚堪扶杖過鄰村。"]'),
('fe7f82f7-81d4-4ab7-8f11-b0db28be2f1d','席間次水村主人韵','劉克莊','宋','宋诗','song-poetry','','[]','遊人似蟻磨邊旋，驚怪壺中有別天。',64,'全唐诗/poet.song.201000.json','["遊人似蟻磨邊旋，驚怪壺中有別天。", "鐵畫誰如奎畫妙，錦湖賽過鑑湖賢。", "懸知星照嚴光瀨，不管江通魯望田。", "昭代未應無狗監，誦公新作冕旒前。"]'),
('fc0dea05-add4-47bd-a9f3-59c16dee7a10','挽鄭計院','劉克莊','宋','宋诗','song-poetry','','[]','方與譽髦連茹進，忽然避弋下喬來。',64,'全唐诗/poet.song.201000.json','["方與譽髦連茹進，忽然避弋下喬來。", "空令歸訪盟鷗社，不使重登市駿臺。", "古有孟嘗能好客，今無鮑叔肯分財。", "吾衰難秉銘幽筆，短些凄凉不盡哀。"]'),
('34758870-3b60-4f8f-9e4b-489bbd21871b','答林文之','劉克莊','宋','宋诗','song-poetry','','[]','筆勢翩翩漸入佳，晨簷怪得鵲查查。',64,'全唐诗/poet.song.201000.json','["筆勢翩翩漸入佳，晨簷怪得鵲查查。", "勞謙君子方求益，老禿中書不夢花。", "商頌以前殊簡短，衛風而下稍淫哇。", "鶴天鯨海無邊際，莫費工夫納百家。"]'),
('aeb5c6f5-2b21-415d-8e99-f1996ed079bb','盜發蔡端明墓一首和竹溪韵','劉克莊','宋','宋诗','song-poetry','','[]','忠惠松楸過者欽，誰知藏伏禍機深。',64,'全唐诗/poet.song.201000.json','["忠惠松楸過者欽，誰知藏伏禍機深。", "英魂久向茲埋玉，佛面今爲汝削金。", "下馬三號空抆淚，磔蟇萬段亦甘心。", "邇來野外無全塚，謾使閑人憤滿襟。"]'),
('75e576f3-a0e6-40af-a4a5-355b948caca9','又盜棄端硯一首','劉克莊','宋','宋诗','song-poetry','','[]','□衣孔履世猶欽，此硯隨公歲月深。',64,'全唐诗/poet.song.201000.json','["□衣孔履世猶欽，此硯隨公歲月深。", "璞美止緣鸜眼□，價高不數褭蹄金。", "虬髯尚破偷兒膽，麟筆曾誅賊子心。", "今代安知無雋尹，傳經决獄肯披襟。"]'),
('0d94ff37-fd54-4276-bf39-64666497c912','送方漳浦','劉克莊','宋','宋诗','song-poetry','','[]','頗聞送者詩盈軸，我有樵歌子試聽。',64,'全唐诗/poet.song.201000.json','["頗聞送者詩盈軸，我有樵歌子試聽。", "岩邑雖然人所畏，畬民均是物之靈。", "二升飯了官中事，一字廉真座右銘。", "見說守侯如召杜，斷無走吏至公庭。"]'),
('461e0f1b-4f3a-4e04-b2a0-f332d329c257','和林太淵二首  其一','劉克莊','宋','宋诗','song-poetry','','[]','端人舌本鈍如槌，自畫村眉不入時。',64,'全唐诗/poet.song.201000.json','["端人舌本鈍如槌，自畫村眉不入時。", "門巷張羅賓客少，車輪生角僕夫悲。", "共游洛下凋零盡，末向巖頭付囑誰。", "爲吾子師余豈敢，伊家元有大宗師。"]'),
('3be58da8-2003-4d0e-9dad-c43147e1dd00','和林太淵二首  其二','劉克莊','宋','宋诗','song-poetry','','[]','聲稱籍甚自髫年，聖處聞之於膝邊。',64,'全唐诗/poet.song.201000.json','["聲稱籍甚自髫年，聖處聞之於膝邊。", "廟瑟久無人續響，國棋誰與子分先。", "書經秦火訛難讀，鉢至曹溪靳不傳。", "功行滿時笙鶴下，未應山澤著臞仙。"]'),
('9c352459-0f0f-4cb6-b5c7-dc8ae801db51','禋霈進封一首','劉克莊','宋','宋诗','song-poetry','','[]','忽得中都訊，綸言下玉墀。',48,'全唐诗/poet.song.201000.json','["忽得中都訊，綸言下玉墀。", "名爲開國子，實類出家兒。", "不記操麻卷，猶堪譜荔枝。", "吾方抽手扳，穀璧欲安施。"]'),
('9014ad34-837a-40a8-b97c-cb61077b3856','目疾一首','劉克莊','宋','宋诗','song-poetry','','[]','疾起自肝家，眵昏認物差。',48,'全唐诗/poet.song.201000.json','["疾起自肝家，眵昏認物差。", "昔如虹貫日，今隔霧看花。", "暝鵲驚飛匝，凉蟾瞥露些。", "廟堂見章奏，應笑字欹斜。"]'),
('59afb0ec-d15a-4bd1-bb6c-a339d4a3cb77','送游潮州二首  其一','劉克莊','宋','宋诗','song-poetry','','[]','霜簡剛言璧有瑕，清朝耳目不應差。',64,'全唐诗/poet.song.201000.json','["霜簡剛言璧有瑕，清朝耳目不應差。", "醉翁絕少環滁飲，范老何心慶朔花。", "省庫錢皆留享士，高齋琴却带還家。", "邵平舊圃元無恙，未必封侯勝種瓜。"]'),
('ec4d5a70-19a1-4eae-8b91-d1e70953dbc2','送游潮州二首  其二','劉克莊','宋','宋诗','song-poetry','','[]','雖森畫戟惟清嘯，因討紅巾有雪髯。',64,'全唐诗/poet.song.201000.json','["雖森畫戟惟清嘯，因討紅巾有雪髯。", "孟子曾稱伯夷隘，漢人亦議弱翁嚴。", "交游皆嘆遺公誤，仇怨猶言太守廉。", "可惜遒人官久廢，此詩湮鬰在閭閻。"]'),
('666bf460-b990-416e-8558-39c8e7963e34','左目痛六言九首  其一','劉克莊','宋','宋诗','song-poetry','','[]','深碧非少林祖，暴赤疑歸宗僧。',28,'全唐诗/poet.song.201000.json','["深碧非少林祖，暴赤疑歸宗僧。", "何須近青藜杖，不願如紫石稜。"]'),
('6618b716-3485-49df-9a25-0b6ecc455034','左目痛六言九首  其二','劉克莊','宋','宋诗','song-poetry','','[]','親燈似鴟撮蚤，對卷如獺祭魚。',28,'全唐诗/poet.song.201000.json','["親燈似鴟撮蚤，對卷如獺祭魚。", "今已作白頭觀，昔曾校黄本書。"]'),
('f6262b2b-4d24-4369-a6ad-6d8a002bc6fc','左目痛六言九首  其三','劉克莊','宋','宋诗','song-poetry','','[]','詩到歌行尤妙，傳與國語并行。',28,'全唐诗/poet.song.201000.json','["詩到歌行尤妙，傳與國語并行。", "艱辛張籍病瞎，浮誇左丘失明。"]'),
('2ea7debf-a736-4a08-98ec-44ef136722e3','左目痛六言九首  其四','劉克莊','宋','宋诗','song-poetry','','[]','昏花廢干祿書，麻嗏類辟瘟符。',28,'全唐诗/poet.song.201000.json','["昏花廢干祿書，麻嗏類辟瘟符。", "草字見嗤醉禿，小楷難付官奴。"]'),
('aa148125-4779-4242-8b3a-e691d6c3dc55','左目痛六言九首  其五','劉克莊','宋','宋诗','song-poetry','','[]','晚歲甘爲瞽史，前身不是離婁。',28,'全唐诗/poet.song.201000.json','["晚歲甘爲瞽史，前身不是離婁。", "喜梵夾書送老，惡巾箱本如雔。"]'),
('0142e2a7-3934-4e60-8a0c-cdb8187e98b1','左目痛六言九首  其六','劉克莊','宋','宋诗','song-poetry','','[]','儒醫診肝脈去，小童負藥笈從。',28,'全唐诗/poet.song.201000.json','["儒醫診肝脈去，小童負藥笈從。", "吾寧作一目鬼，古曾有獨眼龍。"]'),
