('0c59e93a-1f2a-48e6-8ec8-7ab93c7fbc0a','左目痛六言九首  其八','劉克莊','宋','宋诗','song-poetry','','[]','早耽蔡譜華妙，晚受聃書深長。',28,'全唐诗/poet.song.201000.json','["早耽蔡譜華妙，晚受聃書深長。", "始悟擘紅異味，不如守黑單方。"]'),
('8f16ab4a-3259-426e-9044-2f203a88bf22','左目痛六言九首  其九','劉克莊','宋','宋诗','song-poetry','','[]','閣上束三千卷，牆角棄二尺檠。',28,'全唐诗/poet.song.201000.json','["閣上束三千卷，牆角棄二尺檠。", "此玉函方不載，無金篦刮亦明。"]'),
('74fa3afc-46dd-4e77-9686-33882eb199b5','後九首  其一','劉克莊','宋','宋诗','song-poetry','','[]','弘景疏已上矣，天子書久無之。',28,'全唐诗/poet.song.201000.json','["弘景疏已上矣，天子書久無之。", "怕騎瞎馬浪出，安用明駝疾馳。"]'),
('fa2a899b-ca9f-419d-b5cc-7973b8f54741','後九首  其二','劉克莊','宋','宋诗','song-poetry','','[]','經來葱嶺絕域，書出汲縣古冢。',28,'全唐诗/poet.song.201000.json','["經來葱嶺絕域，書出汲縣古冢。", "饒君一目十行，如彼千瘡百孔。"]'),
('14645097-e110-4baf-a035-dd32c1308e62','後九首  其三','劉克莊','宋','宋诗','song-poetry','','[]','痛定偶成短夢，驚迴如近清光。',28,'全唐诗/poet.song.201000.json','["痛定偶成短夢，驚迴如近清光。", "黄帕牙篦開卷，絳紗玉斧照廊。"]'),
('b1981316-6842-43bc-852d-2fdad3d346ea','後九首  其四','劉克莊','宋','宋诗','song-poetry','','[]','夜眠便甘菊枕，晨起避凌霄露。',28,'全唐诗/poet.song.201000.json','["夜眠便甘菊枕，晨起避凌霄露。", "信爾雅幾委頓，註本草不宜誤。"]'),
('b7b06e3b-f032-4f43-9efe-710c3a0bd8a9','後九首  其五','劉克莊','宋','宋诗','song-poetry','','[]','力疾搜腸草制，忍痛撚髭改詩。',28,'全唐诗/poet.song.201000.json','["力疾搜腸草制，忍痛撚髭改詩。", "鐵燈檠我同好，金蓮炬彼一時。"]'),
('e18c47a4-773c-42bd-a1ee-bcaf7f2a5a59','後九首  其六','劉克莊','宋','宋诗','song-poetry','','[]','默默回光反照，津津勿藥有喜。',28,'全唐诗/poet.song.201000.json','["默默回光反照，津津勿藥有喜。", "八荒入吾闥中，四海在我牆裏。"]'),
('5f2b8768-bbae-4af7-a0c6-0f5886fd57e6','後九首  其七','劉克莊','宋','宋诗','song-poetry','','[]','坐井成小眼孔，面壁得大醫王。',28,'全唐诗/poet.song.201000.json','["坐井成小眼孔，面壁得大醫王。", "凈洗三生熱惱，不煩一服清凉。"]'),
('ff48e586-ad23-46ba-8997-e582fba418ca','後九首  其八','劉克莊','宋','宋诗','song-poetry','','[]','老去具一隻眼，向來隔幾重膜。',28,'全唐诗/poet.song.201000.json','["老去具一隻眼，向來隔幾重膜。", "盡見夫子宗廟，遍觀彌勒樓閣。"]'),
('a99330a8-f3aa-4d3c-86df-d450fb852872','後九首  其九','劉克莊','宋','宋诗','song-poetry','','[]','吾今垂老示疾，君昔與人作緣。',28,'全唐诗/poet.song.201000.json','["吾今垂老示疾，君昔與人作緣。", "尚能續華佗傳，何敢負宋清錢。"]'),
('50a73419-cfb0-416c-830a-e1eeb2e7ef3c','陳佐藏之溫陵','劉克莊','宋','宋诗','song-poetry','','[]','蔚鬰相門望，新書在所銜。',48,'全唐诗/poet.song.201000.json','["蔚鬰相門望，新書在所銜。", "昔隨翁出宰，今見子封男。", "大錄鶩行至，遺民馬首參。", "擊鮮良不惡，何日返槐庵。"]'),
('0d30b36c-5081-4672-8c11-9057ef5320d8','陳郎玉汝之官','劉克莊','宋','宋诗','song-poetry','','[]','擇地喜將父，戴星勤坐曹。',48,'全唐诗/poet.song.201000.json','["擇地喜將父，戴星勤坐曹。", "阿奴已傷錦，君子好更□。", "大尹徵求寡，先賢撫字勞。", "直須琴調古，莫倚棒頭高。"]'),
('88ccb24b-94f4-4e24-bca8-ac9178ef3546','目痛一月未愈自和前九首  其一','劉克莊','宋','宋诗','song-poetry','','[]','開之則新生犢，閉之則入定僧。',28,'全唐诗/poet.song.201000.json','["開之則新生犢，閉之則入定僧。", "有時起瞻斗極，有時遥望觚稜。"]'),
('b32114cc-da36-4892-9727-258da975094c','目痛一月未愈自和前九首  其二','劉克莊','宋','宋诗','song-poetry','','[]','悔名草木鳥獸，住校亥豕魯魚。',28,'全唐诗/poet.song.201000.json','["悔名草木鳥獸，住校亥豕魯魚。", "識字惹客問字，懶書怕人索書。"]'),
('84e2e9ed-fc6c-4af5-8c5c-573662d2429c','目痛一月未愈自和前九首  其三','劉克莊','宋','宋诗','song-poetry','','[]','隘矣匹夫疾視，鄙哉主父倒行。',28,'全唐诗/poet.song.201000.json','["隘矣匹夫疾視，鄙哉主父倒行。", "止酒看花濺淚，吹燈見月羞明。"]'),
('3bd20549-7418-4b5c-8894-41893da159f5','目痛一月未愈自和前九首  其四','劉克莊','宋','宋诗','song-poetry','','[]','無復燃藜照向，徒以親燈觀符。',28,'全唐诗/poet.song.201000.json','["無復燃藜照向，徒以親燈觀符。", "掩卷嫌收穢史，絕纓罵玄老奴。"]'),
('9da3725d-8c23-4291-96ff-036f0380abe6','目痛一月未愈自和前九首  其五','劉克莊','宋','宋诗','song-poetry','','[]','鬚眉似是綺皓，耳目已非曠婁。',28,'全唐诗/poet.song.201000.json','["鬚眉似是綺皓，耳目已非曠婁。", "受明上座頂禮，視彼老公血讐。"]'),
('7bfb57ec-e97d-4e12-921f-112b9aec78b5','目痛一月未愈自和前九首  其六','劉克莊','宋','宋诗','song-poetry','','[]','耄及歲不我與，眼空吾誰適從。',28,'全唐诗/poet.song.201000.json','["耄及歲不我與，眼空吾誰適從。", "蒙叟達觀鵬鷃，子雲自視蛇龍。"]'),
('427abcd3-71db-4386-81fb-d419ac125634','目痛一月未愈自和前九首  其七','劉克莊','宋','宋诗','song-poetry','','[]','靜中面壁打坐，倦後拋書投床。',28,'全唐诗/poet.song.201000.json','["靜中面壁打坐，倦後拋書投床。", "認自家一尺棰，管渠儂萬丈光。"]'),
('02622f67-7969-4df7-a12d-966d5d0fec74','目痛一月未愈自和前九首  其八','劉克莊','宋','宋诗','song-poetry','','[]','朱顔無藥能駐，白髮緣愁許長。',28,'全唐诗/poet.song.201000.json','["朱顔無藥能駐，白髮緣愁許長。", "昏昏枉讀萬卷，蹙蹙起瞻四方。"]'),
('40075f18-8b05-432a-acfc-36d911f3842b','目痛一月未愈自和前九首  其九','劉克莊','宋','宋诗','song-poetry','','[]','乍可頻看短劍，渠肯高張長檠。',28,'全唐诗/poet.song.201000.json','["乍可頻看短劍，渠肯高張長檠。", "已與鷗盟浩蕩，都忘鵠立通明。"]'),
('aa036528-6466-41c5-8abc-3c90ae1c9b21','又和後九首  其一','劉克莊','宋','宋诗','song-poetry','','[]','覺性靈明自若，本心利欲食之。',28,'全唐诗/poet.song.201000.json','["覺性靈明自若，本心利欲食之。", "大觀如夢如幻，小視坐忘坐馳。"]'),
('1a4363ba-6179-41ff-b56a-d7234948b5a4','又和後九首  其二','劉克莊','宋','宋诗','song-poetry','','[]','學仙燒汞成灰，學書埋筆爲塚。',28,'全唐诗/poet.song.201000.json','["學仙燒汞成灰，學書埋筆爲塚。", "羨關尹喜見聃，愛希氏子瞻孔。"]'),
('ea7a696a-c8b8-41bc-8b64-b1119452e338','又和後九首  其三','劉克莊','宋','宋诗','song-poetry','','[]','寒儒頼有雪映，貧女那無績光。',28,'全唐诗/poet.song.201000.json','["寒儒頼有雪映，貧女那無績光。", "千眼今依佛閣，重瞳昔侍舜廊。"]'),
('2fd7a23a-c59b-4b88-8cc5-f1dff6563775','又和後九首  其四','劉克莊','宋','宋诗','song-poetry','','[]','康術鷹眼不化，處仲蜂目亦露。',28,'全唐诗/poet.song.201000.json','["康術鷹眼不化，處仲蜂目亦露。", "我自有觀人訣，汝勿爲相祖誤。"]'),
('27c97756-2c29-4a7d-aab8-5acb6f001432','又和後九首  其五','劉克莊','宋','宋诗','song-poetry','','[]','竹簡定隸古字，黑屏刻月蝕詩。',28,'全唐诗/poet.song.201000.json','["竹簡定隸古字，黑屏刻月蝕詩。", "嗜學心無止法，讀書眼有還時。"]'),
('85c6475a-4918-480f-9f04-60d6a1ab90fd','又和後九首  其六','劉克莊','宋','宋诗','song-poetry','','[]','入槐見蟻群聚，賦芧覺狙怒喜。',28,'全唐诗/poet.song.201000.json','["入槐見蟻群聚，賦芧覺狙怒喜。", "脫離黑暗獄中，透入光明境裏。"]'),
('d7cc9fda-f171-419b-a9f7-77c30ec2af0d','又和後九首  其七','劉克莊','宋','宋诗','song-poetry','','[]','自遣病魔病豎，不干藥上藥王。',28,'全唐诗/poet.song.201000.json','["自遣病魔病豎，不干藥上藥王。", "洗眼菊泉舊本，照懷蓉月新凉。"]'),
('2039fa8c-6723-465c-a84e-475f5cbd0e0d','又和後九首  其八','劉克莊','宋','宋诗','song-poetry','','[]','浮雲月之障礙，蒙氣日之翳膜。',28,'全唐诗/poet.song.201000.json','["浮雲月之障礙，蒙氣日之翳膜。", "已把太玄覆瓿，更將三傳束閣。"]'),
('17ed6295-70c9-4f32-9eae-649b0117cafa','又和後九首  其九','劉克莊','宋','宋诗','song-poetry','','[]','憂患長我意智，苦樂隨渠業緣。',28,'全唐诗/poet.song.201000.json','["憂患長我意智，苦樂隨渠業緣。", "貴人銀燭按樂，書生紙裹見錢。"]'),
('4cdd737b-e9ec-4496-bc14-1f18f86f87fd','送方郎唐卿漕試','劉克莊','宋','宋诗','song-poetry','','[]','翁已鞭鸞上九霄，此郎雖小亦清標。',64,'全唐诗/poet.song.201000.json','["翁已鞭鸞上九霄，此郎雖小亦清標。", "斯文尚有嫡傳在，每見能令人意消。", "身退吾難論一鶚，才高君必中雙鵰。", "漢廷急士將親策，想見諸儒避董晁。"]'),
('97ad17a3-33ed-4550-9994-a4e341d0d640','自題長短句後','劉克莊','宋','宋诗','song-poetry','','[]','春端帖子讓渠儂，別有詩餘繼變風。',64,'全唐诗/poet.song.201000.json','["春端帖子讓渠儂，別有詩餘繼變風。", "壓盡晚唐人以下，託諸小石調之中。", "蜀公喜柳歌仁廟，洛叟譏秦媟上穹。", "可惜今無同好者，樽前憶殺老花翁。"]'),
('bf403574-e2f3-410f-8206-45cf3f661f83','勉千里姪秋試六言四首  其一','劉克莊','宋','宋诗','song-poetry','','[]','而翁二子絕奇，其季虎中最怒。',28,'全唐诗/poet.song.201000.json','["而翁二子絕奇，其季虎中最怒。", "期此郎甲科郎，跨王父曾王父。"]'),
('7a91047e-8e51-4497-a5fa-e0b802397149','勉千里姪秋試六言四首  其二','劉克莊','宋','宋诗','song-poetry','','[]','童習好雕篆作，相業寓混成篇。',28,'全唐诗/poet.song.201000.json','["童習好雕篆作，相業寓混成篇。", "猶之射者百中，勉旃原夫一聯。"]'),
('00ef0a0b-738f-484d-a2a6-11334bc29b1c','勉千里姪秋試六言四首  其三','劉克莊','宋','宋诗','song-poetry','','[]','茂才異等息響，太祝齋郎比肩。',28,'全唐诗/poet.song.201000.json','["茂才異等息響，太祝齋郎比肩。", "汝伯何由漆髮，我家舊有青氈。"]'),
('e1688398-8ba3-4bf4-ad19-3007718fd561','勉千里姪秋試六言四首  其四','劉克莊','宋','宋诗','song-poetry','','[]','子心思猶盛壯，吾光陰已耋耄。',28,'全唐诗/poet.song.201000.json','["子心思猶盛壯，吾光陰已耋耄。", "不堪蝥弧先登，尚可鼓旗傍譟。"]'),
('42dfd7f4-9682-4204-87a7-6475011b124f','中秋大風雨五絕  其一','劉克莊','宋','宋诗','song-poetry','','[]','車喚阿香推，情知雨必雷。',24,'全唐诗/poet.song.201000.json','["車喚阿香推，情知雨必雷。", "不干巽二事，也伴阿姨來。"]'),
('a73ac085-d3bd-43ef-bc3f-53672e4ed88f','中秋大風雨五絕  其二','劉克莊','宋','宋诗','song-poetry','','[]','□□□□□，冰輪□□□。',24,'全唐诗/poet.song.201000.json','["□□□□□，冰輪□□□。", "□□□□妬，不管素娥愁。"]'),
('86c46678-2aaa-4462-a1b9-6234971d6083','中秋大風雨五絕  其三','劉克莊','宋','宋诗','song-poetry','','[]','好客期難至，清歡擬即差。',24,'全唐诗/poet.song.201000.json','["好客期難至，清歡擬即差。", "不逢□□鏡，何處覓金蟇。"]'),
('8ef76106-798e-4882-8491-dbd45fb3f5bc','中秋大風雨五絕  其四','劉克莊','宋','宋诗','song-poetry','','[]','詔歲銀袍盛，頭場玉鑑明。',24,'全唐诗/poet.song.201000.json','["詔歲銀袍盛，頭場玉鑑明。", "妃靈如有助，娥老尚多情。"]'),
('45b09a94-e5d7-4f04-8904-8508fe07c3fb','中秋大風雨五絕  其五','劉克莊','宋','宋诗','song-poetry','','[]','眥血滴耕夫，愁眉蹙賈胡。',24,'全唐诗/poet.song.201000.json','["眥血滴耕夫，愁眉蹙賈胡。", "良辰風雨至，不復田禾蘇。"]'),
('bd5ee48d-7893-41c0-823e-134696accb5b','縱筆一首','劉克莊','宋','宋诗','song-poetry','','[]','鄴下徐陳逐逝波，僅留老子尚婆娑。',64,'全唐诗/poet.song.201000.json','["鄴下徐陳逐逝波，僅留老子尚婆娑。", "吾宗世有戴花舞，大耋誰能鼓缶歌。", "松下尋常無喝道，花間隨處有行窩。", "癡人逐物迴頭少，看到棋終恐爛柯。"]'),
('94a942a1-a6e5-49d7-8dcc-5c0cd3d70754','洪秘監徐常丞有詩賀余休致次韻四首  其一','劉克莊','宋','宋诗','song-poetry','','[]','還笏何須待拖紳，世間無價是元身。',64,'全唐诗/poet.song.201000.json','["還笏何須待拖紳，世間無價是元身。", "爲梁父詠常存漢，累太玄經坐美新。", "朝露饒他夸奪子，曉星有幾典刑人。", "由來老幹禁霜雪，不問東皇探借春。"]'),
('2f571646-d8ba-480a-a8cf-5ba7fa4b2ff5','洪秘監徐常丞有詩賀余休致次韻四首  其二','劉克莊','宋','宋诗','song-poetry','','[]','玉座分明念老臣，孤忠何路更前陳。',64,'全唐诗/poet.song.201000.json','["玉座分明念老臣，孤忠何路更前陳。", "無枯樹賦如開府，有病梨篇似照鄰。", "粥鉢不愁餐哽噎，蔬盤何用膾紛綸。", "儘教巷靜門羅爵，絕勝山空塚卧麟。"]'),
('ce82d995-b407-40a3-8f44-a8230795a540','洪秘監徐常丞有詩賀余休致次韻四首  其三','劉克莊','宋','宋诗','song-poetry','','[]','既衰戒得久書紳，所得毫毛所失身。',64,'全唐诗/poet.song.201000.json','["既衰戒得久書紳，所得毫毛所失身。", "疎傳畫圖傳不朽，胡公糞土謗如新。", "古詢黄髮非無意，今繫蒼生尚有人。", "吾老而休君未可，時來徧與物爲春。"]'),
('45eaeaa7-101f-4eed-bdbd-1f2c99ecfccb','洪秘監徐常丞有詩賀余休致次韻四首  其四','劉克莊','宋','宋诗','song-poetry','','[]','好語噓枯極主臣，未應公幹勝徐陳。',64,'全唐诗/poet.song.201000.json','["好語噓枯極主臣，未應公幹勝徐陳。", "爭三十里敢言智，有百萬錢難買鄰。", "殘燭苛留終斷簡，瘦筇扶出拜新綸。", "德星若肯過田舍，只膾溪鮮代脯麟。"]'),
('42839b56-0533-4a43-bae7-6df7611a90f6','和警齋侍郎二首  其一','劉克莊','宋','宋诗','song-poetry','','[]','顔蒼鬢禿舊詞臣，幾見臺家局面新。',64,'全唐诗/poet.song.201000.json','["顔蒼鬢禿舊詞臣，幾見臺家局面新。", "栖碧山中真大隠，立紅雲畔是前身。", "魯公昔有書干祿，楊子今無賦逐貧。", "縱使未能追綺皓，絕勝賜杖給扶人。"]'),
('b194a8c1-a149-44a2-9606-e05116b6f907','和警齋侍郎二首  其二','劉克莊','宋','宋诗','song-poetry','','[]','家傳豈有枕中方，敢向堯朝議大章。',64,'全唐诗/poet.song.201000.json','["家傳豈有枕中方，敢向堯朝議大章。", "難入高賢真率社，且尋童子釣遊鄉。", "有西疇事咨衡宇，無北山移誚草堂。", "獨恨才衰詩不進，儻容摘艷更薰香。"]'),
('81cf9716-3c82-431d-b134-6e758036baec','病起十首  其一','劉克莊','宋','宋诗','song-poetry','','[]','架帙縱橫硯有埃，先生久不至山齋。',64,'全唐诗/poet.song.201000.json','["架帙縱橫硯有埃，先生久不至山齋。", "散花魔已降摩詰，裹飯人誰訪子來。", "又與杜康絕交矣，併疎毛穎少恩哉。", "幾時真得金篦力，書債重償酒禁開。"]'),
('ed6f3d27-ae67-4aac-adc7-279cb8a714ba','病起十首  其二','劉克莊','宋','宋诗','song-poetry','','[]','薄有桑麻在北溪，輜車懸了駕雞栖。',64,'全唐诗/poet.song.201000.json','["薄有桑麻在北溪，輜車懸了駕雞栖。", "專房安得莫愁妾，同穴除非法喜妻。", "羢掛屋梁聊藉草，螢穿窗隙勝然藜。", "謝公虛下聞箏淚，輸與劉伶醉似泥。"]'),
('54332ba9-4dcb-4ca5-8c59-fd57feaf7395','病起十首  其三','劉克莊','宋','宋诗','song-poetry','','[]','未縱心年乞退休，年垂八十更何求。',64,'全唐诗/poet.song.201000.json','["未縱心年乞退休，年垂八十更何求。", "相方好事下白屋，帝豈無人記玉樓。", "綬未必爲翁子福，扇安能障彥回羞。", "吾詩絕似淵明誄，莫遣他人弄筆頭。"]'),
('3c4dbc7c-ff12-45c6-b1bb-e8fbf86fc01f','病起十首  其四','劉克莊','宋','宋诗','song-poetry','','[]','亹亹清談猶可聽，星星短髮不禁搔。',64,'全唐诗/poet.song.201000.json','["亹亹清談猶可聽，星星短髮不禁搔。", "昔如八駿走千里，今似九牛亡一毛。", "吟苦都忘年事老，寢酣始悟早朝勞。", "箕山只在人間世，堯大如天未易逃。"]'),
('912d645e-0532-44cf-9046-e0dea921b203','病起十首  其五','劉克莊','宋','宋诗','song-poetry','','[]','有四宜休七不堪，豈容華皓尚癡貪。',64,'全唐诗/poet.song.201000.json','["有四宜休七不堪，豈容華皓尚癡貪。", "固難唐突耆英社，尚可追攀老學庵。", "酷嗜蟹螯聊自酌，高懸麈尾共誰談。", "吾聞多壽常多辱，伯始何須飲菊潭。"]'),
('01e82a42-e176-40ac-aefd-87f3d16f0ee1','病起十首  其六','劉克莊','宋','宋诗','song-poetry','','[]','昔與諸賢共造廷，如風吹絮浪飄萍。',64,'全唐诗/poet.song.201000.json','["昔與諸賢共造廷，如風吹絮浪飄萍。", "溘先忽忽同晨露，殿後暉暉獨曙星。", "未肯肩隨金谷友，幸留面見草堂靈。", "伯倫舊與吾通譜，欲往從之喚不醒。"]'),
('98cf86f7-f2ae-46d9-b63b-932e78c25d51','病起十首  其七','劉克莊','宋','宋诗','song-poetry','','[]','酒戶詩壇聊爾耳，也吟唧唧醉陶陶。',64,'全唐诗/poet.song.201000.json','["酒戶詩壇聊爾耳，也吟唧唧醉陶陶。", "鯨魚翡翠兼羣體，蜾蠃螟蛉視二豪。", "京洛飲徒煩借問，江湖社友謬推高。", "可憐小杜醺酣者，浪許詩人僕命騷。"]'),
('967abec7-1e6f-4ce8-a147-e0c4b98650fd','病起十首  其八','劉克莊','宋','宋诗','song-poetry','','[]','暮年字字費冥搜，少作如山棄不收。',64,'全唐诗/poet.song.201000.json','["暮年字字費冥搜，少作如山棄不收。", "作美新文生失節，留封禪草死包羞。", "懷中探錦都無幾，身後懸金未易求。", "懊恨新來剛制酒，世間何物可澆愁。"]'),
('bad337c1-6eda-40aa-9209-1739f49165d1','病起十首  其九','劉克莊','宋','宋诗','song-poetry','','[]','變風而下世無詩，幼學西崑壯恥爲。',64,'全唐诗/poet.song.201000.json','["變風而下世無詩，幼學西崑壯恥爲。", "老去僅名小家數，向來曾識大宗師。", "百年不覺皤雙鬢，一字誰能斷數髭。", "誠叟放翁幾曾死，著鞭萬一許肩隨。"]'),
('1892afda-53bc-4999-aa0e-93b8d5f380ca','病起十首  其一○','劉克莊','宋','宋诗','song-poetry','','[]','有粟二囷書數厨，一生受用小規模。',64,'全唐诗/poet.song.201000.json','["有粟二囷書數厨，一生受用小規模。", "要令後裔師吾儉，不願多財使爾愚。", "旋作續書傳福畤，偶成小楷付官奴。", "自慙未至韓公地，老語諄譫謾勸符。"]'),
('3f38c658-1391-4aa5-a123-f6eab57614cf','諸公載酒賀余休致水村農卿有詩次韻  其一','劉克莊','宋','宋诗','song-poetry','','[]','聖世鳥巢可俯窺，乞身豈必避危機。',64,'全唐诗/poet.song.201000.json','["聖世鳥巢可俯窺，乞身豈必避危機。", "牛車徑駕史儋出，麟筆曾嘉季友歸。", "迂叟相邀入真率，乖崖安肯慕輕肥。", "山林深密雲天遠，存闕心寧不可磯。"]'),
('5ac3c721-7d7f-4015-99c2-333827f284a0','諸公載酒賀余休致水村農卿有詩次韻  其二','劉克莊','宋','宋诗','song-poetry','','[]','目眚陳編懶更窺，博通似恐洩天機。',64,'全唐诗/poet.song.201000.json','["目眚陳編懶更窺，博通似恐洩天機。", "大愚苦要騎麟下，小黠猶能化鶴歸。", "覓句瘦肩兩山聳，絕糧乾嚥上池肥。", "平生慕用徐先輩，異世溪邊共一磯。"]'),
('91cf987f-489e-4aaf-8bc3-f81cd3d12ce6','諸公載酒賀余休致水村農卿有詩次韻  其三','劉克莊','宋','宋诗','song-poetry','','[]','別無穴隙可鑽窺，常恐冥行踐駭機。',64,'全唐诗/poet.song.201000.json','["別無穴隙可鑽窺，常恐冥行踐駭機。", "恰則賜環煩內引，俄然隻履已西歸。", "都忘紫禁煙花繞，絕喜青山筍蕨肥。", "應被水村翁冷笑，爭墩未了又爭磯。"]'),
('ba43b3bc-f568-4708-95cd-3327c3a19432','諸公載酒賀余休致水村農卿有詩次韻  其四','劉克莊','宋','宋诗','song-poetry','','[]','覺海難將淺見窺，打包徑去契禪機。',64,'全唐诗/poet.song.201000.json','["覺海難將淺見窺，打包徑去契禪機。", "何曾蝴蝶暫成夢，除却杜鵑誰勸歸。", "江上風濤猶洶涌，盤中泉土頗甘肥。", "自當叱犢勤耕野，不必然犀往照磯。"]'),
('51f8df3e-4d62-4b58-83e5-d2e4660e0964','諸公載酒賀余休致水村農卿有詩次韻  其五','劉克莊','宋','宋诗','song-poetry','','[]','聃書深遠絕難窺，止足書中向上機。',64,'全唐诗/poet.song.201000.json','["聃書深遠絕難窺，止足書中向上機。", "但看杖扶博山入，不知扇賜曲江歸。", "年饑方慮溝中瘠，旰食欲令天下肥。", "念此令人生內熱，溪邊頼有滌煩磯。"]'),
('d6831246-f86e-4c46-9ac9-37477adc3434','諸公載酒賀余休致水村農卿有詩次韻  其六','劉克莊','宋','宋诗','song-poetry','','[]','時事渾如坐井窺，逢人不敢問邊機。',64,'全唐诗/poet.song.201000.json','["時事渾如坐井窺，逢人不敢問邊機。", "連營未寄寒衣去，故里何心晝錦歸。", "笑矍鑠翁鳶跕墮，愛玄真子鱖魚肥。", "綠陰多處宜垂釣，莫管楸花落滿磯。"]'),
('84055b65-cb89-4890-98ae-bc6a3eaa73fa','諸公載酒賀余休致水村農卿有詩次韻  其七','劉克莊','宋','宋诗','song-poetry','','[]','戶外荒園久不窺，桔槔已息漢陰機。',64,'全唐诗/poet.song.201000.json','["戶外荒園久不窺，桔槔已息漢陰機。", "與雞窠老略相似，微鹿門翁誰與歸。", "訓儉家纔支伏臘，力農田不問磽肥。", "由來位重多憂責，未必沙隄勝石磯。"]'),
('c3055271-4461-4f75-b8be-4d7410c7efa7','諸公載酒賀余休致水村農卿有詩次韻  其八','劉克莊','宋','宋诗','song-poetry','','[]','指法金針不許窺，笑他貧女織寒機。',64,'全唐诗/poet.song.201000.json','["指法金針不許窺，笑他貧女織寒機。", "謫仙曲奏調羹賜，之問詩成奪錦歸。", "論定會盼銀信召，眷濃漫妬玉環肥。", "溪邊鷗鷺偷相語，只怕先生又下磯。"]'),
('82ff171b-9b29-44d3-9604-189c68af0ce1','諸公載酒賀余休致水村農卿有詩次韻  其九','劉克莊','宋','宋诗','song-poetry','','[]','陸海潘江莫測窺，手揮巧斲執神機。',64,'全唐诗/poet.song.201000.json','["陸海潘江莫測窺，手揮巧斲執神機。", "昔如魯野麟初獲，今似遼天鶴獨歸。", "外物何殊竿木戲，內丹不待藥苗肥。", "只愁戶外蒲輪至，去坐狨韉勿坐磯。"]'),
('1271726d-ed52-4428-8dcd-0767c2518560','諸公載酒賀余休致水村農卿有詩次韻  其一○','劉克莊','宋','宋诗','song-poetry','','[]','高屋從來有鬼窺，鐵門關枉費心機。',64,'全唐诗/poet.song.201000.json','["高屋從來有鬼窺，鐵門關枉費心機。", "逃堯欲去未忍去，捨魯不歸何處歸。", "款段馬知如狗大，堂厨羊不似蠔肥。", "賜金未可都揮散，要買荒山鶴斷磯。"]'),
('6ce77192-463e-46ec-b81f-8a89ad741a36','目眚','劉克莊','宋','宋诗','song-poetry','','[]','一秋窗下少書聲，目眚纏綿久未平。',64,'全唐诗/poet.song.201000.json','["一秋窗下少書聲，目眚纏綿久未平。", "大德三麻如昨日，善和千卷付來生。", "聃兮雖視如無見，藉也於心固不盲。", "吹却殘燈拋蠹簡，擁衾危坐待天明。"]'),
('f74e1986-6a7e-4ab6-91ba-8e472c8f4f80','賀警齋吳侍郎被召','劉克莊','宋','宋诗','song-poetry','','[]','舊人僅有魯靈光，銀信翩翩下帝傍。',64,'全唐诗/poet.song.201000.json','["舊人僅有魯靈光，銀信翩翩下帝傍。", "龍去十年閑卧洛，鳳來一日再鳴陽。", "璽書下訪芻言急，月食回思欖味長。", "善類合離關世道，祈公趣駕勿循牆。"]'),
('6554154e-e4a5-443d-9acb-f33256e3dace','挽鄭甥主學二首  其一','劉克莊','宋','宋诗','song-poetry','','[]','北轍心猶銳，南廊策不遷。',48,'全唐诗/poet.song.201000.json','["北轍心猶銳，南廊策不遷。", "美芹干將相，采藻淑生徒。", "賦鵩方强仕，聞雞漫壯圖。", "未應精爽盡，丹穴有雙雛。"]'),
('e96b26c5-d35c-484a-95f3-bbf36b1facb3','挽鄭甥主學二首  其二','劉克莊','宋','宋诗','song-poetry','','[]','親則班□子，賢於輔嗣甥。',48,'全唐诗/poet.song.201000.json','["親則班□子，賢於輔嗣甥。", "奠芻終古訣，炊黍霎時榮。", "先墓身爲殉，新丘手自營。", "老人尤惜淚，何况又偏盲。"]'),
('6e4f8f58-2480-4449-82a8-2a64456bbf53','大淵寄道冠漢鏡各答以一首  其一','劉克莊','宋','宋诗','song-poetry','','[]','已掛朝冠了，煩君寄道冠。',48,'全唐诗/poet.song.201000.json','["已掛朝冠了，煩君寄道冠。", "頭蓬不梳久，髮禿欲簪難。", "簡便烏巾贅，清羸鶴氅寬。", "兒童怪崖異，便作羽流看。"]'),
('80b756a4-3824-470b-83f4-7813c64e195a','大淵寄道冠漢鏡各答以一首  其二','劉克莊','宋','宋诗','song-poetry','','[]','雁足傳書至，蟾光出匣新。',48,'全唐诗/poet.song.201000.json','["雁足傳書至，蟾光出匣新。", "真從古冶子，曾照漢時人。", "昔作美年少，今非妙色身。", "明知皆夢幻，莫認假爲真。"]'),
('13a2d16a-c8a7-4758-9270-1a0797efdd73','覽西齋弟子抄諸家詩一首','劉克莊','宋','宋诗','song-poetry','','[]','小窗幾載共吟披，重見殘編拊事悲。',64,'全唐诗/poet.song.201000.json','["小窗幾載共吟披，重見殘編拊事悲。", "早日才高鸚鵡賦，暮年淚盡鶺鴒詩。", "神交夢尚通康樂，手澤書堪付阿宜。", "若是孔懷因未斷，安知來世不吹箎。"]'),
('9230564b-6018-485e-b2d7-48084b935d8c','讀太白詩一首和竹溪','劉克莊','宋','宋诗','song-poetry','','[]','翰林萬里出峨嵋，曾受開元帝異知。',64,'全唐诗/poet.song.201000.json','["翰林萬里出峨嵋，曾受開元帝異知。", "只道高爺能毀鬲，無端環子亦嗔癡。", "空傳飛燕當時句，難覓騎鯨以後詩。", "的是長庚星現世，粃糠伯友與王師。"]'),
('836bbcc7-4cef-475b-b1f3-4fdc6486766b','挽陳岩方隠君二首  其一','劉克莊','宋','宋诗','song-poetry','','[]','長魯申公數歲餘，占天隨子百弓居。',64,'全唐诗/poet.song.201000.json','["長魯申公數歲餘，占天隨子百弓居。", "久拋科舉尋初服，不願君王載後車。", "里有學人來問字，朝無掌故就傳書。", "新春農告西疇事，誰伴樗翁共荷鋤。"]'),
('f5fffca3-d72c-45be-8421-51766ded1ff9','挽陳岩方隠君二首  其二','劉克莊','宋','宋诗','song-poetry','','[]','溪墅山房委折通，每分半榻聽松風。',64,'全唐诗/poet.song.201000.json','["溪墅山房委折通，每分半榻聽松風。", "篘成昔喜同浮白，荔熟今悲自擘紅。", "宰上碑何慙有道，城中人少識龐公。", "單雞勺酒新丘遠，迢遞扶衰別殯宮。"]'),
('c3c9dc06-8023-46b9-bef5-477b1f71a995','徐洪二公再和二詩余亦隨喜  其一','劉克莊','宋','宋诗','song-poetry','','[]','腰臂拘攣倦笏紳，箋天乞得水雲身。',64,'全唐诗/poet.song.201000.json','["腰臂拘攣倦笏紳，箋天乞得水雲身。", "古書一點心源合，時事千莖鬢雪新。", "世重晚香并晚節，史難全傳更全人。", "歲寒頼有梅相伴，先向南枝漏洩春。"]'),
('6f8f04a0-617a-4800-91f0-4b4932c0a630','徐洪二公再和二詩余亦隨喜  其二','劉克莊','宋','宋诗','song-poetry','','[]','龍鍾詎可備藩臣，半俸恩深勝在陳。',64,'全唐诗/poet.song.201000.json','["龍鍾詎可備藩臣，半俸恩深勝在陳。", "熏鼠少曾開北牖，殺牛何必效東鄰。", "箋天疏許初還笏，上水船難更掌綸。", "幼讀學而渾忘却，豈能歌鳳又書麟。"]'),
('9f24b2ef-9473-45db-9af2-efba34ce1c02','徐洪二公再和二詩余亦隨喜  其三','劉克莊','宋','宋诗','song-poetry','','[]','松風地籟瀑天紳，下有苔磯著老身。',64,'全唐诗/poet.song.201000.json','["松風地籟瀑天紳，下有苔磯著老身。", "僵卧從教茅屋破，放歌不犯玉臺新。", "陶元亮可羲皇上，管幼安非漢魏人。", "酒禁近來開一綫，霜天便覺滿懷春。"]'),
('790d5165-7984-4b01-ad6e-8d27a5555224','徐洪二公再和二詩余亦隨喜  其四','劉克莊','宋','宋诗','song-poetry','','[]','久愧君恩祿具臣，太倉非有粟陳陳。',64,'全唐诗/poet.song.201000.json','["久愧君恩祿具臣，太倉非有粟陳陳。", "立朝到老羞營窟，避客經年少覿鄰。", "鶴夜失鳴猶給料，魚寒不食已收綸。", "小瓢如璽猶慵佩，何况金龜與玉麟。"]'),
('97136c38-f12d-40a1-ac6b-87fed62c5964','和長溪葉潘投贈韻','劉克莊','宋','宋诗','song-poetry','','[]','脯麟炮鳳飲鯨吞，肯學寒儒嚙菜根。',64,'全唐诗/poet.song.201000.json','["脯麟炮鳳飲鯨吞，肯學寒儒嚙菜根。", "琴古無階登舜殿，詩窮作祟客羌村。", "可憐書畫科俱廢，誰謂文章技未尊。", "世上金臺隨處有，吾貧聊復贈君言。"]'),
('bfa4ac97-3f15-44f3-b08e-aafaa4fc504e','林卿勸開酒禁次韻一首','劉克莊','宋','宋诗','song-poetry','','[]','新沐髮渾如雪白，大開眼只見天青。',64,'全唐诗/poet.song.201000.json','["新沐髮渾如雪白，大開眼只見天青。", "稱觥乍可同邠俗，錫爵安能效衛伶。", "過眼神奇俄臭腐，到頭濁醉勝清醒。", "閙藍不是安身處，且向糟邱寄暮齡。"]'),
('3b0b8c1f-3fb8-4fd5-9276-1ebd185f67fb','和曹守司直勸駕','劉克莊','宋','宋诗','song-poetry','','[]','李唐故典存燒尾，皇宋科名從敕頭。',64,'全唐诗/poet.song.201000.json','["李唐故典存燒尾，皇宋科名從敕頭。", "月露濃熏仙桂發，天風高送客槎浮。", "三場魁匪先賢志，千佛名知幾劫脩。", "自笑申公垂八十，不能挾冊共西游。"]'),
('7d25e0f8-d89b-426b-b962-9904a5051d18','讀大行皇帝遺詔感恩哀慟六首  其一','劉克莊','宋','宋诗','song-poetry','','[]','昨者欃槍久未收，宮中齋素却珍羞。',64,'全唐诗/poet.song.201000.json','["昨者欃槍久未收，宮中齋素却珍羞。", "宵衣密遣庚牌遞，露布差寬丙枕憂。", "大漸忽然開玉鎖，積勤端爲保金甌。", "堯民莫不如喪考，况侍堯階近璪旒。"]'),
('945b3b87-0ccf-43a3-b15b-59543a2de2ba','讀大行皇帝遺詔感恩哀慟六首  其二','劉克莊','宋','宋诗','song-poetry','','[]','或犯威顔批逆鱗，容如天地養如春。',64,'全唐诗/poet.song.201000.json','["或犯威顔批逆鱗，容如天地養如春。", "早年憔悴行吟者，歲晚賡歌喜起人。", "風雨無終飄暴意，雪霜有大發生仁。", "才衰莫頌文之德，虛忝詞臣與史臣。"]'),
('d5001d26-1845-408a-95d4-0d88e7d11cf0','讀大行皇帝遺詔感恩哀慟六首  其三','劉克莊','宋','宋诗','song-poetry','','[]','聖度如天未易量，每憐孤直赦疎狂。',64,'全唐诗/poet.song.201000.json','["聖度如天未易量，每憐孤直赦疎狂。", "中傷競發千鈞弩，拂拭重登七寶牀。", "昔忝未歸同二老，今無殉死愧三良。", "鼎湖望斷靈斿遠，血淚纔乾又數行。"]'),
('62addcb9-b957-4333-a461-82db1670e76c','讀大行皇帝遺詔感恩哀慟六首  其四','劉克莊','宋','宋诗','song-poetry','','[]','禁中宣召佯狂李，度外蒐羅不第蕡。',64,'全唐诗/poet.song.201000.json','["禁中宣召佯狂李，度外蒐羅不第蕡。", "先帝英明親擢汝，孤臣老死敢忘君。", "壞麻詎忍加城罪，庭著居常讀軾文。", "縱使天光留隻眼，此生無復望堯雲。"]'),
('d963e197-3aaf-4070-8714-040ba105ab2b','讀大行皇帝遺詔感恩哀慟六首  其五','劉克莊','宋','宋诗','song-poetry','','[]','批鳳提鼇間世遭，老臣全未報絲毫。',64,'全唐诗/poet.song.201000.json','["批鳳提鼇間世遭，老臣全未報絲毫。", "封還不覺天顔近，勸誦偏知帝學高。", "戶外昭容猶紫袖，柩前諸后更黄袍。", "暮年淚滴藏山稿，疇昔曾經聖筆褒。"]'),
('483ad928-627e-4b8f-b357-2415de79a74e','讀大行皇帝遺詔感恩哀慟六首  其六','劉克莊','宋','宋诗','song-poetry','','[]','士有一長斯可矣，文兼衆妙古難之。',64,'全唐诗/poet.song.201000.json','["士有一長斯可矣，文兼衆妙古難之。", "元豐御覽諸生賦，淳化屏題侍讀詩。", "序建隆須還鞏筆，記儲祥必待蘇碑。", "臣於四美安能備，虛受先皇不世知。"]'),
('d25b772e-8993-486a-b7ae-45e87934ed6d','大行皇帝挽詩六首  其一','劉克莊','宋','宋诗','song-poetry','','[]','仁厚傳嘉祐，重華繼紹興。',48,'全唐诗/poet.song.201000.json','["仁厚傳嘉祐，重華繼紹興。", "方恢周境土，忽治漢山陵。", "儉匪珠襦殮，危猶玉几憑。", "遥知天上樂，難返白雲乘。"]'),
('9cbd9d57-0842-4a7c-86e0-610929716232','大行皇帝挽詩六首  其二','劉克莊','宋','宋诗','song-poetry','','[]','臨照三千界，涵濡四十春。',48,'全唐诗/poet.song.201000.json','["臨照三千界，涵濡四十春。", "沙難量福壽，天不大堯仁。", "眇小坡詩案，優容濮議人。", "老臣偏慟絕，曾扈屬車塵。"]'),
('621d481b-cd05-4a1b-80b3-8cf3b750f25a','大行皇帝挽詩六首  其三','劉克莊','宋','宋诗','song-poetry','','[]','虜哨無寧處，龍顔有隠憂。',48,'全唐诗/poet.song.201000.json','["虜哨無寧處，龍顔有隠憂。", "未曾御戎服，已報走旃裘。", "地拓黄河土，天燒赤壁舟。", "奈何投柱斧，不待獻俘囚。"]'),
('3d96fcb4-458c-4687-bdd4-4e05ccd074fc','大行皇帝挽詩六首  其四','劉克莊','宋','宋诗','song-poetry','','[]','頗怪旄頭異，何曾玉色怡。',48,'全唐诗/poet.song.201000.json','["頗怪旄頭異，何曾玉色怡。", "惡言聞佛耳，夷猾上堯眉。", "河豈無清日，天曾有壞時。", "嗣皇新纘禹，遺老喜還悲。"]'),
('dc74417b-77e7-4b27-9f29-01e5272451a0','大行皇帝挽詩六首  其五','劉克莊','宋','宋诗','song-poetry','','[]','自惜孤寒士，栖栖到老休。',48,'全唐诗/poet.song.201000.json','["自惜孤寒士，栖栖到老休。", "生前浩然棄，歿後所忠求。", "臣草金雞赦，帝臨丹鳳樓。", "追懷稀闊遇，恨不殺身酬。"]'),
('f1472528-45d2-4200-b209-68b42258b67d','大行皇帝挽詩六首  其六','劉克莊','宋','宋诗','song-poetry','','[]','英鑒高千古，名尤不假人。',48,'全唐诗/poet.song.201000.json','["英鑒高千古，名尤不假人。", "周惟十夫哲，漢止一儒醇。", "聖筆嚴褒貶，臣材豈擬倫。", "驪珠六十九，誰謂橐中貧。"]'),
('6d1ac0a7-9c76-44e8-9d03-7494b0782909','送外弟方時父寄呈□古心相公','劉克莊','宋','宋诗','song-poetry','','[]','一自子猷迴棹後，溪邊風雪少來賓。',64,'全唐诗/poet.song.201000.json','["一自子猷迴棹後，溪邊風雪少來賓。", "櫟樗吾偶逃天伐，瓜葛君猶訪古親。", "不以癡頑疎此老，絕勝富貴合它人。", "相公留下陽春脚，應念詩翁白首貧。"]'),
('f8e1556d-37ba-45d8-844f-1f2b883361f2','挽高孺人','劉克莊','宋','宋诗','song-poetry','','[]','泝源高適譜，作媲鄭虔家。',48,'全唐诗/poet.song.201000.json','["泝源高適譜，作媲鄭虔家。", "賢子搴丹桂，高才補白華。", "病猶觀冕輅，沒不待笄珈。", "阡表堪傳遠，何須挽誄加。"]'),
('d8a85af0-abff-4277-a3bb-100def728ae3','挽黄拙軒','劉克莊','宋','宋诗','song-poetry','','[]','曠懷無事可攢眉，高興成章不撚髭。',64,'全唐诗/poet.song.201000.json','["曠懷無事可攢眉，高興成章不撚髭。", "愛殺元公爲□賦，笑他平子作愁詩。", "山中猿鶴平生友，天上麒麟是小兒。", "今代徐陵文價重，爲君鄭重述俚辭。"]'),
('212e2848-d39f-4a2f-80d5-13fc7f6daea4','臈月二十二夜漏下數刻小飲徑醉坐小閤睡傍無侍者仆於戶限眉鼻傷焉流血被面記以六言九首  其一','劉克莊','宋','宋诗','song-poetry','','[]','退之落齒感慨，子春傷足悲哀。',28,'全唐诗/poet.song.201000.json','["退之落齒感慨，子春傷足悲哀。", "遺體有所受也，敗面豈不痛哉。"]'),
('ab823363-62ae-49b5-8c48-b3300d540703','臈月二十二夜漏下數刻小飲徑醉坐小閤睡傍無侍者仆於戶限眉鼻傷焉流血被面記以六言九首  其二','劉克莊','宋','宋诗','song-poetry','','[]','玉追琢天肖汝，血模糊物敗之。',28,'全唐诗/poet.song.201000.json','["玉追琢天肖汝，血模糊物敗之。", "何時鼻端白現，依舊眉毫雪垂。"]'),
('b8572e8a-8c67-46ef-9322-4d6d3f8069df','臈月二十二夜漏下數刻小飲徑醉坐小閤睡傍無侍者仆於戶限眉鼻傷焉流血被面記以六言九首  其三','劉克莊','宋','宋诗','song-poetry','','[]','黠鬼機械惡毒，老人皮肉麻頑。',28,'全唐诗/poet.song.201000.json','["黠鬼機械惡毒，老人皮肉麻頑。", "且摩麟肪止血，不須獺髓滅瘢。"]'),
('4e9e75d3-864d-456f-8f8e-1c888a48a87d','臈月二十二夜漏下數刻小飲徑醉坐小閤睡傍無侍者仆於戶限眉鼻傷焉流血被面記以六言九首  其四','劉克莊','宋','宋诗','song-poetry','','[]','不爲卿面作計，轉令汝貌不揚。',28,'全唐诗/poet.song.201000.json','["不爲卿面作計，轉令汝貌不揚。", "鬢畔有千莖白，眉間無一點黄。"]'),
('4832f5f9-5fea-40e1-949e-d8bdd4a014a9','臈月二十二夜漏下數刻小飲徑醉坐小閤睡傍無侍者仆於戶限眉鼻傷焉流血被面記以六言九首  其五','劉克莊','宋','宋诗','song-poetry','','[]','垂堂一跌血面，閉閤三旬裹瘡。',28,'全唐诗/poet.song.201000.json','["垂堂一跌血面，閉閤三旬裹瘡。", "有佛至維摩室，無人拜德公床。"]'),
('6a66d452-2f35-4582-b351-9bcf1cb0f80b','臈月二十二夜漏下數刻小飲徑醉坐小閤睡傍無侍者仆於戶限眉鼻傷焉流血被面記以六言九首  其六','劉克莊','宋','宋诗','song-poetry','','[]','室中文殊已去，戶外子輿不來。',28,'全唐诗/poet.song.201000.json','["室中文殊已去，戶外子輿不來。", "蒙補陀衲足矣，扶靈壽杖彼哉。"]'),
('808f18ec-2cc0-4763-9687-810562820b7e','臈月二十二夜漏下數刻小飲徑醉坐小閤睡傍無侍者仆於戶限眉鼻傷焉流血被面記以六言九首  其七','劉克莊','宋','宋诗','song-poetry','','[]','晉士讐阮籍眼，唐人觀李邕眉。',28,'全唐诗/poet.song.201000.json','["晉士讐阮籍眼，唐人觀李邕眉。", "任汝得吾皮骨，惟吾不汝瑕疵。"]'),
('4cfebfce-9105-4aaa-bdbd-3ac14c8eec38','臈月二十二夜漏下數刻小飲徑醉坐小閤睡傍無侍者仆於戶限眉鼻傷焉流血被面記以六言九首  其八','劉克莊','宋','宋诗','song-poetry','','[]','丹書大聖初元，白髮先朝遺老。',28,'全唐诗/poet.song.201000.json','["丹書大聖初元，白髮先朝遺老。", "浪言鐵筆猶存，不覺玉山自倒。"]'),
('463be21a-7b69-4a7f-869a-f342dbf1f68d','臈月二十二夜漏下數刻小飲徑醉坐小閤睡傍無侍者仆於戶限眉鼻傷焉流血被面記以六言九首  其九','劉克莊','宋','宋诗','song-poetry','','[]','未嘗學斲傷鼻，不待狂言炙眉。',28,'全唐诗/poet.song.201000.json','["未嘗學斲傷鼻，不待狂言炙眉。", "禍福非自求者，橫逆當順受之。"]'),
('9c06a67f-675e-4277-bfbd-7f915b83cf8f','責貓','劉克莊','宋','宋诗','song-poetry','','[]','將錢聘汝向彫籠，穩卧花陰曉日紅。',64,'全唐诗/poet.song.201000.json','["將錢聘汝向彫籠，穩卧花陰曉日紅。", "鷙性偶然捎蝶戲，魚餐不與飼鷄同。", "首斑虛有含蟬相，尸素全無執鼠功。", "歲暮貧家宜汰冗，未知誰告主人公。"]'),
('81ccf9ac-b099-4032-aff5-13703a06f28e','答陳莆田投贈二首  其一','劉克莊','宋','宋诗','song-poetry','','[]','夙昔潘郎說孟公，講聞久矣匪匆匆。',64,'全唐诗/poet.song.201000.json','["夙昔潘郎說孟公，講聞久矣匪匆匆。", "君豪不忝十才子，吾老真成一禿翁。", "謝事安能謄妙墨，輟耕猶可和高風。", "畫簾寂寂蒲鞭小，應許澹臺至室中。"]'),
('9cb76d72-4a22-45a5-be97-436bac76aaa1','答陳莆田投贈二首  其二','劉克莊','宋','宋诗','song-poetry','','[]','恬退已邀鷗入社，畸孤羞使鴆爲媒。',64,'全唐诗/poet.song.201000.json','["恬退已邀鷗入社，畸孤羞使鴆爲媒。", "聞新令尹彈琴治，有遠方人負耒來。", "雷邑地偏難舞袖，坳堂水淺易膠杯。", "一枝半朶真窮相，輸與河陽滿縣開。"]'),
('c759aa07-b921-475a-8d25-376061b2900b','送林德輔倅三山','劉克莊','宋','宋诗','song-poetry','','[]','匹雛力薄難軒輊，一鶚能高易輓推。',64,'全唐诗/poet.song.201000.json','["匹雛力薄難軒輊，一鶚能高易輓推。", "屢見衮衣聞吉語，安知夾袋偶遺才。", "易云極困將亨矣，諺說平分有是哉。", "若餞古公煩問訊，蚤開翹館築金臺。"]'),
('69a03c50-1d40-420f-ae70-dc9cb0bf35af','七十九吟十首  其一','劉克莊','宋','宋诗','song-poetry','','[]','閲世桑田變海波，謾存銅狄共誰摩。',32,'全唐诗/poet.song.201000.json','["閲世桑田變海波，謾存銅狄共誰摩。", "釣璜歲日明年是，馳隙光陰一霎過。"]'),
('57a55741-2beb-4a3e-91af-378d93f716cf','七十九吟十首  其二','劉克莊','宋','宋诗','song-poetry','','[]','仕宦端平甲子歲，結局景定壬戌年。',32,'全唐诗/poet.song.201000.json','["仕宦端平甲子歲，結局景定壬戌年。", "有北窗凉來枕畔，無南風塵傍扇邊。"]'),
('ee12b927-7ca4-43ac-8ba7-da3d4acb5792','七十九吟十首  其三','劉克莊','宋','宋诗','song-poetry','','[]','便有鳳從千仞下，更無虎守九重門。',32,'全唐诗/poet.song.201000.json','["便有鳳從千仞下，更無虎守九重門。", "拔茅初喜仕途泰，起蕝迺知皇帝尊。"]'),
('60310eb8-9156-4621-a45b-ebaf7be46842','七十九吟十首  其四','劉克莊','宋','宋诗','song-poetry','','[]','多作惡詩供世笑，晚持孤論誰予同。',32,'全唐诗/poet.song.201000.json','["多作惡詩供世笑，晚持孤論誰予同。", "才名壓倒豁□老，官職火迫乖崖翁。"]'),
('0479f792-800f-4741-b221-16063b9d1cc9','七十九吟十首  其五','劉克莊','宋','宋诗','song-poetry','','[]','向來熱血潑虛庸，巵酒憑誰酹二公。',32,'全唐诗/poet.song.201000.json','["向來熱血潑虛庸，巵酒憑誰酹二公。", "老作地仙差□了，洞賓相約聽松風。"]'),
('eab974b6-b542-42cc-906d-50f0c5346cf8','七十九吟十首  其六','劉克莊','宋','宋诗','song-poetry','','[]','適聞有詔追陽子，又說厚禮迎申公。',32,'全唐诗/poet.song.201000.json','["適聞有詔追陽子，又說厚禮迎申公。", "莫教涑水疑四皓，且伴橫渠吟八翁。"]'),
('bffa5b06-94e5-4c18-96a9-2b8b0fc9b7f1','七十九吟十首  其七','劉克莊','宋','宋诗','song-poetry','','[]','經書上卿曰劉子，史稱三老爲董公。',32,'全唐诗/poet.song.201000.json','["經書上卿曰劉子，史稱三老爲董公。", "趙章泉自號晏叟，朱先生一字遯翁。"]'),
('739063f5-7487-458a-aa21-9a41ea066fe1','七十九吟十首  其八','劉克莊','宋','宋诗','song-poetry','','[]','舊田廬我先人業，某水丘吾童子遊。',32,'全唐诗/poet.song.201000.json','["舊田廬我先人業，某水丘吾童子遊。", "有杞菊姑安甫里，無蒲萄可博凉州。"]'),
('7ec099e1-79a7-435e-a75a-f2bf5a6e6062','七十九吟十首  其九','劉克莊','宋','宋诗','song-poetry','','[]','業緣在東震旦國，參禮徧南贍部州。',32,'全唐诗/poet.song.201000.json','["業緣在東震旦國，參禮徧南贍部州。", "欠明眼人與談道，就圓機士語九流。"]'),
('8124fff0-8437-4de8-8bbd-34b0b7befe4e','七十九吟十首  其一○','劉克莊','宋','宋诗','song-poetry','','[]','雖瞎吾眼猶劬書，平生無淚如唐衢。',32,'全唐诗/poet.song.201000.json','["雖瞎吾眼猶劬書，平生無淚如唐衢。", "愛鶴天鯨海空闊，嫌羊腸鳥道崎嶇。"]'),
('7490c879-fd85-44f2-af38-783e3ea561d8','吾里前輩林刪定甫六十挂冠夾漈艾軒諸老皆爲賦詩追次其韻','劉克莊','宋','宋诗','song-poetry','','[]','□定飛仙去不留，惜余生晚欠從游。',64,'全唐诗/poet.song.201000.json','["□定飛仙去不留，惜余生晚欠從游。", "种明逸後屈二指，范景仁邊放一頭。", "有鹿門栖堪遯去，無菟裘計徑歸休。", "却憐荷蓧非真隠，鷄黍殷勤止仲由。"]'),
('17cd2e7a-93f6-4a42-abc3-4d0957f09025','乙丑元日口號十首  其一','劉克莊','宋','宋诗','song-poetry','','[]','三白吳中梅花雪，一穟海南沉水煙。',32,'全唐诗/poet.song.201000.json','["三白吳中梅花雪，一穟海南沉水煙。", "勸汝杯酒令汝壽，著婆衫子拜婆年。"]'),
('f579826c-d6e4-4ee1-a419-2b4501aa100d','乙丑元日口號十首  其二','劉克莊','宋','宋诗','song-poetry','','[]','俗情諱老難藏老，暮景添年是減年。',32,'全唐诗/poet.song.201000.json','["俗情諱老難藏老，暮景添年是減年。", "舉力田科雖殿後，序鄉飲酒却居前。"]'),
('9a2a745b-9b42-46a8-8bb9-57d4c04b2403','乙丑元日口號十首  其三','劉克莊','宋','宋诗','song-poetry','','[]','癡獃已肖木雞狀，行走不減竹馬時。',32,'全唐诗/poet.song.201000.json','["癡獃已肖木雞狀，行走不減竹馬時。", "太平期恰當今日，嬉戲翁渾如小兒。"]'),
('b130cfa0-0b43-4477-893d-618807506067','乙丑元日口號十首  其四','劉克莊','宋','宋诗','song-poetry','','[]','方坐臯比開講肆，忽看傀儡至優場。',32,'全唐诗/poet.song.201000.json','["方坐臯比開講肆，忽看傀儡至優場。", "此翁奇奇又怪怪，若非僞學即陽狂。"]'),
('00102313-04b6-4cc5-a9a9-90cc3661fd20','乙丑元日口號十首  其五','劉克莊','宋','宋诗','song-poetry','','[]','伴壯丁騎秧馬出，看兒童放紙鳶嬉。',32,'全唐诗/poet.song.201000.json','["伴壯丁騎秧馬出，看兒童放紙鳶嬉。", "老無憂責庸非福，身是神仙不自知。"]'),
('90f72d43-6b72-4323-aec3-0d50bde1f9d6','乙丑元日口號十首  其六','劉克莊','宋','宋诗','song-poetry','','[]','無春一點到田廬，有雪千莖上鬢鬚。',32,'全唐诗/poet.song.201000.json','["無春一點到田廬，有雪千莖上鬢鬚。", "昧爽小孫喚翁起，勸簪柏葉飲屠蘇。"]'),
('7d7dd7a0-2f3c-4414-8f4c-6bb3f0e05f8a','乙丑元日口號十首  其七','劉克莊','宋','宋诗','song-poetry','','[]','遵新天子法永阜，爲先皇帝服通喪。',32,'全唐诗/poet.song.201000.json','["遵新天子法永阜，爲先皇帝服通喪。", "初元年素幄視草，千萬世青史有光。"]'),
('26707420-8b5f-42a6-aacc-8383c67b2c20','乙丑元日口號十首  其八','劉克莊','宋','宋诗','song-poetry','','[]','新擢咸淳兩臺端，可繼慶曆四諫官。',32,'全唐诗/poet.song.201000.json','["新擢咸淳兩臺端，可繼慶曆四諫官。", "安知千載無南董，異日求君諫草看。"]'),
('96d2811e-5fe0-4cf0-9898-d2cabc909a09','乙丑元日口號十首  其九','劉克莊','宋','宋诗','song-poetry','','[]','聖主出矣千載遇，王言大哉萬口夸。',32,'全唐诗/poet.song.201000.json','["聖主出矣千載遇，王言大哉萬口夸。", "聞道朝廷却苞篚，更無方鎮進鞭靴。"]'),
('428ad353-5967-4c00-93f6-5f6a98c1a91e','乙丑元日口號十首  其一○','劉克莊','宋','宋诗','song-poetry','','[]','作慶曆詩賡石介，讀開元報喜孫樵。',32,'全唐诗/poet.song.201000.json','["作慶曆詩賡石介，讀開元報喜孫樵。", "自節蕢桴諧律呂，豈無木鐸採風謠。"]'),
('273e3203-1fb9-4eaf-9d2d-41d445815a16','病中雜興五言十首  其一','劉克莊','宋','宋诗','song-poetry','','[]','鐵筆俱牽動，金臺總去登。',24,'全唐诗/poet.song.201000.json','["鐵筆俱牽動，金臺總去登。", "老僧不出院，挂起一枝藤。"]'),
('a27c6ab5-fb47-4546-89a2-6e9cbe3a818b','病中雜興五言十首  其二','劉克莊','宋','宋诗','song-poetry','','[]','皓素應難染，玄纁未易迎。',24,'全唐诗/poet.song.201000.json','["皓素應難染，玄纁未易迎。", "只宜大牀卧，或命小車行。"]'),
('96af4abd-f6ec-46fd-b702-22b6c1b8d254','病中雜興五言十首  其三','劉克莊','宋','宋诗','song-poetry','','[]','烏寺迎巖主，螭坳起澗翁。',24,'全唐诗/poet.song.201000.json','["烏寺迎巖主，螭坳起澗翁。", "也須留幾箇，相伴聽松風。"]'),
('01bf6969-3ce6-4f98-9851-06dec68ed8f3','病中雜興五言十首  其四','劉克莊','宋','宋诗','song-poetry','','[]','李廣飛將軍，世南行秘書。',24,'全唐诗/poet.song.201000.json','["李廣飛將軍，世南行秘書。", "乃知數寸管，不及丈二殳。"]'),
('5ffc3236-7039-416d-bec9-ca1670a9a288','病中雜興五言十首  其五','劉克莊','宋','宋诗','song-poetry','','[]','鰲頂來差晚，龍髯去莫攀。',24,'全唐诗/poet.song.201000.json','["鰲頂來差晚，龍髯去莫攀。", "不能從襄野，只合殉橋灣。"]'),
('7578f29d-50f4-4d47-8054-8272c6896bf5','病中雜興五言十首  其六','劉克莊','宋','宋诗','song-poetry','','[]','佛以滅爲樂，觀身等一漚。',24,'全唐诗/poet.song.201000.json','["佛以滅爲樂，觀身等一漚。", "如何盧行者，鎔鐵護枯髏。"]'),
('db109ae9-b851-43d8-b5aa-69463843d17e','病中雜興五言十首  其七','劉克莊','宋','宋诗','song-poetry','','[]','蒙叟云聃死，當時有吊賓。',24,'全唐诗/poet.song.201000.json','["蒙叟云聃死，當時有吊賓。", "始知關尹子，迂誕誑愚人。"]'),
('60bf7021-8405-4f2d-828c-456c96eed37c','病中雜興五言十首  其八','劉克莊','宋','宋诗','song-poetry','','[]','柳七葬淮頭，營妓歲瀝酒。',24,'全唐诗/poet.song.201000.json','["柳七葬淮頭，營妓歲瀝酒。", "不知花翁墳，有人擘紙否。"]'),
('e1420647-ba8b-4391-912b-2e4545c3b0e1','病中雜興五言十首  其九','劉克莊','宋','宋诗','song-poetry','','[]','向來春帖子，殘膏罥蛛絲。',24,'全唐诗/poet.song.201000.json','["向來春帖子，殘膏罥蛛絲。", "無復秦郎思，聊吟党進詩。"]'),
('9027965a-f040-4615-86b8-6cebe8b82686','病中雜興五言十首  其一○','劉克莊','宋','宋诗','song-poetry','','[]','跌蕩四千首，流行宇宙間。',24,'全唐诗/poet.song.201000.json','["跌蕩四千首，流行宇宙間。", "國風幾曾熄，聖筆不能刪。"]'),
('814aba45-38b6-4a11-9ba0-9d9f4526d16a','題趙與㑾贄卷','劉克莊','宋','宋诗','song-poetry','','[]','身已明農老一丘，屢空何以答珍投。',64,'全唐诗/poet.song.201000.json','["身已明農老一丘，屢空何以答珍投。", "新腔高處古樂府，警句當家小倚樓。", "此筆生花尤組麗，彼風吹籜漫輕浮。", "從前作者皆勤苦，螢雪功夫更講求。"]'),
('abc8b41c-60c3-4879-952d-de40f00d343d','迎候艮翁二首  其一','劉克莊','宋','宋诗','song-poetry','','[]','問訊江邊白首郎，可堪留滯向殊方。',64,'全唐诗/poet.song.201000.json','["問訊江邊白首郎，可堪留滯向殊方。", "遠遊定有騷哀郢，新集應添賦弔湘。", "得路諸公蛇入宇，去國幾箇鶴還鄉。", "與君大勝於劉柳，歲晚鄰翁約未償。"]'),
('53454cfa-2e87-4c81-b595-b4f22e54de14','迎候艮翁二首  其二','劉克莊','宋','宋诗','song-poetry','','[]','恰則含香文德殿，俄而攬轡祝融峯。',64,'全唐诗/poet.song.201000.json','["恰則含香文德殿，俄而攬轡祝融峯。", "得非麟角驚凡目，或是蛾眉妬冶容。", "六丈一勾非惡意，兩翁相對少歡悰。", "西山北郭多幽事，雖老猶堪撰杖從。"]'),
('7029dfb9-f7b6-4ccf-8b29-3a7d22a9ec53','送洪侍御二首  其一','劉克莊','宋','宋诗','song-poetry','','[]','曾峨豸角立朝端，貴近聞名膽尚寒。',64,'全唐诗/poet.song.201000.json','["曾峨豸角立朝端，貴近聞名膽尚寒。", "古冢狐狸何足問，法筵龍象各傍觀。", "青霄直上雲梯易，白首能堅鐵壁難。", "想見洛陽爲紙貴，爭傳獻可袖中彈。"]'),
('eec77cb8-e7ad-4e6a-b2e2-6a1c03fa848f','送洪侍御二首  其二','劉克莊','宋','宋诗','song-poetry','','[]','幾迴南向望蒲輪，聞引而西忽改轅。',64,'全唐诗/poet.song.201000.json','["幾迴南向望蒲輪，聞引而西忽改轅。", "小毖上求助初政，大招公起入修門。", "鱗無嬰者寧非諂，膳有鬈如不必言。", "膜外浮榮均臭腐，本來面目要常存。"]'),
('3dfd0fe5-557f-4705-b222-32c10e210a9d','送雷司法於發秤提結局一首','劉克莊','宋','宋诗','song-poetry','','[]','吏奉新書多刻峭，君於此事極忠勤。',64,'全唐诗/poet.song.201000.json','["吏奉新書多刻峭，君於此事極忠勤。", "告緡鮮有麗三尺，投劾不如寬一分。", "重幣稍權周舊法，大搜安用漢深文。", "先民最善言陰德，莫要人知耳自聞。"]'),
('ebb3d242-1d44-484f-8951-e36c72b9c518','居厚弟得玉局祠','劉克莊','宋','宋诗','song-poetry','','[]','憶昔端平初去國，署銜竊喜似坡仙。',64,'全唐诗/poet.song.201000.json','["憶昔端平初去國，署銜竊喜似坡仙。", "衰翁鬢雪年華晚，賢季條冰敕墨鮮。", "飲馬胡兒來雜沓，猶龍老子去翩躚。", "何時劍閣妖氛掃，重炷荒祠一縷烟。"]'),
('90d681fb-3001-47b8-ad3d-2933708199c5','徐仲晦以尚書郎召','劉克莊','宋','宋诗','song-poetry','','[]','進立乎朝多憚黯，誼形於色欲烹桑。',64,'全唐诗/poet.song.201000.json','["進立乎朝多憚黯，誼形於色欲烹桑。", "瞻前昔徧參諸老，殿後今留遺嗣皇。", "主聖方當親上輦，時清未可夢凝香。", "蒲輪定以何時發，耄瞎難占紫氣祥。"]'),
('f88dd3b6-7a8f-41d4-97c8-fcb68685b174','送陳監簿造朝','劉克莊','宋','宋诗','song-poetry','','[]','君昔閑三紀，朝今聚衆賢。',48,'全唐诗/poet.song.201000.json','["君昔閑三紀，朝今聚衆賢。", "居然峙鸞鵠，不似襲貂蟬。", "訓儉無釵澤，遺忠有笏傳。", "將何告明主，事事法隆乾。"]'),
('5c28a2df-c96f-4bb5-b837-d78362f53ed6','題高端禮竹屋','劉克莊','宋','宋诗','song-poetry','','[]','植物惟竹尤清剛，高君占斷作屋場。',144,'全唐诗/poet.song.201000.json','["植物惟竹尤清剛，高君占斷作屋場。", "首陽二子艴然怒，柰何千載侵了疆。", "七賢六逸接踵起，紛紜聚訟如堵牆。", "士師狐疑不能决，後村老子來平章。", "世間物以少爲貴，姚花禹柏蜀海棠。", "籜龍子孫異於是，布滿天地并四方。", "幽栖自是渠高興，勝踐不與君相妨。", "立談虞芮各冰釋，高君奄有千篔簹。", "設榻中央墉四旁，莫遣俗客升吾堂。"]'),
('0ca8bec4-5edb-4db1-adbd-246143e04daf','寄題徐候雨山堂','劉克莊','宋','宋诗','song-poetry','','[]','竹溪來索後村吟，讀記披圖已醒心。',64,'全唐诗/poet.song.201000.json','["竹溪來索後村吟，讀記披圖已醒心。", "豈是沕淵行雨懶，亦非避地入山深。", "喜看素瀑飛青壁，不管蒼苔卧綠沉。", "西北城高刁斗急，將軍未可問山林。"]'),
('9f144e60-7bf3-45a8-a8dd-7200d7e5cb54','挽林德遇主學','劉克莊','宋','宋诗','song-poetry','','[]','摛掞多新意，研尋最苦心。',48,'全唐诗/poet.song.201000.json','["摛掞多新意，研尋最苦心。", "可憐策名晚，誰遣讀書深。", "兄老悲長枕，妻賢歛短衾。", "近書猶未答，展玩一沾襟。"]'),
('5f587ddf-b8b0-44b8-a973-679a6c1eeb06','食早荔七首  其一','劉克莊','宋','宋诗','song-poetry','','[]','苧蘿仙子絳紗裳，歲歲年年逞色香。',32,'全唐诗/poet.song.201000.json','["苧蘿仙子絳紗裳，歲歲年年逞色香。", "不比阿環池上果，一千年得一番嘗。"]'),
('ef4528a8-56a7-4827-b69d-319c54113990','食早荔七首  其二','劉克莊','宋','宋诗','song-poetry','','[]','活八十年頭雪白，啖三百顆面桃紅。',32,'全唐诗/poet.song.201000.json','["活八十年頭雪白，啖三百顆面桃紅。", "村南村北無人識，向荔枝邊覓此翁。"]'),
('130cd397-08f6-4231-9edb-09077c7f4641','食早荔七首  其三','劉克莊','宋','宋诗','song-poetry','','[]','樹頭栗鼠往來頻，時遣髽童作徼巡。',32,'全唐诗/poet.song.201000.json','["樹頭栗鼠往來頻，時遣髽童作徼巡。", "不是尚方要包貢，暮年頼此助精神。"]'),
('a3b9e938-f479-4306-8112-571a2cb0d41c','食早荔七首  其四','劉克莊','宋','宋诗','song-poetry','','[]','蜀道閩山各有之，千林紅綠任紛披。',32,'全唐诗/poet.song.201000.json','["蜀道閩山各有之，千林紅綠任紛披。", "杜詩息響難追和，蔡譜孤行欠補遺。"]');
